-- Poems batch 28
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('06d59c41-8301-473d-9239-c4a3be3a561a','華清宮','杜牧','唐','唐诗','tang','','[]','零葉飜紅萬樹霜，玉蓮開蘂暖泉香。',32,'全唐诗/poet.tang.28000.json','["零葉飜紅萬樹霜，玉蓮開蘂暖泉香。", "行雲不下朝元閣，一曲淋鈴淚數行。"]'),
('ceb63d3c-a86e-45b6-b0dc-e51878c64fe1','冬日題智門寺北樓','杜牧','唐','唐诗','tang','','[]','滿懷多少是恩酬，未見功名已白頭。',32,'全唐诗/poet.tang.28000.json','["滿懷多少是恩酬，未見功名已白頭。", "不爲尋山試筋力，豈能寒上背雲樓。"]'),
('32ec6cfe-5d91-4324-8fd0-2b4cfc2e19cd','別王十後遣京使累路附書','杜牧','唐','唐诗','tang','','[]','重關曉度宿雲寒，羸馬緣知步步難。',32,'全唐诗/poet.tang.28000.json','["重關曉度宿雲寒，羸馬緣知步步難。", "此信的應中路見，亂山何處拆書看。"]'),
('024a43fd-2ce0-44dd-bef9-545e6cf9aafc','許秀才至辱李蘄州絕句問斷酒之情因寄','杜牧','唐','唐诗','tang','','[]','有客南來話所思，故人遙枉醉中詩。',32,'全唐诗/poet.tang.28000.json','["有客南來話所思，故人遙枉醉中詩。", "暫因微疾須防酒，不是歡情減舊時。"]'),
('6cd406b9-476e-4ce6-9af9-a0e29ae94a9f','送張判官歸兼謁鄂州大夫','杜牧','唐','唐诗','tang','','[]','處士聞名早，遊秦獻疏迴。',48,'全唐诗/poet.tang.28000.json','["處士聞名早，遊秦獻疏迴。", "腹中書萬卷，身外酒千盃。", "江雨春波闊，園林客夢催。", "今君拜旌戟，凜凜近霜臺。"]'),
('c0040d15-939e-413c-bb1c-4f7414739294','宿長慶寺','杜牧','唐','唐诗','tang','','[]','南行步步遠浮塵，更近青山昨夜隣。',64,'全唐诗/poet.tang.28000.json','["南行步步遠浮塵，更近青山昨夜隣。", "高鐸數聲秋撼玉，霽河千里曉橫銀。", "紅蕖影落前池淨，綠稻香來野逕頻。", "終日官閑無一事，不妨長醉是遊人。"]'),
('5ffb9229-778c-4658-a3f2-3647f2c78658','望少華三首 一','杜牧','唐','唐诗','tang','','[]','身隨白日看將老，心與青雲自有期。',32,'全唐诗/poet.tang.28000.json','["身隨白日看將老，心與青雲自有期。", "今對晴峰無十里，世緣多累暗生悲。"]'),
('5167f16f-2433-4946-9838-33fe3aaa5737','望少華三首 二','杜牧','唐','唐诗','tang','','[]','文字波中去不還，物情初雨是非閑。',32,'全唐诗/poet.tang.28000.json','["文字波中去不還，物情初雨是非閑。", "時名竟是無端事，羞對靈山道愛山。"]'),
('63f59cc5-72e0-49bf-b420-13d2bbfa6d0f','望少華三首 三','杜牧','唐','唐诗','tang','','[]','眼看雲鶴不相隨，何況塵中事作爲。',32,'全唐诗/poet.tang.28000.json','["眼看雲鶴不相隨，何況塵中事作爲。", "好伴羽人深洞去，月前秋聽玉參差。"]'),
('ec610ff7-9b53-4b32-a1ba-3be555613e3d','登澧州驛樓寄京兆韋尹','杜牧','唐','唐诗','tang','','[]','一話涔陽舊使君，郡人迴首望青雲。',32,'全唐诗/poet.tang.28000.json','["一話涔陽舊使君，郡人迴首望青雲。", "政聲長與江聲在，自到津樓日夜聞。"]'),
('e5597111-7112-45e8-8586-4faecb01f022','長安晴望','杜牧','唐','唐诗','tang','','[]','翠屏山對鳳城開，碧落搖光霽後來。',32,'全唐诗/poet.tang.28000.json','["翠屏山對鳳城開，碧落搖光霽後來。", "廻識六龍巡幸處，飛煙閑遶望春臺。"]'),
('40fdde29-bf45-4fa7-a789-92fd327974e0','歲旦朝回口號','杜牧','唐','唐诗','tang','','[]','星河猶在整朝衣，遠望天門再拜歸。',32,'全唐诗/poet.tang.28000.json','["星河猶在整朝衣，遠望天門再拜歸。", "笑向春風初五十，敢言知命且知非。"]'),
('1dd45230-903a-405d-bb6a-4640a6c18040','驌驦駿','杜牧','唐','唐诗','tang','','[]','瑤池罷遊宴，良樂委塵沙。',24,'全唐诗/poet.tang.28000.json','["瑤池罷遊宴，良樂委塵沙。", "遭遇不遭遇，鹽車與鼓車。"]'),
('aad6ca7c-09f5-4e83-9448-179f08519125','龍丘途中二首 一','杜牧','唐','唐诗','tang','','[]','漢苑殘花別，吳江盛夏來。',24,'全唐诗/poet.tang.28000.json','["漢苑殘花別，吳江盛夏來。", "唯看萬樹合，不見一枝開。"]'),
('a8f958fb-19a3-4f73-a257-c2b3888fe227','龍丘途中二首 二','杜牧','唐','唐诗','tang','','[]','水色饒湘浦，灘聲怯建溪。',24,'全唐诗/poet.tang.28000.json','["水色饒湘浦，灘聲怯建溪。", "淚流迴月上，可得更猿啼。"]'),
('8a7af025-d3cc-48aa-a889-d4760fa64e76','宮人塚','杜牧','唐','唐诗','tang','','[]','盡是離宮院中女，苑牆城外塚纍纍。',32,'全唐诗/poet.tang.28000.json','["盡是離宮院中女，苑牆城外塚纍纍。", "少年入內教歌舞，不識君王到老時。"]'),
('bca25064-fdc9-4fb1-8dae-b888e246550b','寄浙西李判官','杜牧','唐','唐诗','tang','','[]','燕臺上客意[何如]，四五年來漸漸疎。',66,'全唐诗/poet.tang.28000.json','["燕臺上客意[何如]，四五年來漸漸疎。", "直道莫拋男子業，遭時還與故人書。", "青雲滿眼應驕我，白髮渾頭少恨渠。", "唯念賢哉崔大讓，可憐無事不歌魚。"]'),
('41f83dce-4881-4fcf-b272-d4e8e1384ee9','寄杜子二首 一','杜牧','唐','唐诗','tang','','[]','不識長楊事北胡，且教紅袖醉來扶。',32,'全唐诗/poet.tang.28000.json','["不識長楊事北胡，且教紅袖醉來扶。", "狂風烈燄雖千尺，豁得平生俊氣無。"]'),
('1262cfeb-1081-4b6d-8996-fde8d1ef31d8','寄杜子二首 二','杜牧','唐','唐诗','tang','','[]','武牢關吏應相笑，箇裏年年往復來。',32,'全唐诗/poet.tang.28000.json','["武牢關吏應相笑，箇裏年年往復來。", "若問使君何處去，爲言相憶首長迴。"]'),
('54ec5857-33f0-42fb-8b62-dfbf80a7d77a','盧秀才將出王屋高步名場江南相逢贈別','杜牧','唐','唐诗','tang','','[]','王屋山人有古文，欲攀青桂弄氛氳。',64,'全唐诗/poet.tang.28000.json','["王屋山人有古文，欲攀青桂弄氛氳。", "將攜健筆干明主，莫向仙壇問白雲。", "馳逐寧教爭處讓，是非偏忌衆人分。", "交遊話我憑君道，除却鱸魚更不聞。"]'),
('1acab59d-a894-46c8-94e8-0a256c34df65','送劉三復郎中赴闕','杜牧','唐','唐诗','tang','','[]','橫溪辭寂寞，金馬去追遊。',48,'全唐诗/poet.tang.28000.json','["橫溪辭寂寞，金馬去追遊。", "好是鴛鴦侶，正逢霄漢秋。", "玉珂聲瑣瑣，錦帳夢悠悠。", "微笑知今是，因風謝釣舟。"]'),
('eb36dbd4-9bc4-4d36-8373-962f7b63451c','羊欄浦夜陪宴會','杜牧','唐','唐诗','tang','','[]','戈檻營中夜未央，雨沾雲惹侍襄王。',48,'全唐诗/poet.tang.28000.json','["戈檻營中夜未央，雨沾雲惹侍襄王。", "毬來香袖依稀暖，酒凸斛心汎灩光。", "紅弦高緊聲聲急，珠唱鋪圓褭褭長。"]'),
('be6c51dd-d0bb-4030-b9ba-eb4d4a165f76','送杜顗赴潤州幕','杜牧','唐','唐诗','tang','','[]','少年才俊赴知音，丞相門欄不覺深。',64,'全唐诗/poet.tang.28000.json','["少年才俊赴知音，丞相門欄不覺深。", "直道事人男子業，異鄉加飯弟兄心。", "還須整理韋弦佩，莫獨矜誇玳瑁簪。", "若去上元懷古去，謝安墳下與沈吟。"]'),
('037f8e37-1da9-47b7-a350-126a07b33385','有感','杜牧','唐','唐诗','tang','','[]','宛溪垂柳最長枝，曾被春風盡日吹。',32,'全唐诗/poet.tang.28000.json','["宛溪垂柳最長枝，曾被春風盡日吹。", "不堪攀折猶堪看，陌上少年來自遲。"]'),
('8f6fb2d1-46dd-4732-a5de-d542f35083f0','書懷寄盧州','杜牧','唐','唐诗','tang','','[]','謝山南畔州，風物最宜秋。',48,'全唐诗/poet.tang.28000.json','["謝山南畔州，風物最宜秋。", "太守懸金印，佳人敞畫樓。", "凝缸暗醉夕，殘月上汀州。", "可惜當年鬢，朱門不得遊。"]'),
('2de5b7bd-c485-4b42-96bf-076a90b33e76','賀崔大夫崔正字','杜牧','唐','唐诗','tang','','[]','內舉無慚古所難，燕臺遙想拂塵冠。',64,'全唐诗/poet.tang.28000.json','["內舉無慚古所難，燕臺遙想拂塵冠。", "登龍有路水不峻，一鴈背飛天正寒。", "別夜酒餘紅燭短，映山帆滿碧霞殘。", "謝公樓下潺湲響，離恨詩情添幾般。"]'),
('e5286e89-da5f-4544-8a12-e49f9bb2fbff','江南送左師','杜牧','唐','唐诗','tang','','[]','江南爲客正悲秋，更送吾師古渡頭。',32,'全唐诗/poet.tang.28000.json','["江南爲客正悲秋，更送吾師古渡頭。", "惆悵不同塵土別，水雲蹤跡去悠悠。"]'),
('85a19bca-cdc4-4b5b-872c-07ed61be29e5','寢夜','杜牧','唐','唐诗','tang','','[]','蛩唱如波咽，更深似水寒。',48,'全唐诗/poet.tang.28000.json','["蛩唱如波咽，更深似水寒。", "露華驚弊褐，燈影挂塵冠。", "故國初離夢，前溪更下灘。", "紛紛毫髪事，多少宦遊難。"]'),
('aeafd492-7902-44b5-a3dc-a18dfc350df7','十九兄郡樓有宴病不赴','杜牧','唐','唐诗','tang','','[]','十二層樓敞畫簷，連雲歌盡草纖纖。',32,'全唐诗/poet.tang.28000.json','["十二層樓敞畫簷，連雲歌盡草纖纖。", "空堂病怯階前月，燕子嗔垂一竹簾。"]'),
('3fd7fae5-8491-429f-aef4-2ba1b9bcbabf','愁','杜牧','唐','唐诗','tang','','[]','聚散竟無形，迴腸自結成。',48,'全唐诗/poet.tang.28000.json','["聚散竟無形，迴腸自結成。", "古今留不得，離別又潛生。", "降虜將軍思，窮秋遠客情。", "何人更憔悴，落第泣秦京。"]'),
('ae02ce20-de19-4c23-9c6c-f782859a773b','隋苑','杜牧','唐','唐诗','tang','','[]','紅霞一抹廣陵春，定子當筵睡臉新。',32,'全唐诗/poet.tang.28000.json','["紅霞一抹廣陵春，定子當筵睡臉新。", "却笑喫虧隋煬帝，破家亡國爲誰人。"]'),
('3135c2ee-00f2-4225-9eba-bbf494faad73','芭蕉','杜牧','唐','唐诗','tang','','[]','芭蕉爲雨移，故向窓前種。',36,'全唐诗/poet.tang.28000.json','["芭蕉爲雨移，故向窓前種。", "憐渠點滴聲，留得歸鄉夢。", "夢遠莫歸鄉，覺來一翻動。"]'),
('68957cfc-69fd-4e1c-b185-84c78c02d4c3','汴人舟行荅張祜','杜牧','唐','唐诗','tang','','[]','千萬長河共使船，聽君詩句倍愴然。',32,'全唐诗/poet.tang.28000.json','["千萬長河共使船，聽君詩句倍愴然。", "春風野岸名花發，一道帆檣畫柳煙。"]'),
('6fe3bbaf-2f8b-4bf1-a2d1-79f5a6bef477','牧陪昭應盧郎中在江西宣州佐今吏部沈公幕罷府周歲公宰昭應牧在淮南縻職敘舊成二十二韻用以投寄','杜牧','唐','唐诗','tang','','[]','燕鴈下揚州，涼風柳陌愁。',264,'全唐诗/poet.tang.28000.json','["燕鴈下揚州，涼風柳陌愁。", "可憐千里夢，還是一年秋。", "宛水環朱檻，章江敞碧流。", "謬陪吾益友，祗事我賢侯。", "印組縈光馬，鋒鋩看解牛。", "井閭安樂易，冠蓋愜依投。", "政簡稀開閣，功成每運籌。", "送春經野塢，遲日上高樓。", "玉裂歌聲斷，霞飄舞帶收。", "泥情斜拂印，別臉小低頭。", "日晚花枝爛，釭凝粉彩稠。", "未曾孤酩酊，剩肯隻淹留。", "重德俄徵寵，諸生苦宦遊。", "分途之絕國，灑淚拜行輈。", "聚散真漂梗，光陰急轉郵。", "銘心徒歷歷，屈指盡悠悠。", "君作烹鮮用，誰膺仄席求。", "卷懷能憤悱，卒歲且優遊。", "去矣時難遇，沽哉價莫酬。", "滿枝爲鼓吹，衷甲避戈矛。", "隋帝宮荒草，秦王土一丘。", "相逢好大笑，除此總雲浮。"]'),
('68167dff-23be-4876-a742-f75d80307d9c','寓言','杜牧','唐','唐诗','tang','','[]','暖風遲日柳初含，顧影看身又自慙。',32,'全唐诗/poet.tang.28000.json','["暖風遲日柳初含，顧影看身又自慙。", "何事明朝獨惆悵，杏花時節在江南。"]'),
('52a599ad-0b63-410e-b38f-2109e636673f','猿','杜牧','唐','唐诗','tang','','[]','月白煙青水暗流，孤猿銜恨叫中秋。',32,'全唐诗/poet.tang.28000.json','["月白煙青水暗流，孤猿銜恨叫中秋。", "三聲欲斷疑腸斷，饒是少年今白頭。"]'),
('dc074254-7e82-4c23-b798-3609e747bec4','懷歸','杜牧','唐','唐诗','tang','','[]','塵埃終日滿牕前，水態雲容思浩然。',32,'全唐诗/poet.tang.28000.json','["塵埃終日滿牕前，水態雲容思浩然。", "爭得便歸湘浦去，却持竿上釣魚船。"]'),
('a20b27d3-d785-4d73-8dd9-12b65ffd2e00','邊上晚秋','杜牧','唐','唐诗','tang','','[]','黑山南面更無州，馬放平沙夜不收。',32,'全唐诗/poet.tang.28000.json','["黑山南面更無州，馬放平沙夜不收。", "風送孤城臨晚角，一聲聲入客心愁。"]'),
('4e28d87d-576b-4af0-8a43-63d28c15f811','傷友人悼吹簫妓','杜牧','唐','唐诗','tang','','[]','玉簫聲斷沒流年，滿目春愁隴樹煙。',32,'全唐诗/poet.tang.28000.json','["玉簫聲斷沒流年，滿目春愁隴樹煙。", "豔質已隨雲雨散，鳳樓空鎖月明天。"]'),
('308eb1a8-b305-4809-ae8b-4a13cb09bff8','訪許顏','杜牧','唐','唐诗','tang','','[]','門近寒溪牕近山，枕山流水日潺潺。',32,'全唐诗/poet.tang.28000.json','["門近寒溪牕近山，枕山流水日潺潺。", "長嫌世上浮雲客，老向塵中不解顏。"]'),
('52fdb35a-5a08-41ba-b6be-996087bf2843','春日古道傍作','杜牧','唐','唐诗','tang','','[]','萬古榮華旦暮齊，樓臺春盡草萋萋。',32,'全唐诗/poet.tang.28000.json','["萬古榮華旦暮齊，樓臺春盡草萋萋。", "君看陌上何人墓，旋化紅塵送馬蹏。"]'),
('304aa711-54e3-4550-b2ab-ec17b1e24a76','青塚','杜牧','唐','唐诗','tang','','[]','青塚前頭隴水流，燕支山上暮雲秋。',32,'全唐诗/poet.tang.28000.json','["青塚前頭隴水流，燕支山上暮雲秋。", "蛾眉一墜窮泉路，夜夜孤魂月下愁。"]'),
('bb217f10-edb0-45b7-8e49-47585cc6c8b9','大夢上人自廬峰回','杜牧','唐','唐诗','tang','','[]','行脚尋常到寺稀，一枝藜杖一禪衣。',32,'全唐诗/poet.tang.28000.json','["行脚尋常到寺稀，一枝藜杖一禪衣。", "開門滿院空秋色，新向廬峰過夏歸。"]'),
('0b459de7-7741-4711-9302-d65394318cc5','洛中二首 一','杜牧','唐','唐诗','tang','','[]','柳動晴風拂路塵，年年宮闕鎖濃春。',32,'全唐诗/poet.tang.28000.json','["柳動晴風拂路塵，年年宮闕鎖濃春。", "一從翠輦無巡幸，老却蛾眉幾許人。"]'),
('2a39a296-cc21-44b4-84c9-a660196a4e61','洛中二首 二','杜牧','唐','唐诗','tang','','[]','風吹柳帶搖晴綠，蝶遶花枝戀暖香。',32,'全唐诗/poet.tang.28000.json','["風吹柳帶搖晴綠，蝶遶花枝戀暖香。", "多把芳菲泛春酒，直教愁色對愁腸。"]'),
('1f464abe-9a19-49a5-b026-450807a7661f','邊上聞笳三首 一','杜牧','唐','唐诗','tang','','[]','何處吹笳薄暮天，塞垣高鳥沒狼煙。',32,'全唐诗/poet.tang.28000.json','["何處吹笳薄暮天，塞垣高鳥沒狼煙。", "遊人一聽頭堪白，蘇武爭禁十九年。"]'),
('4350de2f-0914-4bdb-b9ce-713bcd97e2f4','邊上聞笳三首 二','杜牧','唐','唐诗','tang','','[]','海路無塵邊草新，榮枯不見綠楊春。',32,'全唐诗/poet.tang.28000.json','["海路無塵邊草新，榮枯不見綠楊春。", "白沙日暮愁雲起，獨感離鄉萬里人。"]'),
('1927803a-61ed-4f62-a93c-5f498b286c5a','邊上聞笳三首 三','杜牧','唐','唐诗','tang','','[]','胡雛吹笛上高臺，寒雁驚飛去不回。',32,'全唐诗/poet.tang.28000.json','["胡雛吹笛上高臺，寒雁驚飛去不回。", "盡日春風吹不散，只應分付客愁來。"]'),
('9c0f6ffa-7149-40b9-a8e3-a7579d77259d','春日寄許渾先輩','杜牧','唐','唐诗','tang','','[]','薊北雁初去，湘南春又歸。',48,'全唐诗/poet.tang.28000.json','["薊北雁初去，湘南春又歸。", "水流滄海急，人到白頭稀。", "塞路盡何處，我愁當落暉。", "終須接鴛鷺，霄漢共高飛。"]'),
('9b5a42d1-285e-4955-b55a-1917f61167b2','經闔閭城','杜牧','唐','唐诗','tang','','[]','遺蹤委衰草，行客思悠悠。',48,'全唐诗/poet.tang.28000.json','["遺蹤委衰草，行客思悠悠。", "昔日人何處，終年水自流。", "孤煙邨戌遠，亂雨海門秋。", "吟罷獨歸去，煙雲盡慘愁。"]'),
('eb5120bb-738e-4b1f-b212-869ed20e2c48','幷州道中','杜牧','唐','唐诗','tang','','[]','行役我方倦，苦吟誰復聞。',48,'全唐诗/poet.tang.28000.json','["行役我方倦，苦吟誰復聞。", "戌樓春帶雪，邊角暮吹雲。", "極目無人迹，回頭送鴈羣。", "如何遣公子，高臥醉醺醺。"]'),
('58912283-2b9a-42fe-be12-744cc183543f','別懷','杜牧','唐','唐诗','tang','','[]','相別徒成泣，經過總是空。',48,'全唐诗/poet.tang.28000.json','["相別徒成泣，經過總是空。", "勞生慣離別，夜夢苦西東。", "去路三湘浪，歸程一片風。", "他年寄消息，書在鯉魚中。"]'),
('1dae0963-7101-4cf3-a045-1c0607adc419','漁父','杜牧','唐','唐诗','tang','','[]','白髮滄浪上，全忘是與非。',48,'全唐诗/poet.tang.28000.json','["白髮滄浪上，全忘是與非。", "秋潭垂釣去，夜月叩船歸。", "煙影侵蘆岸，潮痕在竹扉。", "終年狎鷗鳥，來去且無機。"]'),
('f8aedfad-1722-4af7-8212-a5aec92fd87a','秋夢','杜牧','唐','唐诗','tang','','[]','寒空動高吹，月色滿清砧。',48,'全唐诗/poet.tang.28000.json','["寒空動高吹，月色滿清砧。", "殘夢夜魂斷，美人邊思深。", "孤鴻秋出塞，一葉暗辭林。", "又寄征衣去，迢迢天外心。"]'),
('408b44e4-92fd-41f5-a073-6559f58e51e1','早秋客舍','杜牧','唐','唐诗','tang','','[]','風吹一片葉，萬物已驚秋。',48,'全唐诗/poet.tang.28000.json','["風吹一片葉，萬物已驚秋。", "獨夜他鄉淚，年年爲客愁。", "別離何處盡，搖落幾時休。", "不及磻溪叟，身閑長自由。"]'),
('7e57dc35-56b8-4e3d-ab51-25d6c4bd1fab','逢故人','杜牧','唐','唐诗','tang','','[]','故交相見稀，相見倍依依。',48,'全唐诗/poet.tang.28000.json','["故交相見稀，相見倍依依。", "塵路事不盡，雲巖閑好歸。", "投人銷壯志，徇俗變真機。", "又落他鄉淚，風前一滿衣。"]'),
('51ef42d5-7ee1-4f03-abd0-082156116f1c','秋晚江上遣懷','杜牧','唐','唐诗','tang','','[]','孤舟天際外，去路望中賒。',48,'全唐诗/poet.tang.28000.json','["孤舟天際外，去路望中賒。", "貧病遠行客，夢魂多在家。", "蟬吟秋色樹，鴉噪夕陽沙。", "不擬徹雙鬢，他方擲歲華。"]'),
('a8b805ad-170d-4d5b-a213-7fa8a9267ef3','長安夜月','杜牧','唐','唐诗','tang','','[]','寒光垂靜夜，皓彩滿重城。',48,'全唐诗/poet.tang.28000.json','["寒光垂靜夜，皓彩滿重城。", "萬國盡分照，誰家無此明。", "古槐疎影薄，仙桂動秋聲。", "獨有長門裏，蛾眉對曉晴。"]'),
('28433d8d-5936-45da-ade8-19c96e9b7882','雲','杜牧','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','東西那有礙，出處豈虛心。',48,'全唐诗/poet.tang.28000.json','["東西那有礙，出處豈虛心。", "曉入洞庭闊，暮歸巫峽深。", "渡江隨鳥影，擁樹隔猿吟。", "莫隱高唐去，枯苗待作霖。"]'),
('524e074f-6a93-407d-860f-6aedbcafb736','春懷','杜牧','唐','唐诗','tang','','[]','年光何太急，倏忽又青春。',48,'全唐诗/poet.tang.28000.json','["年光何太急，倏忽又青春。", "明月誰爲主，江山暗換人。", "鶯花潛運老，榮樂漸成塵。", "遙憶朱門柳，別離應更頻。"]'),
('916b8772-417b-4c41-8444-cc5cf7653df1','逢故人','杜牧','唐','唐诗','tang','','[]','年年不相見，相見却成悲。',48,'全唐诗/poet.tang.28000.json','["年年不相見，相見却成悲。", "教我淚如霰，嗟君髪似絲。", "正傷攜手處，況值落花時。", "莫惜今宵醉，人間忽忽期。"]'),
('fa3e549f-176c-48b3-bf3e-c713f218bea3','閑題','杜牧','唐','唐诗','tang','','[]','男兒所在即爲家，百鎰黃金一朵花。',32,'全唐诗/poet.tang.28000.json','["男兒所在即爲家，百鎰黃金一朵花。", "借問春風何處好，綠楊深巷馬頭斜。"]'),
('80159919-0b66-4956-a563-ef9bcf6a05c0','金谷園','杜牧','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u6000\u53e4"]','繁華事散逐香塵，流水無情草自春。',32,'全唐诗/poet.tang.28000.json','["繁華事散逐香塵，流水無情草自春。", "日暮東風怨啼鳥，落花猶似墮樓人。"]'),
('2029f78f-5712-4d96-ac73-6400df8b6f61','重登科','杜牧','唐','唐诗','tang','','[]','星漢離宮月出輪，滿街含笑綺羅春。',32,'全唐诗/poet.tang.28000.json','["星漢離宮月出輪，滿街含笑綺羅春。", "花前每被青蛾問，何事重來只一人。"]'),
('28799a12-e0c3-48ef-a28a-5524333f8f4a','遊邊','杜牧','唐','唐诗','tang','','[]','黃沙連海路無塵，邊草長枯不見春。',32,'全唐诗/poet.tang.28000.json','["黃沙連海路無塵，邊草長枯不見春。", "日暮拂雲堆下過，馬前逢著射鵰人。"]'),
('092a87b0-7174-4349-aa8e-66e55664ce16','將赴池州道中作','杜牧','唐','唐诗','tang','','[]','青陽雲水去年尋，黃絹歌詩出翰林。',64,'全唐诗/poet.tang.28000.json','["青陽雲水去年尋，黃絹歌詩出翰林。", "投轄暫停留酒客，絳帷斜繫滿松陰。", "妖人笑我不相問，道者應知歸路心。", "南去南來盡鄉國，月明秋水只沈沈。"]'),
('c96d8cbe-15b2-4741-8223-cdf24c7d0b3c','隋宮春','杜牧','唐','唐诗','tang','','[]','龍舟東下事成空，蔓草萋萋滿故宮。',32,'全唐诗/poet.tang.28000.json','["龍舟東下事成空，蔓草萋萋滿故宮。", "亡國亡家爲顏色，露桃猶自恨春風。"]'),
('18046e74-6340-4797-808e-aaf0a557caee','蠻中醉','杜牧','唐','唐诗','tang','','[]','瘴塞蠻江入洞流，人家多在竹棚頭。',32,'全唐诗/poet.tang.28000.json','["瘴塞蠻江入洞流，人家多在竹棚頭。", "青山海上無城郭，唯見松牌出象州。"]'),
('cc1f4baf-4d3d-4694-8e1e-2e6a3c06f737','寓題','杜牧','唐','唐诗','tang','','[]','把酒直須判酩酊，逢花莫惜暫淹留。',32,'全唐诗/poet.tang.28000.json','["把酒直須判酩酊，逢花莫惜暫淹留。", "假如三萬六千日，半是悲哀半是愁。"]'),
('1fc932b9-69e4-4562-b3b9-bf4bfeae9e54','送趙十二赴舉','杜牧','唐','唐诗','tang','','[]','省事却因多事力，無心翻似有心來。',32,'全唐诗/poet.tang.28000.json','["省事却因多事力，無心翻似有心來。", "秋風郡閣殘花在，別後何人更一杯。"]'),
('62506da7-05c5-4c55-878a-0b86b2ab50fe','偶呈鄭先輩','杜牧','唐','唐诗','tang','','[]','不語亭亭儼薄粧，畫裙雙鳳鬱金香。',32,'全唐诗/poet.tang.28000.json','["不語亭亭儼薄粧，畫裙雙鳳鬱金香。", "西京才子旁看取，何似喬家郍窈娘。"]'),
('d93b8de9-bb98-4e94-ac57-56fb66930975','子規','杜牧','唐','唐诗','tang','','["\u601d\u4e61", "\u82b1", "\u5199\u9e1f", "\u5199\u82b1", "\u9e1f"]','蜀地曾聞子規鳥，宣城又見杜鵑花。',32,'全唐诗/poet.tang.28000.json','["蜀地曾聞子規鳥，宣城又見杜鵑花。", "一呌一回腸一斷，三春三月憶三巴。"]'),
('9d95e279-c674-4b69-a5e9-1b8585ff0f21','江樓','杜牧','唐','唐诗','tang','','[]','獨酌芳春酒，登樓已半醺。',24,'全唐诗/poet.tang.28000.json','["獨酌芳春酒，登樓已半醺。", "誰驚一行雁，衝斷過江雲。"]'),
('200fe9fa-0221-4123-86de-4d63ce9d3daf','旅宿','杜牧','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u7f81\u65c5", "\u601d\u4e61", "\u4e94\u8a00\u5f8b\u8bd7"]','旅館無良伴，凝情自悄然。',48,'全唐诗/poet.tang.28000.json','["旅館無良伴，凝情自悄然。", "寒燈思舊事，斷鴈警愁眠。", "遠夢歸侵曉，家書到隔年。", "湘江好煙月，門繫釣魚船。"]'),
('ee85588c-0534-4102-8f5c-e305f5f4eec0','杜鵑','杜牧','唐','唐诗','tang','','[]','杜宇竟何冤，年年呌蜀門。',48,'全唐诗/poet.tang.28000.json','["杜宇竟何冤，年年呌蜀門。", "至今銜積恨，終古弔殘魂。", "芳草迷腸結，紅花染血痕。", "山川盡春色，嗚咽復誰論。"]'),
('a4b1c163-b708-42d3-99af-a02f36eac49d','聞蟬','杜牧','唐','唐诗','tang','','[]','火雲初似滅，曉角欲微清。',48,'全唐诗/poet.tang.28000.json','["火雲初似滅，曉角欲微清。", "故國行千里，新蟬忽數聲。", "時行仍髣髴，度日更分明。", "不敢頻傾耳，唯憂白髮生。"]'),
('cde49e9e-6a1b-4410-9be7-00f366a05d55','送友人','杜牧','唐','唐诗','tang','','[]','十載名兼利，人皆與命爭。',48,'全唐诗/poet.tang.28000.json','["十載名兼利，人皆與命爭。", "青春留不住，白髮自然生。", "夜雨滴鄉思，秋風從別情。", "都門五十里，馳馬逐雞聲。"]'),
('30040ee2-58a0-4ff6-be84-c8c55f440a88','旅情','杜牧','唐','唐诗','tang','','[]','窗虛枕簟涼，寢倦憶瀟湘。',48,'全唐诗/poet.tang.28000.json','["窗虛枕簟涼，寢倦憶瀟湘。", "山色幾時老，人心終日忙。", "松風半夜雨，簾月滿堂霜。", "匹馬好歸去，江頭橘正香。"]'),
('71cf556f-c9b9-48dc-b8db-cd0e71489eab','曉望','杜牧','唐','唐诗','tang','','[]','獨起望山色，水雞鳴蓼洲。',48,'全唐诗/poet.tang.28000.json','["獨起望山色，水雞鳴蓼洲。", "房星隨月曉，楚木向雲秋。", "曲渚疑江盡，平沙似浪浮。", "秦原在何處，澤國碧悠悠。"]'),
('58f6dd3b-adc6-4b9e-9ef0-64fbb119926d','貽友人','杜牧','唐','唐诗','tang','','[]','自是東西客，逢人又送人。',48,'全唐诗/poet.tang.28000.json','["自是東西客，逢人又送人。", "不應相見老，秖是別離頻。", "度日還知暮，平生未識春。", "儻無遷谷分，歸去養天真。"]'),
('97a85c63-017e-4e4f-afbb-7584f6d9f977','書事','杜牧','唐','唐诗','tang','','[]','自笑走紅塵，流年舊復新。',48,'全唐诗/poet.tang.28000.json','["自笑走紅塵，流年舊復新。", "東風半夜雨，南國萬家春。", "失計拋魚艇，何門化涸鱗。", "是誰添歲月，老却暗投人。"]'),
('7b531a90-ba92-4f64-97e5-e7a353f14f65','別鶴','杜牧','唐','唐诗','tang','','[]','分飛共所從，六翮勢催風。',48,'全唐诗/poet.tang.28000.json','["分飛共所從，六翮勢催風。", "聲斷碧雲外，影孤明月中。", "青田歸路遠，丹桂舊巢空。", "矯翼知何處，天涯不可窮。"]'),
('0aa8fae9-ffb6-4bce-82ce-6e07262b64dc','晚泊','杜牧','唐','唐诗','tang','','[]','帆濕去悠悠，停橈宿渡頭。',50,'全唐诗/poet.tang.28000.json','["帆濕去悠悠，停橈宿渡頭。", "亂煙迷野岸，獨鳥出中流。", "[篷]雨延鄉夢，江風阻暮秋。", "儻無身外事，甘老向扁舟。"]'),
('caaca622-c956-41cc-8332-ed41f24818a7','山寺','杜牧','唐','唐诗','tang','','[]','峭壁引行徑，截溪開石門。',48,'全唐诗/poet.tang.28000.json','["峭壁引行徑，截溪開石門。", "泉飛濺虛檻，雲起漲河軒。", "隔水看來路，疎籬見定猿。", "未閑難久住，歸去復何言。"]'),
('e8712c56-38dc-490d-81ce-03dbb8fac1a1','早行','杜牧','唐','唐诗','tang','','["\u6292\u60c5"]','垂鞭信馬行，數里未雞鳴。',48,'全唐诗/poet.tang.28000.json','["垂鞭信馬行，數里未雞鳴。", "林下帶殘夢，葉飛時忽驚。", "霜凝孤鶴逈，月曉遠山橫。", "僮僕休辭險，時平路復平。"]'),
('6de81737-7d03-4b65-87cb-fc3a286825b8','秋日偶題','杜牧','唐','唐诗','tang','','[]','荷花兼柳葉，彼此不勝秋。',48,'全唐诗/poet.tang.28000.json','["荷花兼柳葉，彼此不勝秋。", "玉露滴初泣，金風吹更愁。", "綠眉甘棄墜，紅臉恨飄流。", "歎息是遊子，少年還白頭。"]'),
('3f5d1c3a-0f7a-4acf-8a5b-0a90f5eda796','憶歸','杜牧','唐','唐诗','tang','','[]','新城非故里，終日想柴扃。',48,'全唐诗/poet.tang.28000.json','["新城非故里，終日想柴扃。", "興罷花還落，愁來酒欲醒。", "何人初髪白，幾處亂山青。", "遠憶湘江上，漁歌對月聽。"]'),
('b15e15e7-93ac-4923-bf7b-d5e06a4104a2','偶見','杜牧','唐','唐诗','tang','','[]','朔風高緊掠河樓，白鼻騧郎白罽裘。',32,'全唐诗/poet.tang.28000.json','["朔風高緊掠河樓，白鼻騧郎白罽裘。", "有箇當壚明似月，馬鞭斜揖笑回頭。"]'),
('09f484d9-6b45-4920-9497-7f9c1e94c4f1','醉倒','杜牧','唐','唐诗','tang','','[]','日晴空樂下仙雲，俱在涼亭送使君。',32,'全唐诗/poet.tang.28000.json','["日晴空樂下仙雲，俱在涼亭送使君。", "莫辭一盞即相請，還是三年更不聞。"]'),
('a6ea719c-de54-450a-a810-ec7e136445f7','酬許十三秀才兼依來韻','杜牧','唐','唐诗','tang','','[]','多爲裁詩步竹軒，有時凝思過朝昏。',64,'全唐诗/poet.tang.28000.json','["多爲裁詩步竹軒，有時凝思過朝昏。", "篇成敢道懷金璞，吟苦唯應似嶺猿。", "迷興每慙花月夕，寄愁長在別離魂。", "憑君把卷侵寒燭，麗句時傳畫戟門。"]'),
('9c486955-3227-4d91-a098-df46818ca5c8','後池泛舟送王十秀才','杜牧','唐','唐诗','tang','','[]','城日晚悠悠，弦歌在碧流。',48,'全唐诗/poet.tang.28000.json','["城日晚悠悠，弦歌在碧流。", "夕風飄度曲，煙嶼隱行舟。", "問拍擬新令，憐香占彩毬。", "當筵雖一醉，寧復緩離愁。"]'),
('41e6abd8-7f86-47c8-8864-80194d5f471e','書情','杜牧','唐','唐诗','tang','','[]','誰家洛浦神，十四五來人。',48,'全唐诗/poet.tang.28000.json','["誰家洛浦神，十四五來人。", "媚髪輕垂額，香衫軟著身。", "摘蓮紅袖濕，窺淥翠蛾頻。", "飛鵲徒來往，平陽公主親。"]'),
('8b9be387-45c4-434b-b095-169df99f2a87','兵部尚書席上作','杜牧','唐','唐诗','tang','','[]','華堂今日綺筵開，誰喚分司御史來。',32,'全唐诗/poet.tang.28000.json','["華堂今日綺筵開，誰喚分司御史來。", "偶發狂言驚滿坐，三重粉面一時回。"]'),
('91cb2639-7f72-4881-98fc-ab984c5e1dec','驌驦坂','杜牧','唐','唐诗','tang','','[]','荆州一萬里，不如蒯易度。',24,'全唐诗/poet.tang.28000.json','["荆州一萬里，不如蒯易度。", "仰首望飛鳴，伊人何異趣。"]'),
('8310ffab-fa9e-473b-b587-7f192954d94d','冬日五湖館水亭懷別','杜牧','唐','唐诗','tang','','[]','蘆荻花多觸處飛，獨凭虛檻雨微微。',64,'全唐诗/poet.tang.28000.json','["蘆荻花多觸處飛，獨凭虛檻雨微微。", "寒林葉落鳥巢出，古渡風高漁艇稀。", "雲抱四山終日在，草荒三徑幾時歸。", "江城向晚西流急，無限鄉心聞擣衣。"]'),
('79cbc5bd-e582-45c9-81dc-41faae227083','不寢','杜牧','唐','唐诗','tang','','[]','到曉不成夢，思量堪白頭。',48,'全唐诗/poet.tang.28000.json','["到曉不成夢，思量堪白頭。", "多無百年命，長有萬般愁。", "世路應難盡，營生卒未休。", "莫言名與利，名利是身讐。"]'),
('8c798165-fe62-41c4-aaff-9d53cca79408','泊松江','杜牧','唐','唐诗','tang','','[]','清露白雲明月天，與君齊櫂木蘭船。',32,'全唐诗/poet.tang.28000.json','["清露白雲明月天，與君齊櫂木蘭船。", "南湖風雨一相失，夜泊橫塘心渺然。"]'),
('28f10c86-ee73-4720-8e9c-0b39561a8578','題水西寺','杜牧','唐','唐诗','tang','','[]','三日去還住，一生焉再遊。',24,'全唐诗/poet.tang.28000.json','["三日去還住，一生焉再遊。", "含情碧溪水，重上粲公樓。"]'),
('487f4f4a-f3ef-46fb-98cf-4454f7135e85','贈別宣州崔羣相公','杜牧','唐','唐诗','tang','','[]','衰散相逢洛水邊，却思同在紫薇天。',32,'全唐诗/poet.tang.28000.json','["衰散相逢洛水邊，却思同在紫薇天。", "盡將舟楫板橋去，早晚歸來更濟川。"]'),
('b4155273-6b2c-477f-9ddc-08722def1c6a','聞開江相國宋下世二首 一','杜牧','唐','唐诗','tang','','[]','權門陰進奪移才，驛騎如星墮峽來。',64,'全唐诗/poet.tang.28000.json','["權門陰進奪移才，驛騎如星墮峽來。", "晁氏有恩忠作禍，賈生無罪直爲災。", "貞魂誤向崇山沒，冤氣疑從湘水回。", "畢竟成功何處是，五湖雲月一帆開。"]'),
('bfc79005-7c71-4365-bbe6-6ff9b4a7f44a','聞開江相國宋下世二首 二','杜牧','唐','唐诗','tang','','[]','月落清湘棹不喧，玉杯瑤瑟奠蘋蘩。',64,'全唐诗/poet.tang.28000.json','["月落清湘棹不喧，玉杯瑤瑟奠蘋蘩。", "誰令力制乘軒鶴，自取機沈在檻猿。", "位極乾坤三事貴，謗興華夏一夫冤。", "宵衣旰食明天子，日伏青蒲不爲言。"]'),
('7efa218b-1573-4c81-91fa-24b9c998caea','出關','杜牧','唐','唐诗','tang','','[]','朝纓初解佐江濆，麋鹿心知自有羣。',64,'全唐诗/poet.tang.28000.json','["朝纓初解佐江濆，麋鹿心知自有羣。", "漢囿獵稀慵獻賦，楚山耕早任移文。", "臥歸漁浦月連海，行望鳳城花隔雲。", "關吏不須迎馬笑，去時無意學終軍。"]'),
('8bc003c1-d2d3-4708-b014-7048cda8846b','暝投雲智寺渡溪不得却取沿江路往','杜牧','唐','唐诗','tang','','[]','雙嵓瀉一川，回馬斷橋前。',48,'全唐诗/poet.tang.28000.json','["雙嵓瀉一川，回馬斷橋前。", "古廟陰風地，寒鐘暮雨天。", "沙虛留虎跡，水滑帶龍涎。", "却下臨江路，潮深無渡船。"]'),
('3af260ca-3d83-46a3-b1d3-7f8edac1789e','宣城贈蕭兵曹','杜牧','唐','唐诗','tang','','[]','桂檝謫湘渚，三年波上春。',96,'全唐诗/poet.tang.28000.json','["桂檝謫湘渚，三年波上春。", "舟寒句溪雪，衣故洛城塵。", "客道恥搖尾，皇恩寬犯鱗。", "花時去國遠，月夕上樓頻。", "賒酒不辭病，傭書非爲貧。", "行吟值漁父，坐隱對樵人。", "紫陌罷雙轍，碧潭窮一綸。", "高秋更南去，煙水是通津。"]'),
('988f49d0-3ae0-4a41-a673-0817a1ea97e0','過鮑溶宅有感','杜牧','唐','唐诗','tang','','[]','寥落故人宅，重來身已亡。',48,'全唐诗/poet.tang.28000.json','["寥落故人宅，重來身已亡。", "古苔殘墨沼，深竹舊書堂。", "秋色池館靜，雨聲雲木涼。", "無因展交道，日暮倍心傷。"]'),
('584fe075-d3b6-47c4-a182-0c169ca14b5a','寄兄弟','杜牧','唐','唐诗','tang','','[]','江城紅葉盡，旅思倍淒涼。',48,'全唐诗/poet.tang.28000.json','["江城紅葉盡，旅思倍淒涼。", "孤夢家山遠，獨眠秋夜長。", "道存空倚命，身賤未歸鄉。", "南望仍垂淚，天邊鴈一行。"]'),
('e982c7d4-77e3-47d1-9005-8916b7347c70','秋日','杜牧','唐','唐诗','tang','','[]','有計自安業，秋風罷遠吟。',48,'全唐诗/poet.tang.28000.json','["有計自安業，秋風罷遠吟。", "買山惟種竹，對客更彈琴。", "煙起藥厨晚，杵聲松院深。", "閑眠得真性，惆悵舊時心。"]'),
('c4952145-72c2-4da3-b777-a9d307cac272','卜居招書侶','杜牧','唐','唐诗','tang','','[]','憶昨未知道，臨川每羨魚。',48,'全唐诗/poet.tang.28000.json','["憶昨未知道，臨川每羨魚。", "世途行處見，人事病來疎。", "微雨秋栽竹，孤燈夜讀書。", "憐君亦同志，晚歲傍山居。"]'),
('403f8c59-dcd9-4a22-82a1-c5c1230b62b0','西山草堂','杜牧','唐','唐诗','tang','','[]','何處人事少，西峰舊草堂。',48,'全唐诗/poet.tang.28000.json','["何處人事少，西峰舊草堂。", "曬書秋日晚，洗藥石泉香。", "後嶺有微雨，北牕生曉涼。", "徒勞問歸路，峰疊遶家鄉。"]'),
('6fef4c46-59d0-4a27-823e-8869262b093e','貽隱者','杜牧','唐','唐诗','tang','','[]','回報隱居山，莫憂山興闌。',48,'全唐诗/poet.tang.28000.json','["回報隱居山，莫憂山興闌。", "求人顏色盡，知道性情寬。", "信譜彈琴誤，緣崖斸藥難。", "東臯亦自給，殊愧遠相安。"]'),
('eac072c2-87a1-4963-bcea-5c38d28b72ab','石池','杜牧','唐','唐诗','tang','','[]','通竹引泉脉，泓澄深石盆。',48,'全唐诗/poet.tang.28000.json','["通竹引泉脉，泓澄深石盆。", "驚魚翻藻葉，浴鳥上松根。", "殘月留山影，高風耗水痕。", "誰家洗秋藥，來往自開門。"]'),
('2b2171cf-cccb-4a93-93c0-f48fcbcfd026','送蘇協律從事振武','杜牧','唐','唐诗','tang','','[]','琴尊詩思勞，更欲學龍韜。',48,'全唐诗/poet.tang.28000.json','["琴尊詩思勞，更欲學龍韜。", "王粲暫投筆，呂虔初佩刀。", "夜吟關月苦，秋望塞雲高。", "去去從軍樂，鵰飛岱馬豪。"]'),
('cad612b5-a64b-4663-9313-84c7152468cc','懷政禪師院','杜牧','唐','唐诗','tang','','[]','山齋路幾層，敗衲學真乘。',48,'全唐诗/poet.tang.28000.json','["山齋路幾層，敗衲學真乘。", "寒暑移雙樹，光陰盡一燈。", "風飄高竹雪，泉漲小池冰。", "莫訝頻來此，修身欲到僧。"]'),
('00a3c877-5904-43d5-8248-7327151eb464','送荔浦蔣明府赴任','杜牧','唐','唐诗','tang','','[]','路長春欲盡，歌怨酒多酣。',48,'全唐诗/poet.tang.28000.json','["路長春欲盡，歌怨酒多酣。", "白社蓮塘北，青袍桂水南。", "驛行盤鳥道，船宿避龍潭。", "真得詩人趣，煙霞處處諳。"]'),
('0b859bef-0c17-45ab-845d-9875dd865677','秋夕有懷','杜牧','唐','唐诗','tang','','[]','念遠坐西閣，華池涵月涼。',48,'全唐诗/poet.tang.28000.json','["念遠坐西閣，華池涵月涼。", "書回秋欲盡，酒醒夜初長。", "露白蓮衣淺，風清蕙帶香。", "前年此佳景，蘭棹醉橫塘。"]'),
('1b368e99-78ba-45ce-9a35-2bf5c0a250bb','秋霽寄遠','杜牧','唐','唐诗','tang','','[]','初霽獨登賞，西樓多遠風。',48,'全唐诗/poet.tang.28000.json','["初霽獨登賞，西樓多遠風。", "橫煙秋水上，疎雨夕陽中。", "高樹下山鳥，平蕪飛草蟲。", "唯應待明月，千里與君同。"]'),
('35120a7d-9555-479f-9cdc-370dc97d4b74','經古行宮','杜牧','唐','唐诗','tang','','[]','臺閣參差倚太陽，年年花發滿山香。',64,'全唐诗/poet.tang.28000.json','["臺閣參差倚太陽，年年花發滿山香。", "重門勘鎖青春晚，深殿垂簾白日長。", "草色芊綿侵御路，泉聲嗚咽繞宮墻。", "先皇一去無回駕，紅粉雲環空斷腸。"]'),
('4de353cb-66da-46ad-bb87-7fe9a9052fa5','宣州開元寺贈惟真上人','杜牧','唐','唐诗','tang','','[]','曾與徑山爲小師，千年僧行衆人知。',64,'全唐诗/poet.tang.28000.json','["曾與徑山爲小師，千年僧行衆人知。", "夜深月色當禪處，齋後鐘聲到講時。", "經雨綠苔侵古畫，過秋紅葉落新詩。", "勸君莫厭江城客，雖在風塵別有期。"]'),
('1c6c8b83-6bf8-4cf1-a6f9-72a7480931ad','秋晚懷茅山石涵村舍','杜牧','唐','唐诗','tang','','[]','十畝山田近石涵，村居風俗舊曾諳。',64,'全唐诗/poet.tang.28000.json','["十畝山田近石涵，村居風俗舊曾諳。", "簾前白艾驚春燕，籬上青桑待晚蠶。", "雲暖採茶來嶺北，月明沽酒過溪南。", "陵陽秋盡多歸思，紅樹蕭蕭覆碧潭。"]'),
('b7fb92f5-2218-4360-af84-2b553b1060d1','留題李侍御書齋','杜牧','唐','唐诗','tang','','[]','曾話平生志，書齋幾見留。',48,'全唐诗/poet.tang.28000.json','["曾話平生志，書齋幾見留。", "道孤心易感，恩重力難酬。", "獨立千峰晚，頻來一葉秋。", "雞鳴應有處，不學淚空流。"]'),
('4f7c94e4-93c7-45ce-8877-2d47cbd22a4b','行次白沙館先寄上河南王侍郎','杜牧','唐','唐诗','tang','','[]','夜程何處宿，山疊樹層層。',48,'全唐诗/poet.tang.28000.json','["夜程何處宿，山疊樹層層。", "孤館閑秋雨，空堂停曙燈。", "歌慙漁浦客，詩學雁門僧。", "此意無人識，明朝見李膺。"]'),
('d505f107-27db-48e3-8e87-87d5a5a671e6','貴遊','杜牧','唐','唐诗','tang','','[]','朝回珮馬草萋萋，年少恩深衛霍齊。',64,'全唐诗/poet.tang.28000.json','["朝回珮馬草萋萋，年少恩深衛霍齊。", "斧鉞舊威龍塞北，池臺新賜鳳城西。", "門通碧樹開金鎖，樓對青山倚玉梯。", "南陌行人盡廻首，笙歌一曲暮雲低。"]'),
('c49367d4-cdb7-4cc3-8433-0cac723302aa','越中','杜牧','唐','唐诗','tang','','[]','石城花暖鷓鴣飛，征客春帆秋不歸。',32,'全唐诗/poet.tang.28000.json','["石城花暖鷓鴣飛，征客春帆秋不歸。", "猶自保郎心似石，綾梭夜夜織寒衣。"]'),
('06ac6585-2683-4b5f-b94c-854297f32676','聞范秀才自蜀遊江湖','杜牧','唐','唐诗','tang','','[]','蜀道下湘渚，客帆應不迷。',48,'全唐诗/poet.tang.28000.json','["蜀道下湘渚，客帆應不迷。", "江分三峽響，山竝九華齊。", "秋泊鴈初宿，夜吟猿乍啼。", "歸時慎行李，莫到石城西。"]'),
('a5272df5-6b7d-485f-a6bd-f1df33a54ae6','綠蘿','杜牧','唐','唐诗','tang','','[]','綠蘿縈數匝，本在草堂間。',48,'全唐诗/poet.tang.28000.json','["綠蘿縈數匝，本在草堂間。", "秋色寄高樹，晝陰籠近山。", "移花疎處過，斸藥困時攀。", "日暮微風起，難尋舊徑還。"]'),
('fdbb7018-8746-4c25-a00a-336a1a235075','宿東橫山瀨','杜牧','唐','唐诗','tang','','[]','孤舟路漸賒，時見碧桃花。',48,'全唐诗/poet.tang.28000.json','["孤舟路漸賒，時見碧桃花。", "溪雨灘聲急，巖風樹勢斜。", "獼猴懸弱柳，鸂鶒睡橫楂。", "謾向仙林宿，無人識阮家。"]'),
('263c2582-05d9-4f21-b486-bcd547701eaa','貽遷客','杜牧','唐','唐诗','tang','','[]','無機還得罪，直道不傷情。',48,'全唐诗/poet.tang.28000.json','["無機還得罪，直道不傷情。", "微雨昏山色，疎籠閉鶴聲。", "閑居多野客，高枕見江城。", "門外長溪水，憐君又濯纓。"]'),
('ccdf927c-b0d5-4603-8a99-ac627e88bf7d','陵陽送客','杜牧','唐','唐诗','tang','','[]','南樓送郢客，西郭望荆門。',48,'全唐诗/poet.tang.28000.json','["南樓送郢客，西郭望荆門。", "鳧鵠下寒渚，牛羊歸遠村。", "蘭舟倚行棹，桂酒掩餘罇。", "重此一留宿，前汀煙月昏。"]'),
('59c8555c-d6da-4681-810e-0bbd58a246e7','寄桐江隱者','杜牧','唐','唐诗','tang','','[]','潮去潮來洲渚春，山花如繡草如茵。',32,'全唐诗/poet.tang.28000.json','["潮去潮來洲渚春，山花如繡草如茵。", "嚴陵臺下桐江水，解釣鱸魚能幾人。"]'),
('952142bd-583b-4bbd-bafa-25e37f2d0953','長興里夏日寄南隣避暑','杜牧','唐','唐诗','tang','','[]','侯家大道傍，蟬噪樹蒼蒼。',48,'全唐诗/poet.tang.28000.json','["侯家大道傍，蟬噪樹蒼蒼。", "開鎖洞門遠，捲簾官舍涼。", "欄圍紅藥盛，架引綠蘿長。", "永日一欹枕，故山雲水鄉。"]'),
('a3105b52-d9ef-4848-bf48-afb35adbd9f4','送太昱禪師','杜牧','唐','唐诗','tang','','[]','禪牀深竹裏，心與徑山期。',48,'全唐诗/poet.tang.28000.json','["禪牀深竹裏，心與徑山期。", "結社多高客，登壇盡小師。", "早秋歸寺遠，新雨上灘遲。", "別後江雲碧，南齋一首詩。"]'),
('ac22b4fe-0b9a-49bd-ad10-596cc309c935','梁秀才以早春旅次大梁將歸郊扉言懷兼別示亦蒙見贈凡二十韻走筆依韻','杜牧','唐','唐诗','tang','','[]','玉塞功猶阻，金門事已陳。',240,'全唐诗/poet.tang.28000.json','["玉塞功猶阻，金門事已陳。", "世途皆擾擾，鄉黨盡循循。", "客道難投足，家聲易發身。", "松篁標節晚，蘭蕙吐詞春。", "處困羞搖尾，懷忠壯犯鱗。", "宅臨三楚水，衣帶二京塵。", "歛迹愁山鬼，遺形慕谷神。", "採芝先避貴，栽橘早防貧。", "弦泛桐材響，杯澄糯醁醇。", "但尋陶令集，休獻楚王珍。", "林密聞風遠，池平見月勻。", "藤龕紅婀娜，苔磴綠嶙峋。", "雪樹交梁苑，冰河漲孟津。", "面邀文作友，心許德爲隣。", "旅館將分被，嬰兒共灑巾。", "渭陽連漢曲，京口接漳濱。", "通塞時應定，榮枯理會均。", "儒流當自勉，妻族更誰親。", "照矚三光政，生成四氣仁。", "磻溪有心者，垂白肯湮淪。"]'),
('d93a5ed7-6c7d-47fe-b394-00b755e2d855','川守大夫劉公早歲寓居敦行里肆有題壁十韻今之置第乃獲舊居洛下大僚因有唱和歎詠不足輙獻此詩','杜牧','唐','唐诗','tang','','[]','旅館當年葺，公才此日論。',120,'全唐诗/poet.tang.28000.json','["旅館當年葺，公才此日論。", "林繁輕竹祖，樹暗惜桐孫。", "鍊藥藏金鼎，疏泉陷石盆。", "散科松有節，深薙草無根。", "龍臥池猶在，鸎遷谷尚存。", "昔爲揚子宅，今是李膺門。", "積學螢嘗聚，微詞鳳早吞。", "百年明素志，三顧起新恩。", "雪耀冰霜冷，塵飛水墨昏。", "莫教垂露迹，歲晚雜苔痕。"]'),
('81acf292-4b8b-427e-bf96-bfceded135ea','中秋日拜起居表晨渡天津橋即事十六韻獻居守相國崔公兼呈工部劉公','杜牧','唐','唐诗','tang','','[]','碧樹康莊內，清川鞏洛間。',192,'全唐诗/poet.tang.28000.json','["碧樹康莊內，清川鞏洛間。", "壇分中岳頂，城繚大河灣。", "廣殿含涼靜，深宮積翠閑。", "樓齊雲漠漠，橋束水潺潺。", "過雨檉枝潤，迎霜柿葉殷。", "紫鱗衝晚浪，白鳥背秋山。", "月拜西歸表，晨趨北向班。", "鴛鴻隨半仗，貔虎護重關。", "玉帳才容足，金罇暫解顏。", "跡留傷墮屨，恩在樂銜環。", "南省蘭先握，東堂桂早攀。", "龍門君夭矯，鶯谷我綿蠻。", "分薄嵇心懶，哀多庾鬢班。", "人慙公幹臥，頻送子牟還。", "自覩宸居壯，誰憂國步艱。", "只應時與醉，因病縱疎頑。"]'),
('b13ef423-0fc6-4e91-a62f-5c5ea99fffb3','分司東都寓居履道叨承川尹劉侍郎大夫恩知上四十韻','杜牧','唐','唐诗','tang','','[]','命世須人瑞，匡君在岳靈。',288,'全唐诗/poet.tang.28000.json','["命世須人瑞，匡君在岳靈。", "氣和薰北陸，襟曠納東溟。", "賦妙排鸚鵡，詩能繼鶺鴒。", "蒲親香案色，蘭動粉闈馨。", "周孔傳文教，蕭曹授武經。", "家童諳禁掖，廐馬識金鈴。", "性與姦邪背，心因啓沃冥。", "進賢光日月，誅惡助雷霆。", "閶闔開時召，簫韶奏處聽。", "水精懸御幄，雲母展宮屏。", "捧詔巡汧隴，飛書護井陘。", "先聲威虎兕，餘力活蟭螟。", "榮重秦軍箭，功高漢將銘。", "戈鋋迴紫塞，干戚散彤庭。", "順美皇恩洽，扶顛國步寧。", "禹謨推掌誥，湯網屬司刑。", "穉榻蓬萊掩，膺舟鞏洛停。", "馬羣先去害，民籍更添丁。", "猾吏門長塞，豪家戶不扃。", "四知臺上鏡，三惑井中瓶。", "雅韻憑開匣，雄鋩待發硎。", "火中膠綠樹，泉下斸青萍。", "五岳期雙節，三台空一星。", "鳳池方注意，麟閣會圖行。"]'),
('48b32e82-b781-438a-ae5a-90fcff37ce2b','題白雲樓','杜牧','唐','唐诗','tang','','[]','西北樓開四望通，殘霞成綺月懸弓。',64,'全唐诗/poet.tang.28000.json','["西北樓開四望通，殘霞成綺月懸弓。", "江村夜漲浮天水，澤國秋生動地風。", "高下綠苗千頃盡，新陳紅粟萬箱空。", "才微分薄憂何益，却欲回心學塞翁。"]'),
('be357910-9baf-4763-ac3e-3f8a11d074ca','贈別','杜牧','唐','唐诗','tang','','[]','眼前迎送不曾休，相續輪蹄似水流。',64,'全唐诗/poet.tang.28000.json','["眼前迎送不曾休，相續輪蹄似水流。", "門外若無南北路，人間應免別離愁。", "蘇秦六印歸何日，潘岳雙毛去值秋。", "莫怪分襟銜淚語，十年耕釣憶滄洲。"]'),
('c11425c0-11e0-41ea-ba1b-7e0b12fd5b23','秋夜與友人宿','杜牧','唐','唐诗','tang','','[]','楚國同遊過十霜，萬重心事幾堪傷。',64,'全唐诗/poet.tang.28000.json','["楚國同遊過十霜，萬重心事幾堪傷。", "蒹葭露白蓮塘淺，砧杵夜清河漢涼。", "雲外山川歸夢遠，天涯歧路客愁長。", "寒城欲曉聞吹笛，猶臥東軒月滿牀。"]'),
('168eba54-c8a7-4690-90fd-aeb22b271741','將赴京留贈僧院','杜牧','唐','唐诗','tang','','[]','九衢塵土遞追攀，馬跡軒車日暮間。',64,'全唐诗/poet.tang.28000.json','["九衢塵土遞追攀，馬跡軒車日暮間。", "玄髪盡驚爲客換，白頭曾見幾人閑。", "空悲浮世雲無定，多感流年水不還。", "謝却從前受恩地，歸來依止叩禪關。"]'),
('08a96355-143c-40eb-9c8b-abcc42b82721','寄湘中友人','杜牧','唐','唐诗','tang','','[]','莫戀醉鄉迷酒桮，流年長怕少年催。',64,'全唐诗/poet.tang.28000.json','["莫戀醉鄉迷酒桮，流年長怕少年催。", "西陵水闊魚難到，南國路遙書未回。", "匹馬計程愁日盡，一蟬何事引秋來。", "相如已定題橋志，江上無由夢釣臺。"]'),
('377fd2d1-06c2-44c3-bb4c-301674936478','江上逢友人','杜牧','唐','唐诗','tang','','[]','故國歸人酒一盃，暫亭蘭棹共裴回。',64,'全唐诗/poet.tang.28000.json','["故國歸人酒一盃，暫亭蘭棹共裴回。", "村連三峽暮雲起，潮送九江寒雨來。", "已作相如投賦計，還憑殷浩寄書迴。", "到時若見東籬菊，爲問經霜幾度開。"]'),
('b014850a-7c92-4dc5-be88-3486cb0bea18','金谷懷古','杜牧','唐','唐诗','tang','','[]','淒涼遺跡洛川東，浮世榮枯萬古同。',64,'全唐诗/poet.tang.28000.json','["淒涼遺跡洛川東，浮世榮枯萬古同。", "桃李香消金谷在，綺羅魂斷玉樓空。", "往年人事傷心外，今日風光屬夢中。", "徒想夜泉流客恨，夜泉流恨恨無窮。"]'),
('4e52d648-f27f-4c64-a47a-b06696d5e37f','寄盧先輩','杜牧','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一從分首劒江濱，南國相思寄夢頻。',64,'全唐诗/poet.tang.28000.json','["一從分首劒江濱，南國相思寄夢頻。", "書去又逢商嶺雪，信回應過洞庭春。", "關河日日悲長路，霄漢年年望後塵。", "願指丹梯曾到處，莫教猶作獨迷人。"]'),
('7fb76d3a-fa0f-4c28-afc4-73d7f1e1bdca','南樓夜','杜牧','唐','唐诗','tang','','[]','玉管金罇夜不休，如悲晝短惜年流。',64,'全唐诗/poet.tang.28000.json','["玉管金罇夜不休，如悲晝短惜年流。", "歌聲褭褭澈清夜，月色娟娟當翠樓。", "枕上暗驚垂釣夢，燈前偏起別家愁。", "思量今日英雄事，身到簪裾已白頭。"]'),
('c69eec8e-2a84-4950-9a73-dcd540447c55','行經廬山東林寺','杜牧','唐','唐诗','tang','','["\u5e90\u5c71"]','離魂斷續楚江壖，葉墜初紅十月天。',64,'全唐诗/poet.tang.28000.json','["離魂斷續楚江壖，葉墜初紅十月天。", "紫陌事多難暫息，青山長在好閑眠。", "方趨上國期干祿，未得空堂學坐禪。", "他歲若教如范蠡，也應須入五湖煙。"]'),
('db6298f9-cb5c-4b4c-9707-4959c9a8e114','途中逢故人話西山讀書早曾遊覽','杜牧','唐','唐诗','tang','','[]','西巖曾到讀書堂，穿竹行莎十里強。',64,'全唐诗/poet.tang.28000.json','["西巖曾到讀書堂，穿竹行莎十里強。", "湖上夢餘波灩灩，嶺頭愁斷路茫茫。", "經過事寄煙霞遠，名利塵隨日月長。", "莫道少年頭不白，君看潘岳幾莖霜。"]'),
('1200f8ba-fd2b-4480-b584-99457cf3f081','將赴京題陵陽王氏水居','杜牧','唐','唐诗','tang','','[]','簾卷平蕪接遠天，暫寬行役到罇前。',64,'全唐诗/poet.tang.28000.json','["簾卷平蕪接遠天，暫寬行役到罇前。", "是非境裏有閑日，榮辱塵中無了年。", "山簇暮雲千野雨，江分秋水九條煙。", "馬蹄不道貪西去，爭向一聲高樹蟬。"]'),
('2709de0e-6b44-4c05-b5c9-82915bc83ab8','送別','杜牧','唐','唐诗','tang','','[]','溪邊楊柳色參差，攀折年年贈別離。',64,'全唐诗/poet.tang.28000.json','["溪邊楊柳色參差，攀折年年贈別離。", "一片風帆望已極，三湘煙水返何時？", "多緣去棹將愁遠，猶倚危亭欲下遲。", "莫殢酒盃閑過日，碧雲深處是佳期。"]'),
('78bd43f1-9a37-410a-9671-f7fbdeaf2443','寄遠','杜牧','唐','唐诗','tang','','[]','兩葉愁眉愁不開，獨含惆悵上層臺。',64,'全唐诗/poet.tang.28000.json','["兩葉愁眉愁不開，獨含惆悵上層臺。", "碧雲空斷鴈行處，紅葉已彫人未來。", "塞外音書無信息，道傍車馬起塵埃。", "功名待寄凌煙閣，力盡遼城不肯迴。"]'),
('6699173b-2c98-4aa7-96fd-5ce5f8e5e51d','新柳','杜牧','唐','唐诗','tang','','[]','無力搖風曉色新，細腰爭妬看來頻。',64,'全唐诗/poet.tang.28000.json','["無力搖風曉色新，細腰爭妬看來頻。", "綠陰未覆長堤水，金穗先迎上苑春。", "幾處傷心懷遠路，一枝和雨送行塵。", "東門門外多離別，愁殺朝朝暮暮人。"]'),
('a66dc561-76e6-46d5-855f-8cc039e1f612','旅懷作','杜牧','唐','唐诗','tang','','[]','促促因吟晝短詩，朝驚穠色暮空枝。',64,'全唐诗/poet.tang.28000.json','["促促因吟晝短詩，朝驚穠色暮空枝。", "無情春色不長久，有限年光多盛衰。", "往事只應隨夢裏，勞生何處是閑時？", "眼前擾擾日一日，暗送白頭人不知。"]'),
('f66b80d5-086e-4f74-91f0-4896c88da754','鴈','杜牧','唐','唐诗','tang','','[]','萬里銜蘆別故鄉，雲飛雨宿向瀟湘。',64,'全唐诗/poet.tang.28000.json','["萬里銜蘆別故鄉，雲飛雨宿向瀟湘。", "數聲孤枕堪垂淚，幾處高樓欲斷腸。", "度日翩翩斜避影，臨風一一直成行。", "年年辛苦來衡岳，羽翼摧殘隴塞霜。"]'),
('7ece70a7-c48a-4800-aa3f-5417939ce33f','惜春','杜牧','唐','唐诗','tang','','[]','花開又花落，時節暗中遷。',48,'全唐诗/poet.tang.28000.json','["花開又花落，時節暗中遷。", "無計延春日，何能駐少年。", "小藂初散蝶，高柳即聞蟬。", "繁豔歸何處，滿山啼杜鵑。"]'),
('d766bc60-a7aa-4ffd-9ed7-74a4b57080ab','鴛鴦','杜牧','唐','唐诗','tang','','[]','兩兩戲沙汀，長疑畫不成。',48,'全唐诗/poet.tang.28000.json','["兩兩戲沙汀，長疑畫不成。", "錦機爭織樣，歌曲愛呼名。", "好育顧栖息，堪憐泛淺清。", "鳧鷗皆爾類，惟羨獨含情。"]'),
('f15456a8-72f0-4c28-9e52-7d5194ba4759','聞鴈','杜牧','唐','唐诗','tang','','[]','帶霜南去鴈，夜好宿汀沙。',48,'全唐诗/poet.tang.28000.json','["帶霜南去鴈，夜好宿汀沙。", "驚起向何處，高飛極海涯。", "入雲聲漸遠，離岳路由賒。", "歸夢當時斷，參差欲到家。"]'),
('ff7aa762-4959-4037-8af3-5b23c71fec46','江樓晚望','杜牧','唐','唐诗','tang','','[]','湖山翠欲結蒙籠，汗漫誰遊夕照中。',64,'全唐诗/poet.tang.28000.json','["湖山翠欲結蒙籠，汗漫誰遊夕照中。", "初語燕雛知社日，習飛鷹隼識秋風。", "波搖珠樹千尋拔，山鑿金陵萬仞空。", "不欲登樓更懷古，斜陽江上正飛鴻。"]'),
('c8b4183c-0bac-4d7f-bc2b-c60bd4f6d975','九日','杜牧','唐','唐诗','tang','','[]','金英繁亂拂闌香，明府辭官酒滿缸。',32,'全唐诗/poet.tang.28000.json','["金英繁亂拂闌香，明府辭官酒滿缸。", "還有玉樓輕薄女，笑他寒燕一雙雙。"]'),
('13ba31e4-154a-4a6b-bea0-7d3c3b666235','寄牛相公','杜牧','唐','唐诗','tang','','[]','漢水橫衝蜀浪分，危樓點的拂孤雲。',32,'全唐诗/poet.tang.28000.json','["漢水橫衝蜀浪分，危樓點的拂孤雲。", "六年仁政謳歌去，柳遶春堤處處聞。"]'),
('45d31ad0-1298-4d2b-9791-abf5ae6217a3','爲人題贈二首 一','杜牧','唐','唐诗','tang','','[]','我乏青雲稱，君無買笑金。',120,'全唐诗/poet.tang.28000.json','["我乏青雲稱，君無買笑金。", "虛傳南國貌，爭奈五陵心。", "桂席塵瑤珮，瓊鑪燼水沈。", "凝魂空薦夢，低耳悔聽琴。", "月落珠簾卷，春寒錦幕深。", "誰家樓上笛，何處月明砧？", "蘭徑飛蝴蝶，筠籠語翠襟。", "和簪拋鳳髻，將淚入鴛衾。", "的的新添恨，迢迢絕好音。", "文園終病渴，休詠白頭吟。"]'),
('7b17ef17-afc8-4012-a1d4-38c60d838bbf','爲人題贈二首 二','杜牧','唐','唐诗','tang','','[]','綠樹鶯鶯語，平江燕燕飛。',122,'全唐诗/poet.tang.28000.json','["綠樹鶯鶯語，平江燕燕飛。", "枕前聞[鴈去]，樓上送春歸。", "半月縆雙臉，凝腰素一圍。", "西牆苔漠漠，南浦夢依依。", "有恨簪花懶，無聊鬬草稀。", "雕籠長慘淡，蘭畹謾芳菲。", "鏡歛青蛾黛，燈挑皓腕肌。", "避人勻迸淚，拖袖倚殘暉。", "有貌雖桃李，單棲足是非。", "雲軿載馭去，寒夜看裁衣。"]'),
('2f8e8fcd-3837-44c6-a8ed-8d5fad1b89a8','懷紫閣山','杜牧','唐','唐诗','tang','','[]','學他趨世少深機，紫閣青霄半掩扉。',64,'全唐诗/poet.tang.28000.json','["學他趨世少深機，紫閣青霄半掩扉。", "山路遠懷王子晉，詩家長憶謝玄暉。", "百年不肯疎榮辱，雙鬢終應老是非。", "人道青山歸去好，青山曾有幾人歸。"]'),
('74ca8f60-156f-4e8d-be89-af81e81a4e21','題孫逸人山居','杜牧','唐','唐诗','tang','','[]','長懸青紫與芳枝，塵剎無應免別離。',64,'全唐诗/poet.tang.28000.json','["長懸青紫與芳枝，塵剎無應免別離。", "馬上多于在家日，罇前堪憶少年時。", "關河客夢還鄉遠，雨雪山程出店遲。", "却羨高人終此老，軒車過盡不知誰。"]'),
('972e906f-1d41-4dbd-91a6-cea7d0ac0103','中途寄友人','杜牧','唐','唐诗','tang','','[]','道傍高木盡依依，落葉驚風處處飛。',64,'全唐诗/poet.tang.28000.json','["道傍高木盡依依，落葉驚風處處飛。", "未到鄉關聞早鴈，獨於客路授寒衣。", "煙霞舊想長相阻，書劒投人久不歸。", "何日一名隨事了，與君同採碧溪薇。"]'),
('db854b4c-e12b-4df4-a689-38b9b21c92fc','悵詩','杜牧','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5"]','自是尋春去校遲，不須惆悵怨芳時。',32,'全唐诗/poet.tang.28000.json','["自是尋春去校遲，不須惆悵怨芳時。", "狂風落盡深紅色，綠葉成陰子滿枝。"]'),
('09c0b985-2860-4c36-9819-34bf9492b4cb','吳宮詞二首 一','杜牧','唐','唐诗','tang','','[]','越兵驅綺羅，越女唱吳歌。',48,'全唐诗/poet.tang.28000.json','["越兵驅綺羅，越女唱吳歌。", "宮燼花聲少，臺荒麋跡多。", "茱萸垂曉露，菡萏落秋波。", "無遣君王醉，滿城嚬翠蛾。"]'),
('2bb8eaf8-053d-4a82-a3f2-50ef87acb86e','吳宮詞二首 二','杜牧','唐','唐诗','tang','','[]','香逕遶吳宮，千帆落照中。',48,'全唐诗/poet.tang.28000.json','["香逕遶吳宮，千帆落照中。", "鶴鳴山苦雨，魚躍水多風。", "城帶晚莎綠，池連秋蓼紅。", "當年國門外，誰信伍員忠。"]'),
('c42792a9-b483-48a9-8f8d-b0ed6d22db1c','金陵','杜牧','唐','唐诗','tang','','[]','始發碧江口，曠然諧遠心。',48,'全唐诗/poet.tang.28000.json','["始發碧江口，曠然諧遠心。", "風清舟在鑑，日落水浮金。", "瓜步逢潮信，臺城過雁音。", "故鄉何處是，雲外即喬林。"]'),
('2087940b-efb1-46e8-9f42-9d61118e2f65','即事','杜牧','唐','唐诗','tang','','[]','小院無人雨長苔，滿庭修竹間疎槐。',32,'全唐诗/poet.tang.28000.json','["小院無人雨長苔，滿庭修竹間疎槐。", "春愁兀兀成幽夢，又被流鶯喚醒來。"]'),
('4f748737-934b-41fb-92a1-15ac0106f5ff','七夕','杜牧','唐','唐诗','tang','','[]','雲堦月地一相過，未抵經年別恨多。',32,'全唐诗/poet.tang.28000.json','["雲堦月地一相過，未抵經年別恨多。", "最恨明朝洗車雨，不教回脚渡天河。"]'),
('978ec320-75b9-4de0-b0a1-4bf2f24deba9','薔薇花','杜牧','唐','唐诗','tang','','[]','朵朵精神葉葉柔，雨晴香拂醉人頭。',32,'全唐诗/poet.tang.28000.json','["朵朵精神葉葉柔，雨晴香拂醉人頭。", "石家錦幛依然在，閑倚狂風夜不收。"]'),
('9f60ca29-73a7-4d6d-920c-163e1757cd78','句','杜牧','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','幽人聽達曙，聊罷蘇牀琴。',106,'全唐诗/poet.tang.28000.json','["幽人聽達曙，聊罷蘇牀琴。", "魚多知海熟，藥少覺山貧。", "土控吳兼越，州連歙與池。", "山河地襟帶，軍鎮國藩維。", "綠水櫂雲月，洞庭歸路長。", "春橋垂酒幔，夜柵集茶檣。", "箬影沈溪暖，蘋花遶郭香。", "經冬野菜青青色，未臘山梅樹樹花。", "半破前峰月。"]'),
('2bfd5f7d-2db9-40e9-9756-e662b1f26902','陪王尚書泛舟蓮池','許渾','唐','唐诗','tang','','[]','蓮塘移畫舸，泛泛日華清。',48,'全唐诗/poet.tang.28000.json','["蓮塘移畫舸，泛泛日華清。", "水暖魚頻躍，煙秋雁早鳴。", "舞疑回雪態，歌轉遏雲聲。", "客散山公醉，風高月滿城。"]'),
('e1f232cc-76bc-49e2-9939-c9afe9382fd7','贈裴處士','許渾','唐','唐诗','tang','','[]','爲儒白髮生，鄉里早聞名。',48,'全唐诗/poet.tang.28000.json','["爲儒白髮生，鄉里早聞名。", "煖酒雪初下，讀書山欲明。", "字形翻鳥跡，詩調合猿聲。", "門外滄浪水，知君欲濯纓。"]'),
('66eef6e0-819c-4d4b-ba83-72358755f2d9','對雪','許渾','唐','唐诗','tang','','[]','飛舞北風涼，玉人歌玉堂。',48,'全唐诗/poet.tang.28000.json','["飛舞北風涼，玉人歌玉堂。", "簾帷增曙色，珠翠發寒光。", "柳重絮微濕，梅繁花未香。", "茲辰賀豐歲，簫鼓宴梁王。"]'),
('37d5c005-1f9d-475d-b6f6-4db178d71dfe','王居士','許渾','唐','唐诗','tang','','[]','筇杖倚柴關，都城賣卜還。',48,'全唐诗/poet.tang.28000.json','["筇杖倚柴關，都城賣卜還。", "雨中耕白水，雲外斸青山。", "有藥身長健，無機性自閑。", "即應生羽翼，華表在人間。"]'),
('fedb06cc-37da-4aaf-8f39-85ebcb08b947','早秋三首 一','許渾','唐','唐诗','tang','','["\u5199\u666f", "\u79cb\u5929", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7"]','遙夜泛清瑟，西風生翠蘿。',48,'全唐诗/poet.tang.28000.json','["遙夜泛清瑟，西風生翠蘿。", "殘螢委玉露，早鴈拂銀河。", "高樹曉還密，遠山晴更多。", "淮南一葉下，自覺老煙波。"]'),
('63cfaf6e-f0d7-4b7a-a1b6-156d046d6549','早秋三首 二','許渾','唐','唐诗','tang','','[]','一葉下前墀，淮南人已悲。',36,'全唐诗/poet.tang.28000.json','["一葉下前墀，淮南人已悲。", "蹉跎青漢望，迢遰白雲期。", "老信相如渴，貧憂曼倩飢。"]'),
('cdc94ca1-bd5e-43a2-8233-581d68b277de','早秋三首 三','許渾','唐','唐诗','tang','','[]','薊北雁猶遠，淮南人已悲。',48,'全唐诗/poet.tang.28000.json','["薊北雁猶遠，淮南人已悲。", "殘桃間墮井，新菊亦侵籬。", "書劒豈相誤，琴尊聊自持。", "西齋風雨夜，更有詠貧詩。"]'),
('8871da0e-5659-48ca-b47e-4fdc2871e542','洛東蘭若夜歸','許渾','唐','唐诗','tang','','[]','一衲老禪牀，吾生半異鄉。',48,'全唐诗/poet.tang.28000.json','["一衲老禪牀，吾生半異鄉。", "管弦愁裏老，書劒夢中忙。", "鳥急山初暝，蟬稀樹正涼。", "又歸何處去，塵路月蒼蒼。"]'),
('97d990bf-0a3d-42bf-ad1f-20ab8a7eae80','送段覺歸杜曲閑居','許渾','唐','唐诗','tang','','[]','書劒南歸去，山扉別幾年。',48,'全唐诗/poet.tang.28000.json','["書劒南歸去，山扉別幾年。", "苔侵巖下路，果落洞中泉。", "紅葉高齋雨，青蘿曲檻煙。", "寧知遠游客，羸馬太行前。"]'),
('4c200404-86a6-44c1-be5d-925f67a29a2b','寄天鄉寺仲儀上人富春孫處士','許渾','唐','唐诗','tang','','[]','詩僧與釣翁，千里兩情通。',48,'全唐诗/poet.tang.28000.json','["詩僧與釣翁，千里兩情通。", "雲帶鴈門雪，水連漁浦風。", "心期榮辱外，名挂是非中。", "歲晚亦歸去，田園清洛東。"]'),
('db574e31-99c3-42fa-8b45-00bb52037cad','寄契盈上人','許渾','唐','唐诗','tang','','[]','何處是西林，疎鐘復遠砧。',48,'全唐诗/poet.tang.28000.json','["何處是西林，疎鐘復遠砧。", "鴈來秋水闊，鴉盡夕陽沈。", "婚嫁乖前志，功名異夙心。", "湯師不可問，江上碧雲深。"]'),
('1b38cd90-d673-48c6-a71c-d09b9c622e25','晨起二首 一','許渾','唐','唐诗','tang','','[]','桂樹綠層層，風微煙露凝。',48,'全唐诗/poet.tang.28000.json','["桂樹綠層層，風微煙露凝。", "簷楹銜落月，幃幌映殘燈。", "蘄簟曙香冷，越瓶秋水澄。", "心閑即無事，何異住山僧。"]'),
('5416fc63-68d3-4259-88ac-6278432931e8','晨起二首 二','許渾','唐','唐诗','tang','','[]','殘月皓煙露，掩門深竹齋。',48,'全唐诗/poet.tang.28000.json','["殘月皓煙露，掩門深竹齋。", "水蟲鳴曲檻，山鳥下空階。", "清鏡曉看髪，素琴秋寄懷。", "因知北窗客，日與世情乖。"]'),
('4a1fa9b2-6635-453a-b2ce-bba56021376c','曉發鄞江北渡寄崔韓二先輩','許渾','唐','唐诗','tang','','[]','南北信多岐，生涯半別離。',48,'全唐诗/poet.tang.28000.json','["南北信多岐，生涯半別離。", "地窮山盡處，江泛水寒時。", "露曉蒹葭重，霜晴橘柚垂。", "無勞促回檝，千里有心期。"]'),
('13693ea3-2a58-4c7e-a114-af3df8816d71','盈上人','許渾','唐','唐诗','tang','','[]','月沈霜已凝，無夢竟寒燈。',48,'全唐诗/poet.tang.28000.json','["月沈霜已凝，無夢竟寒燈。", "寄世何殊客，修身未到僧。", "二毛梳上雪，雙淚枕前冰。", "借問曹溪路，山多路幾層。"]'),
('c8eb5ada-10d7-423a-aae6-647f4a1c6c9f','廣陵道中','許渾','唐','唐诗','tang','','[]','城勢已坡陀，城邊東逝波。',48,'全唐诗/poet.tang.28000.json','["城勢已坡陀，城邊東逝波。", "綠桑非苑樹，青草是宮莎。", "山暝牛羊少，水寒鳧鴈多。", "因高一回首，還詠黍離歌。"]'),
('c8599f94-fc90-443f-8a40-d556f8724b2b','宿開元寺樓','許渾','唐','唐诗','tang','','[]','誰家歌褭褭，孤枕在西樓。',48,'全唐诗/poet.tang.28000.json','["誰家歌褭褭，孤枕在西樓。", "竹色寒清簟，松香染翠幬。", "月移珠殿曉，風遰玉箏秋。", "日出應移棹，三湘萬里愁。"]'),
('1e82eadf-3c24-49c0-9771-bcb4bddabc6e','洞靈觀冬青','許渾','唐','唐诗','tang','','[]','霜霰不凋色，兩株交石壇。',48,'全唐诗/poet.tang.28000.json','["霜霰不凋色，兩株交石壇。", "未秋紅實淺，經夏綠陰寒。", "露重蟬鳴急，風多鳥宿難。", "何如西禁柳，晴舞玉闌干。"]'),
('6ba82d59-8e2e-4ade-8f2a-48df44825c5c','送友人自荆襄歸江東','許渾','唐','唐诗','tang','','[]','商洛轉江濆，一杯聊送君。',48,'全唐诗/poet.tang.28000.json','["商洛轉江濆，一杯聊送君。", "劒愁龍失伴，琴怨鶴離羣。", "楚驛枕秋水，湘帆凌暮雲。", "猿聲斷腸夜，應向雨中聞。"]'),
('ad9d3fdf-78b1-4091-a5f3-394608cb87c4','送同年崔先輩','許渾','唐','唐诗','tang','','[]','西風帆勢輕，南浦遍離情。',48,'全唐诗/poet.tang.28000.json','["西風帆勢輕，南浦遍離情。", "菊豔含秋水，荷花遰雨聲。", "扣舷灘鳥沒，移棹草蟲鳴。", "更憶前年別，槐花滿鳳城。"]'),
('1a6f80c1-092b-4534-bd0b-a602cf0e9914','山雞','許渾','唐','唐诗','tang','','[]','珍禽暫不扃，飛舞躍前庭。',48,'全唐诗/poet.tang.28000.json','["珍禽暫不扃，飛舞躍前庭。", "翠網摧金距，雕籠減繡翎。", "月圓疑望鏡，花暖似依屏。", "何必舊巢去，山山芳草青。"]'),
('b06445bc-ad26-4e2f-8364-b3effc4c0a18','孤鴈','許渾','唐','唐诗','tang','','[]','昔年雙頡頏，池上靄春暉。',48,'全唐诗/poet.tang.28000.json','["昔年雙頡頏，池上靄春暉。", "霄漢力猶怯，稻粱心已違。", "蘆洲寒獨宿，榆塞夜孤飛。", "不及營巢燕，西風相伴歸。"]'),
('4f19cf9e-5a90-47ff-8a55-9f3a9db209f8','寓懷','許渾','唐','唐诗','tang','','[]','南國浣紗伴，盈盈天下姝。',48,'全唐诗/poet.tang.28000.json','["南國浣紗伴，盈盈天下姝。", "盤金明繡帶，動珮響羅襦。", "素手怨瑤瑟，清心悲玉壺。", "春華坐銷落，未忍泣蘼蕪。"]'),
('d62f99e9-ef65-448f-9930-7fdb06e4c06a','洛中遊眺貽同志','許渾','唐','唐诗','tang','','[]','康衢一望通，河洛正天中。',48,'全唐诗/poet.tang.28000.json','["康衢一望通，河洛正天中。", "樓勢排高鳳，橋形架斷虹。", "遠山晴帶雪，寒水晚多風。", "幾日還攜手，鳥鳴花滿宮。"]'),
('eda154d7-9bbf-4c0e-be4f-342c0e1128c7','夏日戲題郭別駕東堂','許渾','唐','唐诗','tang','','[]','微風起畫鸞，金翠暗珊珊。',48,'全唐诗/poet.tang.28000.json','["微風起畫鸞，金翠暗珊珊。", "晚樹垂朱實，春篁露粉竿。", "散香蘄簟滑，沈水越瓶寒。", "猶恐何郎熱，冰生白玉盤。"]'),
('f4e91c5f-14bf-48ee-ad1b-a4430e1a5e15','長安旅夜','許渾','唐','唐诗','tang','','[]','久客怨長夜，西風吹鴈聲。',48,'全唐诗/poet.tang.28000.json','["久客怨長夜，西風吹鴈聲。", "雲移河漢淺，月泛露華清。", "掩瑟獨凝思，緩歌空寄情。", "門前有歸路，迢遰洛陽城。"]'),
('20b87aaa-89cf-47f9-b711-534ec1c996c8','鸂鶒','許渾','唐','唐诗','tang','','[]','池寒柳復凋，獨宿夜迢迢。',48,'全唐诗/poet.tang.28000.json','["池寒柳復凋，獨宿夜迢迢。", "雨頂冠應冷，風毛劒欲飄。", "故巢迷碧水，舊侶越丹霄。", "不是無歸處，心高多寂寥。"]'),
('96facf2a-2d4b-4c7d-ae52-592710f0e8f9','懿安皇太后挽歌詞','許渾','唐','唐诗','tang','','[]','陵前春不盡，陵下夜何窮。',48,'全唐诗/poet.tang.28000.json','["陵前春不盡，陵下夜何窮。", "未信金蠶老，先驚玉燕空。", "挽移蘭殿月，笳引柏城風。", "自此隨龍馭，橋山翠靄中。"]'),
('e7dd7ca6-3e1f-47ba-b5a0-09c950cf0ba2','示弟','許渾','唐','唐诗','tang','','[]','自爾出門去，淚痕長滿衣。',48,'全唐诗/poet.tang.28000.json','["自爾出門去，淚痕長滿衣。", "家貧爲客早，路遠得書稀。", "文字何人賞，煙波幾日歸。", "秋風正搖落，孤鴈又南飛。"]'),
('a3271f92-09a8-4fc5-93c4-6258d5ba2ea0','送楊處士叔初卜居曲江','許渾','唐','唐诗','tang','','[]','鴈門歸去遠，垂老脫袈裟。',48,'全唐诗/poet.tang.28000.json','["鴈門歸去遠，垂老脫袈裟。", "蕭寺休爲客，曹溪便寄家。", "綠琪千歲樹，黃槿四時花。", "別怨應無限，門前桂水斜。"]'),
('e4935d66-666b-4003-8ad9-24879fdc118c','發靈溪館','許渾','唐','唐诗','tang','','[]','山多水不窮，一葉似漁翁。',48,'全唐诗/poet.tang.28000.json','["山多水不窮，一葉似漁翁。", "鳥浴寒潭雨，猿吟暮嶺風。", "雜英垂錦繡，衆籟合絲桐。", "應有曹溪路，千巖萬壑中。"]'),
('f894e67f-f9c3-4e7b-979d-00e8dabd743b','題杜居士','許渾','唐','唐诗','tang','','[]','松偃石牀平，何人識姓名。',48,'全唐诗/poet.tang.28000.json','["松偃石牀平，何人識姓名。", "溪冰寒棹響，巖雪夜窗明。", "機盡心猿伏，神閑意馬行。", "應知此來客，身世兩無情。"]'),
('925cae85-b045-4109-af8e-607819e6d254','神女祠','許渾','唐','唐诗','tang','','[]','停車祀聖女，涼葉下陰風。',48,'全唐诗/poet.tang.28000.json','["停車祀聖女，涼葉下陰風。", "龍氣石牀濕，鳥聲山廟空。", "長眉留桂綠，丹臉寄蓮紅。", "莫學陽臺畔，朝雲暮雨中。"]'),
('0acee9d4-9c93-4139-aeda-cbd22d787387','送李定言南遊','許渾','唐','唐诗','tang','','[]','酒酣輕別恨，酒醒復離憂。',48,'全唐诗/poet.tang.28000.json','["酒酣輕別恨，酒醒復離憂。", "遠水應移棹，高峯更上樓。", "簟涼清露夜，琴響碧天秋。", "重惜芳尊宴，滿城無舊游。"]'),
('5779c07f-80fc-414b-8dc6-76ee7c14b5cd','早發中巖寺別契直上人','許渾','唐','唐诗','tang','','[]','蒼蒼松桂陰，殘月半西岑。',48,'全唐诗/poet.tang.28000.json','["蒼蒼松桂陰，殘月半西岑。", "素壁寒燈暗，紅爐夜火深。", "廚開山鼠散，鐘盡嶺猿吟。", "行役方如此，逢師嬾話心。"]'),
('6aa2fd24-3a53-4459-a2cb-a141d9343dfe','行次潼關題驛後軒','許渾','唐','唐诗','tang','','[]','飛閣極層臺，終南此路回。',48,'全唐诗/poet.tang.28000.json','["飛閣極層臺，終南此路回。", "山形朝闕去，河勢抱關來。", "鴈過秋風急，蟬鳴宿霧開。", "平生無限意，驅馬任塵埃。"]'),
('b9ef9f61-44e2-453d-8f46-809449fd3b85','晨至南亭呈裴明府','許渾','唐','唐诗','tang','','[]','南齋夢釣竿，晨起月猶殘。',48,'全唐诗/poet.tang.28000.json','["南齋夢釣竿，晨起月猶殘。", "露重螢依草，風高蝶委蘭。", "池光秋鏡澈，山色曉屏寒。", "更戀陶彭澤，無心議去官。"]'),
('3683ef45-e2e6-49d1-af4e-fcf55925b925','灞東題司馬郊園','許渾','唐','唐诗','tang','','[]','楚翁秦塞住，昔事李輕車。',48,'全唐诗/poet.tang.28000.json','["楚翁秦塞住，昔事李輕車。", "白社貧思橘，青門老仰瓜。", "讀書三逕草，沽酒一籬花。", "更欲尋芝朮，商山便寄家。"]'),
('4112cb7e-bf6b-4476-becd-9392aec49d61','游維山新興寺宿石屏村謝叟家','許渾','唐','唐诗','tang','','[]','晚過石屏村，村長日漸曛。',48,'全唐诗/poet.tang.28000.json','["晚過石屏村，村長日漸曛。", "僧歸下嶺見，人語隔溪聞。", "谷響寒耕雪，山明夜燒雲。", "家家扣銅鼓，欲賽魯將軍。"]'),
('84c91cd2-10a8-4d62-8d03-4a5d73ccb3b6','送從兄歸隱藍溪二首 一','許渾','唐','唐诗','tang','','[]','名高猶素衣，窮巷掩荆扉。',48,'全唐诗/poet.tang.28000.json','["名高猶素衣，窮巷掩荆扉。", "漸老故人少，久貧豪客稀。", "塞雲橫劒望，山月抱琴歸。", "幾日藍溪醉，藤花拂釣磯。"]'),
('fb58f507-ddc3-4bbd-be19-06d2889c88a3','送從兄歸隱藍溪二首 二','許渾','唐','唐诗','tang','','[]','京洛多高蓋，憐兄劇斷蓬。',48,'全唐诗/poet.tang.28000.json','["京洛多高蓋，憐兄劇斷蓬。", "身隨一劒老，家入萬山空。", "夜憶蕭關月，行悲易水風。", "無人知此意，甘臥白雲中。"]'),
('9f9d8df6-46d6-44b2-9b7b-c6e2081702c9','村舍','許渾','唐','唐诗','tang','','[]','燕鴈下秋塘，田家自此忙。',48,'全唐诗/poet.tang.28000.json','["燕鴈下秋塘，田家自此忙。", "移蔬通遠水，收果待繁霜。", "野碓舂秔滑，山廚焙茗香。", "客來還有酒，隨事宿茅堂。"]'),
('ac9288a2-ad21-45fc-8208-c449ed069dfe','思歸','許渾','唐','唐诗','tang','','[]','疊嶂平蕪外，依依識舊邦。',48,'全唐诗/poet.tang.28000.json','["疊嶂平蕪外，依依識舊邦。", "氣高詩易怨，愁極酒難降。", "樹暗支公院，山寒謝守窗。", "殷勤樓下水，幾日到荆江。"]'),
('4d728f52-c34d-433e-b22a-bf13d6380617','晚泊七里灘','許渾','唐','唐诗','tang','','[]','天晚日沈沈，歸舟繫柳陰。',48,'全唐诗/poet.tang.28000.json','["天晚日沈沈，歸舟繫柳陰。", "江村平見寺，山郭遠聞砧。", "樹密猿聲響，波澄鴈影深。", "榮華暫時事，誰識子陵心。"]'),
('91a79230-f568-44ab-825a-a57a4d3f00b0','寄題南山王隱居','許渾','唐','唐诗','tang','','[]','近逢商洛客，知爾住南塘。',48,'全唐诗/poet.tang.28000.json','["近逢商洛客，知爾住南塘。", "草閣平春水，柴門掩夕陽。", "隨蜂收野蜜，尋麝采生香。", "更憶前年醉，松花滿石牀。"]'),
('80b5251d-f467-4589-b268-1a12592369f3','晨裝','許渾','唐','唐诗','tang','','[]','帶月飯行侶，西游關塞長。',48,'全唐诗/poet.tang.28000.json','["帶月飯行侶，西游關塞長。", "晨雞鳴遠戍，宿鴈起寒塘。", "雲卷四山雪，風凝千樹霜。", "誰家游俠子，沈醉臥蘭堂。"]'),
('5dae0e95-3506-4a0a-a9e8-53960ec35271','題韋隱居西齋','許渾','唐','唐诗','tang','','[]','斸藥去還歸，家人半掩扉。',48,'全唐诗/poet.tang.28000.json','["斸藥去還歸，家人半掩扉。", "山風藤子落，溪雨豆花肥。", "寺遠僧來少，橋危客到稀。", "不聞砧杵動，應解製荷衣。"]'),
('c93792f9-5858-4a15-8ed6-ecd32441ecc9','送李溟秀才西行','許渾','唐','唐诗','tang','','[]','萬里不辭勞，寒裝疊緼袍。',48,'全唐诗/poet.tang.28000.json','["萬里不辭勞，寒裝疊緼袍。", "停車山店雨，挂席海門濤。", "鷹勢暮偏急，鶴聲秋更高。", "知君北邙路，留劒泣黃蒿。"]'),
('b7390785-10d9-4bc3-9af9-70e3c774d9b9','經馬鎮西宅','許渾','唐','唐诗','tang','','[]','將軍久已沒，行客自興哀。',48,'全唐诗/poet.tang.28000.json','["將軍久已沒，行客自興哀。", "功業山長在，繁華水不回。", "亂藤侵廢井，荒菊上叢臺。", "借問此中事，幾家歌舞來。"]'),
('85d58eb2-4f47-465d-a136-408cacf26ef9','重遊鬱林寺道玄上人院','許渾','唐','唐诗','tang','','[]','藤杖叩松關，春溪斸藥還。',48,'全唐诗/poet.tang.28000.json','["藤杖叩松關，春溪斸藥還。", "雨晴巢燕急，波暖浴鷗閑。", "倚檻花臨水，回舟月照山。", "憶歸師莫笑，書劒在人間。"]'),
('52dcd2d6-4257-4e42-b5e5-28b6d01415f0','泛溪','許渾','唐','唐诗','tang','','[]','疑與武陵通，青溪碧嶂中。',48,'全唐诗/poet.tang.28000.json','["疑與武陵通，青溪碧嶂中。", "水寒深見石，松晚靜聞風。", "遯迹驅雞吏，冥心失馬翁。", "纔應畢婚嫁，還此息微躬。"]'),
('4e2b23d0-14e2-4055-a8d2-a9f4ed90fe72','送樓煩李別駕','許渾','唐','唐诗','tang','','[]','琴清詩思勞，更欲學龍韜。',48,'全唐诗/poet.tang.28000.json','["琴清詩思勞，更欲學龍韜。", "王粲暫停筆，呂虔初佩刀。", "夜吟關月靜，秋望塞雲高。", "去去從軍樂，鵰飛代馬豪。"]'),
('bee7dc17-e38c-4756-885f-1d7c422cf46a','聞兩河用兵因貽友人','許渾','唐','唐诗','tang','','[]','故人日已遠，身事與誰論。',48,'全唐诗/poet.tang.28000.json','["故人日已遠，身事與誰論。", "性拙難趨世，心孤易感恩。", "秋悲憐宋玉，夜舞笑劉琨。", "徒有干時策，青山尚掩門。"]'),
('0d726f81-2211-4151-9bb4-6f59bbac3361','獻白尹','許渾','唐','唐诗','tang','','[]','醉舞任生涯，褐寬烏帽斜。',48,'全唐诗/poet.tang.28000.json','["醉舞任生涯，褐寬烏帽斜。", "庾公先在郡，疎傅早還家。", "林晚鳥爭樹，園春蜂護花。", "高吟應更逸，嵩洛舊煙霞。"]'),
('b93db053-2961-48be-86b9-0756a74ab797','茅山贈梁尊師','許渾','唐','唐诗','tang','','[]','雲屋何年客，青山白日長。',48,'全唐诗/poet.tang.28000.json','["雲屋何年客，青山白日長。", "種花春掃雪，看籙夜焚香。", "上象壺中闊，平生夢裏忙。", "幸承仙籍後，乞取大還方。"]'),
('eddec6b2-bcd2-454b-939a-b4165317282e','聞薛先輩陪大夫看早梅因寄','許渾','唐','唐诗','tang','','[]','澗梅寒正發，莫信笛中吹。',48,'全唐诗/poet.tang.28000.json','["澗梅寒正發，莫信笛中吹。", "素豔雪凝樹，清香風滿枝。", "折驚山鳥散，攜任野蜂隨。", "今日從公醉，何人倒接䍦。"]'),
('7843035d-54ca-495e-a134-799205580a0a','送前緱氏韋明府南游','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','酒闌橫劒歌，日暮望關河。',48,'全唐诗/poet.tang.28000.json','["酒闌橫劒歌，日暮望關河。", "道直去官早，家貧爲客多。", "山昏函谷雨，木落洞庭波。", "莫盡遠游興，故園荒薜蘿。"]'),
('cae58fed-90b3-4662-b9a4-728c392f97dc','看雪','許渾','唐','唐诗','tang','','[]','松亞竹珊珊，心知萬井歡。',48,'全唐诗/poet.tang.28000.json','["松亞竹珊珊，心知萬井歡。", "山明迷舊徑，溪滿漲新瀾。", "客醉瑤臺曙，兵防玉塞寒。", "紅樓知有酒，誰肯學袁安。"]'),
('b2b99c5e-e0da-49f3-b293-d71c5b404e8f','贈僧','許渾','唐','唐诗','tang','','[]','心法本無住，流沙歸復來。',48,'全唐诗/poet.tang.28000.json','["心法本無住，流沙歸復來。", "錫隨山鳥動，經附海船回。", "洗足柳遮寺，坐禪花委苔。", "唯將一童子，又欲上天台。"]'),
('08824232-c3d6-4670-81a4-59fab9a554b4','趨慈和寺移宴','許渾','唐','唐诗','tang','','[]','高寺移清宴，漁舟繫綠蘿。',48,'全唐诗/poet.tang.28000.json','["高寺移清宴，漁舟繫綠蘿。", "潮平秋水闊，雲歛暮山多。", "廣檻停簫鼓，繁弦散綺羅。", "西樓半牀月，莫問夜如何。"]'),
('fa8170d0-81ea-4583-8484-c10f60fb8a3d','留贈偃師主人','許渾','唐','唐诗','tang','','[]','孤城漏未殘，徒侶拂征鞍。',48,'全唐诗/poet.tang.28000.json','["孤城漏未殘，徒侶拂征鞍。", "洛北去游遠，淮南歸夢闌。", "曉燈回壁暗，晴雪卷簾寒。", "強盡主人酒，出門行路難。"]'),
('52115b43-aaab-4d61-b404-0d43dedef0dc','送南陵李少府','許渾','唐','唐诗','tang','','[]','高人亦未閑，來往楚雲間。',48,'全唐诗/poet.tang.28000.json','["高人亦未閑，來往楚雲間。", "劒在心應壯，書窮鬢已斑。", "落帆秋水寺，驅馬夕陽山。", "明日南昌尉，空齋又掩關。"]'),
('84a40be5-cd3b-498a-829d-452aaebd6d70','別韋處士','許渾','唐','唐诗','tang','','[]','南北斷蓬飛，別多相見稀。',48,'全唐诗/poet.tang.28000.json','["南北斷蓬飛，別多相見稀。", "更傷今日酒，未換昔年衣。", "舊友幾人在，故鄉何處歸？", "秦原向西路，雲晚雪霏霏。"]'),
('e174911d-3ccf-46fe-ba9c-7c815fb842dc','九日登樟亭驛樓','許渾','唐','唐诗','tang','','[]','鱸鱠與蒪羹，西風片席輕。',48,'全唐诗/poet.tang.28000.json','["鱸鱠與蒪羹，西風片席輕。", "潮回孤島晚，雲歛衆山晴。", "丹羽下高閣，黃花垂古城。", "因秋倍多感，鄉樹接咸京。"]'),
('f0f7e42b-1b55-4bc1-806d-6bff4553d3fd','再遊越中傷朱餘慶協律好直上人','許渾','唐','唐诗','tang','','[]','昔年湖上客，留訪雪山翁。',48,'全唐诗/poet.tang.28000.json','["昔年湖上客，留訪雪山翁。", "王氏船猶在，蕭家寺已空。", "月高花有露，煙合水無風。", "處處多遺韻，何曾入剡中。"]'),
('e75685d9-1b7a-47b9-a61c-626f0295dcaf','京口津亭送張崔二侍御','許渾','唐','唐诗','tang','','[]','愛樹滿西津，津亭墮淚頻。',48,'全唐诗/poet.tang.28000.json','["愛樹滿西津，津亭墮淚頻。", "素車應度洛，珠履更歸秦。", "水接三湘暮，山通五嶺春。", "傷離與懷舊，明日白頭人。"]'),
('f569440d-43b1-4550-b457-6db79ec5517e','江樓夜別','許渾','唐','唐诗','tang','','[]','離別奈情何，江樓凝豔歌。',48,'全唐诗/poet.tang.28000.json','["離別奈情何，江樓凝豔歌。", "蕙蘭秋露重，蘆葦夜風多。", "深怨寄清瑟，遠愁生翠蛾。", "酒酣相顧起，明月棹寒波。"]'),
('64534330-2243-4baf-ba90-86dfc324761a','送惟素上人歸新安','許渾','唐','唐诗','tang','','[]','山空葉復落，一逕下新安。',48,'全唐诗/poet.tang.28000.json','["山空葉復落，一逕下新安。", "風急渡溪晚，雪晴歸寺寒。", "尋雲策藤杖，向日倚蒲團。", "寧憶西游客，勞勞歌路難。"]'),
('fa790d33-c9ed-40bf-8ae0-f1071d003bdc','霅上宴別','許渾','唐','唐诗','tang','','[]','山斷水茫茫，洛人西路長。',48,'全唐诗/poet.tang.28000.json','["山斷水茫茫，洛人西路長。", "笙歌留遠棹，風雨寄華堂。", "紅壁耿秋燭，翠簾凝曉香。", "誰堪從此去，雲樹滿陵陽。"]'),
('2a51616d-dabb-4327-8917-1f66187b5277','下第別友人楊至之','許渾','唐','唐诗','tang','','[]','花落水潺潺，十年離舊山。',48,'全唐诗/poet.tang.28000.json','["花落水潺潺，十年離舊山。", "夜愁添白髮，春淚減朱顏。", "孤劒北游塞，遠書東出關。", "逢君話心曲，一醉灞陵間。"]'),
('7e8a43db-d4c8-4bc5-b962-80b94004ceba','尋戴處士','許渾','唐','唐诗','tang','','[]','車馬長安道，誰知大隱心。',48,'全唐诗/poet.tang.28000.json','["車馬長安道，誰知大隱心。", "蠻僧留古鏡，蜀客寄新琴。", "曬藥竹齋暖，擣茶松院深。", "思君一相訪，殘雪似山陰。"]'),
('b5bec487-a3df-469c-a069-b8d2ce92074b','放猿','許渾','唐','唐诗','tang','','[]','殷勤解金鎖，昨夜雨淒淒。',48,'全唐诗/poet.tang.28000.json','["殷勤解金鎖，昨夜雨淒淒。", "山淺憶巫峽，水寒思建溪。", "遠尋紅樹宿，深向白雲啼。", "好覓來時路，煙蘿莫共迷。"]'),
('8b208bff-3a2e-48a1-bbaf-c5c9cba720d6','將離郊園留示弟姪','許渾','唐','唐诗','tang','','[]','身賤與心違，秋風生旅衣。',48,'全唐诗/poet.tang.28000.json','["身賤與心違，秋風生旅衣。", "久貧辭國遠，多病在家稀。", "山暝客初散，樹涼人未歸。", "西都萬餘里，明旦別柴扉。"]'),
('b594270e-32d5-4cc7-bd15-05bb17ea198e','夜歸丁卯橋村舍','許渾','唐','唐诗','tang','','[]','月涼風靜夜，歸客泊巖前。',48,'全唐诗/poet.tang.28000.json','["月涼風靜夜，歸客泊巖前。", "橋響犬遙吠，庭空人散眠。", "紫蒲低水檻，紅葉半江船。", "自有還家計，南湖二頃田。"]'),
('c62b0d58-fa1d-4473-af0d-7cd2311ee658','題青山館','許渾','唐','唐诗','tang','','[]','昔人詩酒地，芳草思王孫。',48,'全唐诗/poet.tang.28000.json','["昔人詩酒地，芳草思王孫。", "白水半塘岸，青山橫郭門。", "懸巖碑已折，盤石井猶存。", "無處繼行樂，野花空一尊。"]'),
('64924211-3ff5-4000-a085-94e5792e8fa5','秋日衆哲館對竹','許渾','唐','唐诗','tang','','[]','蕭蕭凌雪霜，濃翠異三湘。',48,'全唐诗/poet.tang.28000.json','["蕭蕭凌雪霜，濃翠異三湘。", "疎影月移壁，寒聲風滿堂。", "捲簾秋更早，高枕夜偏長。", "忽憶秦溪路，萬竿今正涼。"]'),
('8e3f0315-9583-4fa9-8370-6c24ef2ca34d','春日題韋曲野老村舍二首 一','許渾','唐','唐诗','tang','','[]','遶屋遍桑麻，村南第一家。',48,'全唐诗/poet.tang.28000.json','["遶屋遍桑麻，村南第一家。", "林繁樹勢直，溪轉水紋斜。", "竹院晝看筍，藥欄春賣花。", "故園歸未得，到此是天涯。"]'),
('e4ffe075-391f-4beb-9bde-be14f35decbf','春日題韋曲野老村舍二首 二','許渾','唐','唐诗','tang','','[]','北嶺枕南塘，數家村落長。',48,'全唐诗/poet.tang.28000.json','["北嶺枕南塘，數家村落長。", "鶯啼幼婦嬾，蠶出小姑忙。", "煙草近溝濕，風花臨路香。", "自憐非楚客，春望亦心傷。"]'),
('82bfa4c6-3b4b-46ba-b11e-08e18a922b60','崇聖寺別楊至之','許渾','唐','唐诗','tang','','[]','蕭寺暫相逢，離憂滿病容。',48,'全唐诗/poet.tang.28000.json','["蕭寺暫相逢，離憂滿病容。", "寒齋秋少燕，陰壁夜多蛩。", "樹暗水千里，山深雲萬重。", "懷君在書信，莫過鴈回峯。"]'),
('4d70f6a6-abed-4cfc-9785-731b1b2ee812','途經李翰林墓','許渾','唐','唐诗','tang','','[]','氣逸何人識，才高舉世疑。',48,'全唐诗/poet.tang.28000.json','["氣逸何人識，才高舉世疑。", "禰生狂善賦，陶令醉能詩。", "碧水鱸魚思，青山鵩鳥悲。", "至今孤塚在，荆棘楚江湄。"]'),
('c83eb0b6-daca-4a7c-8904-e5d2d15a5479','嚴陵釣臺貽行侶','許渾','唐','唐诗','tang','','[]','故人天下定，垂釣碧巖幽。',48,'全唐诗/poet.tang.28000.json','["故人天下定，垂釣碧巖幽。", "舊跡隨臺古，高名寄水流。", "鳥喧羣木晚，蟬急衆山秋。", "更待新安月，憑君暫駐舟。"]'),
('04b29b89-63cc-48fa-8c07-7eb3995d658f','南樓春望','許渾','唐','唐诗','tang','','[]','南樓春一望，雲水共昏昏。',48,'全唐诗/poet.tang.28000.json','["南樓春一望，雲水共昏昏。", "野店歸山路，危橋帶郭村。", "晴煙和草色，夜雨長溪痕。", "下岸誰家住，殘陽半掩門。"]'),
('a1b6e3cd-f5d1-4d41-8808-44960fd345ad','送無夢道人先歸甘露寺','許渾','唐','唐诗','tang','','[]','飄飄隨晚浪，杯影入鷗羣。',48,'全唐诗/poet.tang.28000.json','["飄飄隨晚浪，杯影入鷗羣。", "岸凍千船雪，巖陰一寺雲。", "夜燈江北見，寒磬水西聞。", "鶴嶺煙霞在，歸期不羨君。"]'),
('a3722838-827a-4595-9ced-c7f0c4afcb92','閑居孟夏即事','許渾','唐','唐诗','tang','','[]','綠樹蔭青苔，柴門臨水開。',48,'全唐诗/poet.tang.28000.json','["綠樹蔭青苔，柴門臨水開。", "簟涼初熟麥，枕膩乍經梅。", "魚躍海風起，鼉鳴江雨來。", "佳人竟何處，日夕上樓臺。"]'),
('35a7b4a1-7173-40de-b5d2-c1cea2893e4c','題灞西駱隱士','許渾','唐','唐诗','tang','','[]','磻溪連灞水，商嶺接秦山。',48,'全唐诗/poet.tang.28000.json','["磻溪連灞水，商嶺接秦山。", "青漢不回駕，白雲長掩關。", "雀喧知鶴靜，鳧戲識鷗閑。", "却笑南昌尉，悠悠城市間。"]'),
('bafc5477-4e0d-4f6b-b111-db86d0b48d39','溪亭二首 一','許渾','唐','唐诗','tang','','[]','溪亭四面山，橫柳半溪灣。',48,'全唐诗/poet.tang.28000.json','["溪亭四面山，橫柳半溪灣。", "蟬響螳螂急，魚深翡翠閑。", "水寒留客醉，月上與僧還。", "猶戀蕭蕭竹，西齋未掩關。"]'),
('cfbcc91f-a55a-4549-8899-eb5ebca01489','溪亭二首 二','許渾','唐','唐诗','tang','','[]','暖枕眠溪柳，僧齋昨夜期。',48,'全唐诗/poet.tang.28000.json','["暖枕眠溪柳，僧齋昨夜期。", "茶香秋夢後，松韻晚吟時。", "共戲魚翻藻，爭棲鳥墜枝。", "重陽應一醉，栽菊助東籬。"]'),
('292c14cd-151f-4321-a94c-46fc86693eb3','秋日赴闕題潼關驛樓','許渾','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7"]','紅葉晚蕭蕭，長亭酒一瓢。',48,'全唐诗/poet.tang.28000.json','["紅葉晚蕭蕭，長亭酒一瓢。", "殘雲歸太華，疎雨過中條。", "樹色隨山迥，河聲入海遙。", "帝鄉明日到，猶自夢漁樵。"]'),
('c02e478c-589f-4ce4-b682-6cec1573dc1b','吳門送客早發','許渾','唐','唐诗','tang','','[]','吳歌咽深思，楚客怨歸程。',48,'全唐诗/poet.tang.28000.json','["吳歌咽深思，楚客怨歸程。", "寺曉樓臺迥，江秋管吹清。", "早潮低水檻，殘月下山城。", "惆悵回舟日，湘南春草生。"]'),
('c57515fd-9841-4bf1-b949-bf171705c4ca','送太昱禪師','許渾','唐','唐诗','tang','','[]','禪牀深竹裏，心與徑山期。',48,'全唐诗/poet.tang.28000.json','["禪牀深竹裏，心與徑山期。", "結社多高客，登壇盡小師。", "早秋歸寺遠，新雨上灘遲。", "別後江雲碧，南齋一首詩。"]'),
('224486d6-50d2-4c4e-968c-867aa36b2dd2','旅懷','許渾','唐','唐诗','tang','','[]','征車何軋軋，南北極天涯。',48,'全唐诗/poet.tang.28000.json','["征車何軋軋，南北極天涯。", "孤枕易爲客，遠書難到家。", "鄉連雲外樹，城閉月中花。", "猶有扁舟思，前年別若耶。"]'),
('8002dd4f-2224-4acc-8d4a-f1ff73ad75d2','南亭與首公讌集','許渾','唐','唐诗','tang','','[]','秋來水上亭，幾處似巖扃。',48,'全唐诗/poet.tang.28000.json','["秋來水上亭，幾處似巖扃。", "戲鳥翻江葉，游龜帶綠萍。", "管弦心戚戚，羅綺鬢星星。", "行樂非吾事，西齋尚有螢。"]'),
('1d0d24ca-2be7-4404-9256-365c9895c11a','早發壽安次永壽渡','許渾','唐','唐诗','tang','','[]','東西車馬塵，鞏洛與咸秦。',48,'全唐诗/poet.tang.28000.json','["東西車馬塵，鞏洛與咸秦。", "山月夜行客，水煙朝渡人。", "樹涼風皓皓，灘淺石磷磷。", "會待功名就，扁舟寄此身。"]'),
('97392a14-7813-463e-b6e6-2e08a9935fd4','泊松江渡','許渾','唐','唐诗','tang','','[]','漠漠故宮地，月涼風露幽。',48,'全唐诗/poet.tang.28000.json','["漠漠故宮地，月涼風露幽。", "雞鳴荒戍曉，鴈過古城秋。", "楊柳北歸路，蒹葭南渡舟。", "去鄉今已遠，更上望京樓。"]'),
('4ec5cc11-be31-4e2a-ac72-b39b64d9fc4e','送魚思別處士歸有懷','許渾','唐','唐诗','tang','','[]','宴罷衆賓散，長歌攜一巵。',48,'全唐诗/poet.tang.28000.json','["宴罷衆賓散，長歌攜一巵。", "溪亭相送遠，山郭獨歸遲。", "風檻夕雲散，月軒寒露滋。", "病來雙鬢白，不是舊離時。"]'),
('1780ff68-d310-4276-a966-e2bd6c80817a','重經姑蘇懷古二首 一','許渾','唐','唐诗','tang','','[]','越兵驅綺羅，越女唱吳歌。',48,'全唐诗/poet.tang.28000.json','["越兵驅綺羅，越女唱吳歌。", "宮盡燕聲少，臺荒麋跡多。", "茱萸垂曉露，菡萏落秋波。", "無復君王醉，滿城顰翠蛾。"]'),
('3146b0b3-5192-4ec2-b0c1-591da35cb6fc','重經姑蘇懷古二首 二','許渾','唐','唐诗','tang','','[]','香逕遶吳宮，千帆落照中。',48,'全唐诗/poet.tang.28000.json','["香逕遶吳宮，千帆落照中。", "鸛鳴山欲雨，魚躍水多風。", "城帶晚莎綠，池連秋蓼紅。", "當年國門外，誰識伍員忠。"]'),
('917c409c-9e63-45af-9052-9a5190c2a5c9','將赴京師留題孫處士山居二首 一','許渾','唐','唐诗','tang','','[]','草堂近西郭，遙對敬亭開。',48,'全唐诗/poet.tang.28000.json','["草堂近西郭，遙對敬亭開。", "枕膩海雲起，簟涼山雨來。", "高歌懷地肺，遠賦憶天台。", "應學相如志，終須駟馬回。"]'),
('22c1c18c-d0c1-4e96-ba26-37ddfc3828b1','將赴京師留題孫處士山居二首 二','許渾','唐','唐诗','tang','','[]','西巖有高興，路僻幾人知。',48,'全唐诗/poet.tang.28000.json','["西巖有高興，路僻幾人知。", "松蔭花開晚，山寒酒熟遲。", "游從隨野鶴，休息遇靈龜。", "長見鄰翁說，容華似舊時。"]'),
('db201840-8273-4d1d-a365-f5ab532cb5e2','下第寓居崇聖寺感事','許渾','唐','唐诗','tang','','[]','懷土泣京華，舊山歸路賒。',48,'全唐诗/poet.tang.28000.json','["懷土泣京華，舊山歸路賒。", "靜依禪客院，幽學野人家。", "林晚鳥爭樹，園春蝶護花。", "東門有閑地，誰種邵平瓜。"]'),
('5ad092f9-fb3d-4df3-a94d-319a018591b4','曉發天井關寄李師晦','許渾','唐','唐诗','tang','','[]','山在水滔滔，流年欲二毛。',48,'全唐诗/poet.tang.28000.json','["山在水滔滔，流年欲二毛。", "湘潭歸夢遠，燕趙客程勞。", "露曉紅蘭重，雲晴碧樹高。", "逢秋正多感，萬里別同袍。"]'),
('8f1fcea5-5eae-440c-9ac0-a19b8ef54797','喜遠書','許渾','唐','唐诗','tang','','[]','端居換時節，離恨隔龍瀧。',48,'全唐诗/poet.tang.28000.json','["端居換時節，離恨隔龍瀧。", "苔色上春閣，柳陰移晚窗。", "寄懷因桂水，流淚極楓江。", "此日南來使，金盤魚一雙。"]'),
('71e82353-6624-4fc3-9266-929715c33939','懷江南同志','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','南國別經年，雲晴波接天。',48,'全唐诗/poet.tang.28000.json','["南國別經年，雲晴波接天。", "蒲深鸂鶒戲，花暖鷓鴣眠。", "竹暗湘妃廟，楓陰楚客船。", "唯應洞庭月，萬里共嬋娟。"]'),
('bba418a8-d57c-4614-9293-d5022c332af7','洛中秋日','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','故國無歸處，官閑憶遠遊。',48,'全唐诗/poet.tang.28000.json','["故國無歸處，官閑憶遠遊。", "吳僧秣陵寺，楚客洞庭舟。", "久病先知雨，長貧早覺秋。", "壯心能幾許，伊水更東流。"]'),
('0501d2f2-fccc-45d1-8320-5b4c8a3ccc70','將赴京師蒜山津送客還荆渚','許渾','唐','唐诗','tang','','[]','尊前萬里愁，楚塞與皇州。',48,'全唐诗/poet.tang.28000.json','["尊前萬里愁，楚塞與皇州。", "雲識瀟湘雨，風知鄠杜秋。", "潮平猶倚棹，月上更登樓。", "他日滄浪水，漁歌對白頭。"]'),
('e49e4df5-f884-4ba2-bb01-9dd8e6d21762','潼關蘭若','許渾','唐','唐诗','tang','','[]','來往幾經過，前軒枕大河。',48,'全唐诗/poet.tang.28000.json','["來往幾經過，前軒枕大河。", "遠帆春水闊，高寺夕陽多。", "蝶影下紅藥，鳥聲喧綠蘿。", "故山歸未得，徒詠採芝歌。"]'),
('5ecfdff1-9784-4be0-8201-02eee3d7fe11','翫殘雪寄江南尹劉大夫','許渾','唐','唐诗','tang','','[]','豔陽無處避，皎潔不成容。',48,'全唐诗/poet.tang.28000.json','["豔陽無處避，皎潔不成容。", "素質添瑤水，清光散玉峯。", "眠鷗猶戀草，棲鶴未離松。", "聞在金鑾望，羣仙對九重。"]'),
('5acbc4e8-85af-412f-9e6e-e9dfa2e9ad07','陪越中使院諸公鏡波館餞明台裴鄭二使君','許渾','唐','唐诗','tang','','[]','傾幕來華館，淹留二使君。',48,'全唐诗/poet.tang.28000.json','["傾幕來華館，淹留二使君。", "舞移清夜月，歌斷碧空雲。", "海郡樓臺接，江船劒戟分。", "明時自騫翥，無復歎離羣。"]'),
('ee8771a9-82fa-4d35-85c0-970ab7ebad8d','春泊弋陽','許渾','唐','唐诗','tang','','[]','江行春欲半，孤枕弋陽堤。',48,'全唐诗/poet.tang.28000.json','["江行春欲半，孤枕弋陽堤。", "雲暗猶飄雪，潮寒未應溪。", "飲猿聞棹散，飛鳥背船低。", "此路成幽絕，家山鞏洛西。"]'),
('209079c5-08ba-4a9f-9c64-f055b5b4242f','晨別翛然上人','許渾','唐','唐诗','tang','','[]','吳僧誦經罷，敗衲倚蒲團。',48,'全唐诗/poet.tang.28000.json','["吳僧誦經罷，敗衲倚蒲團。", "鐘韻花猶歛，樓陰月向殘。", "晴山開殿響，秋水捲簾寒。", "獨恨孤舟去，千灘復萬灘。"]'),
('5e0c24ab-2d9e-4ad8-aaf7-007c63f6f436','送客江行','許渾','唐','唐诗','tang','','[]','蕭蕭蘆荻花，郢客獨辭家。',48,'全唐诗/poet.tang.28000.json','["蕭蕭蘆荻花，郢客獨辭家。", "遠棹依山響，危檣轉浦斜。", "水寒澄淺石，潮落漲虛沙。", "莫與征徒望，鄉園去漸賒。"]'),
('9ccee73e-3244-44fe-9d43-20c505ddded4','將歸塗口宿鬱林寺道玄上人院二首 一','許渾','唐','唐诗','tang','','[]','西巖一磬長，僧起樹蒼蒼。',48,'全唐诗/poet.tang.28000.json','["西巖一磬長，僧起樹蒼蒼。", "開殿灑寒水，誦經焚晚香。", "竹風雲漸散，杉露月猶光。", "無復重來此，歸舟凌夕陽。"]'),
('30ad002b-2a7a-4af3-bb8d-827344c43a03','將歸塗口宿鬱林寺道玄上人院二首 二','許渾','唐','唐诗','tang','','[]','春尋採藥翁，歸路宿禪宮。',48,'全唐诗/poet.tang.28000.json','["春尋採藥翁，歸路宿禪宮。", "雲起客眠處，月殘僧定中。", "藤花深洞水，槲葉滿山風。", "清境不能住，朝朝慙遠公。"]'),
('eac5f393-1297-4d29-98be-df08f1e75332','題宣州元處士幽居','許渾','唐','唐诗','tang','','[]','潺湲遶門水，未省濯纓塵。',48,'全唐诗/poet.tang.28000.json','["潺湲遶門水，未省濯纓塵。", "鳥散千巖曙，蜂來一逕春。", "杉松還待客，芝朮不求人。", "寧學磻溪叟，逢時罷隱淪。"]'),
('4f3382c9-9dae-4be5-a239-b7f321a60527','送李秀才','許渾','唐','唐诗','tang','','[]','南樓送郢客，西郭見荆門。',48,'全唐诗/poet.tang.28000.json','["南樓送郢客，西郭見荆門。", "鳧鵠下寒渚，牛羊歸遠村。", "蘭舟倚行掉，桂酒掩餘尊。", "重此一留宿，前村煙水昏。"]'),
('81beea63-3272-426d-b9f8-7dcde441d20d','題倪處士舊居','許渾','唐','唐诗','tang','','[]','儒翁九十餘，舊向此山居。',48,'全唐诗/poet.tang.28000.json','["儒翁九十餘，舊向此山居。", "生寄一壺酒，死留千卷書。", "檻摧新竹少，池淺故蓮疎。", "但有子孫在，帶經還荷鋤。"]'),
('2059680c-58b9-4996-b797-4a3aaadf63d8','贈梁將軍','許渾','唐','唐诗','tang','','[]','曾經黑山虜，一劒出重圍。',48,'全唐诗/poet.tang.28000.json','["曾經黑山虜，一劒出重圍。", "年長窮書意，時清隱釣磯。", "高齋雲外住，瘦馬月中歸。", "唯說鄉心苦，春風鴈北飛。"]'),
('02be451e-a9e6-48de-9dc9-3de4b28dc469','春望思舊游','許渾','唐','唐诗','tang','','[]','適意極春日，南臺披薜蘿。',48,'全唐诗/poet.tang.28000.json','["適意極春日，南臺披薜蘿。", "花光晴漾漾，山色晝峨峨。", "湘水美人遠，信陵豪客多。", "唯憑一瓢酒，彈瑟縱高歌。"]'),
('b60708b2-6c5f-4eee-8e29-3940efe65462','病中二首 一','許渾','唐','唐诗','tang','','[]','三年嬰酒渴，高臥似袁安。',48,'全唐诗/poet.tang.28000.json','["三年嬰酒渴，高臥似袁安。", "秋色鬢應改，夜涼心已寬。", "風衣藤簟滑，露井竹牀寒。", "臥憶郊扉月，恩深未挂冠。"]'),
('99b70822-e572-4068-bba5-895e14031fda','病中二首 二','許渾','唐','唐诗','tang','','[]','私歸人暫適，扶杖遶西林。',48,'全唐诗/poet.tang.28000.json','["私歸人暫適，扶杖遶西林。", "風急柳溪響，露寒莎徑深。", "一身仍白髮，萬慮只丹心。", "此意無言處，高窗託素琴。"]'),
('748e0791-96ce-4280-b298-c027d69c3bac','姑熟官舍寄汝洛友人','許渾','唐','唐诗','tang','','[]','[官]靜亦無能，平生少面朋。',50,'全唐诗/poet.tang.28000.json','["[官]靜亦無能，平生少面朋。", "務開唯印吏，公退只棊僧。", "藥鼎初寒火，書龕欲夜燈。", "安知北溟水，終日送摶鵬。"]'),
('e61831c5-d0be-4905-bb80-dd0e95eb8f76','恩德寺','許渾','唐','唐诗','tang','','[]','樓臺橫復重，猶有半巖空。',48,'全唐诗/poet.tang.28000.json','["樓臺橫復重，猶有半巖空。", "蘿洞淺深水，竹廊高下風。", "晴山疎雨後，秋樹斷雲中。", "未盡平生意，孤帆又向東。"]'),
('b2970098-8c3d-4acf-b136-960b759cd15a','天竺寺題葛洪井','許渾','唐','唐诗','tang','','[]','羽客鍊丹井，井留人已無。',48,'全唐诗/poet.tang.28000.json','["羽客鍊丹井，井留人已無。", "舊泉青石下，餘甃碧山隅。", "雲朗鏡開匣，月寒冰在壺。", "仍聞釀仙酒，此水過瓊酴。"]'),
('44098361-dbe7-4210-b972-a8fcd93447bc','朗上人院晨坐','許渾','唐','唐诗','tang','','[]','簟涼襟袖清，月沒尚殘星。',48,'全唐诗/poet.tang.28000.json','["簟涼襟袖清，月沒尚殘星。", "山果落秋院，水花開曉庭。", "疎藤風嫋嫋，圓桂露冥冥。", "正憶江南寺，巖齋聞誦經。"]'),
('3438c909-a367-4633-b0ab-a09a0c787f59','送客歸湘楚','許渾','唐','唐诗','tang','','[]','無辭一杯酒，昔日與君深。',48,'全唐诗/poet.tang.28000.json','["無辭一杯酒，昔日與君深。", "秋色換歸鬢，曙光生別心。", "桂花山廟冷，楓樹水樓陰。", "此路千餘里，應勞楚客吟。"]'),
('480317ec-d52e-477f-b710-46d742e023c6','過故友舊居','許渾','唐','唐诗','tang','','[]','往年公子宅，夜宴樂難忘。',48,'全唐诗/poet.tang.28000.json','["往年公子宅，夜宴樂難忘。", "高竹動疎翠，早蓮飄暗香。", "珠盤凝寶瑟，綺席遰華觴。", "今日皆何處，閉門春草長。"]'),
('4ecb56f4-59a7-42a1-b6ab-7e6f6144403c','送客歸峽中','許渾','唐','唐诗','tang','','[]','津亭多別離，楊柳半無枝。',48,'全唐诗/poet.tang.28000.json','["津亭多別離，楊柳半無枝。", "住接猿啼處，行逢鴈過時。", "江風颺帆急，山月下樓遲。", "還就西齋宿，煙波勞夢思。"]'),
('87e871cd-309f-432c-abac-35e91bce9d08','題冲沼上人院','許渾','唐','唐诗','tang','','[]','斸石種松子，數根侵杳冥。',48,'全唐诗/poet.tang.28000.json','["斸石種松子，數根侵杳冥。", "天寒猶講律，雨暗尚尋經。", "小殿燈千盞，深爐水一瓶。", "碧雲多別思，休到望溪亭。"]'),
('1b25f617-6076-42e9-a9dc-e986e5509bc6','和畢員外雪中見寄','許渾','唐','唐诗','tang','','[]','仙署淹清景，雪華松桂陰。',48,'全唐诗/poet.tang.28000.json','["仙署淹清景，雪華松桂陰。", "夜凌瑤席宴，春寄玉京吟。", "燭晃垂羅幙，香寒重繡衾。", "相思不相訪，煙月剡溪深。"]'),
('c05d0c7e-3480-47cb-9073-b4408e445f99','春醉','許渾','唐','唐诗','tang','','[]','酒醲花一樹，何暇卓文君。',48,'全唐诗/poet.tang.28000.json','["酒醲花一樹，何暇卓文君。", "客坐長先飲，公閑半已曛。", "水鄉春足雨，山郭夜多雲。", "何似參禪理，榮枯盡不聞。"]'),
('fc750ec6-3a85-4488-9cbd-758d481e5997','題岫上人院','許渾','唐','唐诗','tang','','[]','病客與僧閑，頻來不掩關。',48,'全唐诗/poet.tang.28000.json','["病客與僧閑，頻來不掩關。", "高窗雲外樹，疎磬雨中山。", "離索秋蟲響，登臨夕鳥還。", "心知落帆處，明日淛河灣。"]'),
('fe9dedd5-31d7-445e-94d9-2071c4bb1bc6','送客南歸有懷','許渾','唐','唐诗','tang','','[]','綠水暖青蘋，湘潭萬里春。',48,'全唐诗/poet.tang.28000.json','["綠水暖青蘋，湘潭萬里春。", "瓦尊迎海客，銅鼓賽江神。", "避雨松楓岸，看雲楊柳津。", "長安一杯酒，座上有歸人。"]'),
('cca6b982-e260-414d-9c5e-298a07298639','李生棄官入道因寄','許渾','唐','唐诗','tang','','[]','西巖一徑通，知學採芝翁。',48,'全唐诗/poet.tang.28000.json','["西巖一徑通，知學採芝翁。", "寒暑丹心外，光陰白髮中。", "水深魚避釣，雲迥鶴辭籠。", "坐想還家日，人非井邑空。"]'),
('67ad6ed1-104c-4bf7-9547-58005168a6fd','長興里夏日南鄰避暑','許渾','唐','唐诗','tang','','[]','侯門大道傍，蟬噪樹蒼蒼。',48,'全唐诗/poet.tang.28000.json','["侯門大道傍，蟬噪樹蒼蒼。", "開鏁洞門遠，下簾賓館涼。", "欄圍紅藥盛，架引綠蘿長。", "永日一欹枕，故山雲水鄉。"]'),
('3599333c-7e9d-4897-92d4-0bc31381791b','送韓校書','許渾','唐','唐诗','tang','','[]','恨與前歡隔，愁因此會同。',48,'全唐诗/poet.tang.28000.json','["恨與前歡隔，愁因此會同。", "跡高芸閣吏，名散雪樓翁。", "城閉三秋雨，帆飛一夜風。", "酒醒鱸鱠美，應在竟陵東。"]'),
('afd48c75-6501-4167-a8b2-149d47b05919','秋晚登城','許渾','唐','唐诗','tang','','[]','城高不可下，永日一登臨。',48,'全唐诗/poet.tang.28000.json','["城高不可下，永日一登臨。", "曲檻涼飆急，空樓返照深。", "葦花迷夕棹，梧葉散秋砧。", "謾作歸田賦，蹉跎歲欲陰。"]'),
('d1c05e8f-d3c3-47dd-ad5a-d531f29da487','江西鄭常侍赴鎮之日有寄因酬和','許渾','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','來暮亦何愁，金貂在鷁舟。',48,'全唐诗/poet.tang.28000.json','["來暮亦何愁，金貂在鷁舟。", "斾隨寒浪動，帆帶夕陽收。", "布令滕王閣，裁詩郢客樓。", "即應歸鳳沼，中外贊天休。"]'),
('7487d0b0-b96b-4af7-a297-933e1558f377','蒙河南劉大夫見示與吏部張公喜雪酬唱輒敢攀和','許渾','唐','唐诗','tang','','[]','風度龍山暗，雲凝象闕陰。',48,'全唐诗/poet.tang.28000.json','["風度龍山暗，雲凝象闕陰。", "瑞花瓊樹合，仙草玉苗深。", "欲醉梁王酒，先調楚客琴。", "即應攜手去，將此助商霖。"]'),
('e779d798-62ec-4ba8-aef8-22c14546179f','下第送宋秀才游岐下楊秀才還江東','許渾','唐','唐诗','tang','','[]','年來不自得，一望幾傷心。',48,'全唐诗/poet.tang.28000.json','["年來不自得，一望幾傷心。", "風轉蕙蘭色，月移松桂陰。", "馬隨邊草遠，帆落海雲深。", "明旦各分首，更聽梁甫吟。"]'),
('e6d4076b-7980-456f-b002-4120afa4c148','南亭偶題','許渾','唐','唐诗','tang','','[]','城下水縈回，潮衝野艇來。',48,'全唐诗/poet.tang.28000.json','["城下水縈回，潮衝野艇來。", "鳥驚山果落，龜泛綠萍開。", "白首書千卷，朱顏酒一杯。", "南軒自流涕，不是望燕臺。"]'),
('2b498332-b5f5-4640-acb5-29477af681bc','與裴三十秀才自越西歸望亭阻凍登虎丘山寺精舍','許渾','唐','唐诗','tang','','[]','春草越吳間，心期旦夕還。',48,'全唐诗/poet.tang.28000.json','["春草越吳間，心期旦夕還。", "酒鄉逢客病，詩境遇僧閑。", "倚棹冰生浦，登樓雪滿山。", "東風不可待，歸鬢坐斑斑。"]'),
('3ce2a6ae-98e8-46bd-b9c1-05f545f7ea1d','太和初靖恭里感事','許渾','唐','唐诗','tang','','[]','清湘弔屈原，垂淚擷蘋蘩。',48,'全唐诗/poet.tang.28000.json','["清湘弔屈原，垂淚擷蘋蘩。", "謗起乘軒鶴，機沈在檻猨。", "乾坤三事貴，華夏一夫冤。", "寧有唐虞世，心知不爲言。"]'),
('c82ff6ae-cdc3-4651-ba33-f93beb4286da','與侯春時同年南池夜話','許渾','唐','唐诗','tang','','[]','蘆葦暮修修，溪禽上釣舟。',48,'全唐诗/poet.tang.28000.json','["蘆葦暮修修，溪禽上釣舟。", "露涼花歛夕，風靜竹含秋。", "素志應難契，清言豈易求。", "相歡一瓢酒，明日醉西樓。"]'),
('291429aa-73ad-4373-9dfc-28b4a96ba982','廣陵送剡縣薛明府赴任','許渾','唐','唐诗','tang','','[]','車馬楚城壕，清歌送濁醪。',48,'全唐诗/poet.tang.28000.json','["車馬楚城壕，清歌送濁醪。", "露花羞別淚，煙草讓歸袍。", "鳥浴春塘暖，猨吟暮嶺高。", "尋仙在仙骨，不用廢牛刀。"]'),
('fc378fa9-aae1-40b4-815c-a56650da4fa5','遊果晝二僧院','許渾','唐','唐诗','tang','','[]','何必老林泉，冥心便是禪。',48,'全唐诗/poet.tang.28000.json','["何必老林泉，冥心便是禪。", "講時開院去，齋後下簾眠。", "鏡朗燈分焰，香銷印絕煙。", "真乘不可到，雲盡月明天。"]'),
('576b6d5c-a5f5-4522-a39b-aea6c86c5523','題官舍','許渾','唐','唐诗','tang','','[]','燕鴈水鄉飛，京華信自稀。',48,'全唐诗/poet.tang.28000.json','["燕鴈水鄉飛，京華信自稀。", "簟瓢貧守道，書劒病忘機。", "疊鼓吏初散，繁鐘鳥獨歸。", "高梧與疎柳，風雨似郊扉。"]'),
('670ad077-f5fa-4393-b323-d605218b8a4a','酬報先上人登樓見寄','許渾','唐','唐诗','tang','','[]','丹葉下西樓，知君萬里愁。',48,'全唐诗/poet.tang.28000.json','["丹葉下西樓，知君萬里愁。", "鐘非黔峽寺，帆是敬亭舟。", "山色和雲暮，湖光共月秋。", "天台多道侶，何惜更南遊。"]'),
('c0c91f10-cd6a-4092-a67e-ae8173e48057','曉過鬱林寺戲呈李明府','許渾','唐','唐诗','tang','','[]','身閑白日長，何處不尋芳？',48,'全唐诗/poet.tang.28000.json','["身閑白日長，何處不尋芳？", "山崦登樓寺，谿灣泊晚檣。", "洞花蜂聚蜜，巖栢麝留香。", "若指求仙路，劉郎學阮郎。"]'),
('67c7cf51-4004-4fb6-b94e-848fb86cac95','泛舟尋鬱林寺道玄上人遇雨而返因寄','許渾','唐','唐诗','tang','','[]','禪扉倚石梯，雲濕雨淒淒。',48,'全唐诗/poet.tang.28000.json','["禪扉倚石梯，雲濕雨淒淒。", "草色分松逕，泉聲咽稻畦。", "棹移灘鳥沒，鐘斷嶺猨啼。", "入夜花如雪，回舟憶剡溪。"]'),
('083cdd5f-b1ac-4aee-82cb-87d076e86dda','鬱林寺','許渾','唐','唐诗','tang','','[]','臺殿冠嵯峨，春來日日過。',48,'全唐诗/poet.tang.28000.json','["臺殿冠嵯峨，春來日日過。", "水分諸院少，雲近上方多。", "衆籟凝絲竹，繁英耀綺羅。", "酒酣詩自逸，乘月棹寒波。"]'),
('3921d439-6153-48a0-8c8c-0993f2cb6b94','題崇聖寺','許渾','唐','唐诗','tang','','[]','西林本行殿，池榭日坡陁。',48,'全唐诗/poet.tang.28000.json','["西林本行殿，池榭日坡陁。", "雨過水初漲，雲開山漸多。", "曉街垂御柳，秋院閉宮莎。", "借問龍歸處，鼎湖空碧波。"]'),
('6fd46c5b-6283-408e-b838-07dc82cbd15c','贈高處士','許渾','唐','唐诗','tang','','[]','宅前雲水滿，高興一書生。',48,'全唐诗/poet.tang.28000.json','["宅前雲水滿，高興一書生。", "垂釣有深意，望山多遠情。", "夜棊留客宿，春酒勸僧傾。", "未作干時計，何人問姓名。"]'),
('370ceeec-e080-44af-ab76-9e0215cee632','送僧歸金山寺','許渾','唐','唐诗','tang','','[]','老歸江上寺，不忘舊師恩。',48,'全唐诗/poet.tang.28000.json','["老歸江上寺，不忘舊師恩。", "駐錫逢山色，停杯見浪痕。", "秋濤吞楚驛，曉月上荆門。", "爲訪題詩處，莓苔幾字存。"]'),
('629f0831-43f0-4a07-8875-8abbd83f47b5','金谷桃花','許渾','唐','唐诗','tang','','[]','花在舞樓空，年年依舊紅。',48,'全唐诗/poet.tang.28000.json','["花在舞樓空，年年依舊紅。", "淚光停曉露，愁態倚春風。", "開處妾先死，落時君亦終。", "東流兩三片，應在夜泉中。"]'),
('5679821e-4d95-4e64-bcea-d9e0531b3cda','憶長洲','許渾','唐','唐诗','tang','','[]','香徑小船通，菱歌遶故宮。',48,'全唐诗/poet.tang.28000.json','["香徑小船通，菱歌遶故宮。", "魚沈秋水靜，鳥宿暮山空。", "荷葉橋邊雨，蘆花海上風。", "歸心無處託，高枕畫屏中。"]'),
('f1d289d5-7b9b-44a9-afa1-5f839f10ace3','寄殷堯藩','許渾','唐','唐诗','tang','','[]','直道知難用，經年向水濱。',48,'全唐诗/poet.tang.28000.json','["直道知難用，經年向水濱。", "宅從栽竹貴，家爲買書貧。", "就學多新客，登朝盡故人。", "蓬萊自有路，莫羨武陵春。"]'),
('e5e87a03-29a4-4e7f-a36b-28ae803d65a3','題鄒處士隱居','許渾','唐','唐诗','tang','','[]','桑柘滿江村，西齋接海門。',48,'全唐诗/poet.tang.28000.json','["桑柘滿江村，西齋接海門。", "浪衝高岸響，潮入小池渾。", "嵒樹陰棊局，山花落酒樽。", "相逢亦留宿，還似識王孫。"]'),
('f9649b00-f87c-43ca-b84a-dc17089105e1','送僧歸敬亭山寺','許渾','唐','唐诗','tang','','[]','十年劒中路，傳盡本師經。',48,'全唐诗/poet.tang.28000.json','["十年劒中路，傳盡本師經。", "曉月下黔峽，秋風歸敬亭。", "開門新樹綠，登閣舊山青。", "遙想論禪處，松陰水一瓶。"]'),
('8d80c52e-0108-4215-86e5-4ee71ecf9aac','新卜原上居寄袁校書','許渾','唐','唐诗','tang','','[]','貧居樂游此，江海思迢迢。',48,'全唐诗/poet.tang.28000.json','["貧居樂游此，江海思迢迢。", "雪夜書千卷，花時酒一瓢。", "獨愁秦樹老，孤夢楚山遙。", "有路應相念，風塵滿黑貂。"]'),
('437f7068-127c-47db-b4b4-80bf4b78a30a','天街曉望','許渾','唐','唐诗','tang','','[]','明星低未央，蓮闕逈蒼蒼。',48,'全唐诗/poet.tang.28000.json','["明星低未央，蓮闕逈蒼蒼。", "疊鼓催殘月，疎鐘迎早霜。", "關防浮瑞氣，宮館耀神光。", "再拜爲君壽，南山高且長。"]'),
('22b5f7b8-530b-426b-b7ae-03bee02523c2','江上喜洛中親友繼至','許渾','唐','唐诗','tang','','[]','戰馬昔紛紛，風驚嵩少塵。',48,'全唐诗/poet.tang.28000.json','["戰馬昔紛紛，風驚嵩少塵。", "全家南渡遠，舊友北來頻。", "罷酒松筠晚，賦詩楊柳春。", "誰言今夜月，同是洛陽人。"]'),
('dcfa2c6d-bc15-49c1-8533-6ed189e7946e','下第歸朱方寄劉三復','許渾','唐','唐诗','tang','','[]','素衣京洛塵，歸棹過南津。',48,'全唐诗/poet.tang.28000.json','["素衣京洛塵，歸棹過南津。", "故里跡猶在，舊交心更親。", "月高蕭寺夜，風暖庾樓春。", "詩酒應無暇，朝朝問旅人。"]'),
('35b41d75-03c1-4ed1-a684-80437eb641cf','送人歸吳興','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','綠水棹雲月，洞庭歸路長。',48,'全唐诗/poet.tang.28000.json','["綠水棹雲月，洞庭歸路長。", "春橋懸酒幔，夜柵集茶檣。", "箬葉沈溪暖，蘋花遶郭香。", "應逢柳太守，爲說過瀟湘。"]'),
('73e62369-50fa-4a3e-b041-ac1e66892b83','月夜期友人不至','許渾','唐','唐诗','tang','','[]','坐待故人宿，月華清興秋。',48,'全唐诗/poet.tang.28000.json','["坐待故人宿，月華清興秋。", "管弦誰處醉，池館此時愁。", "風過渚荷動，露含山桂幽。", "孤吟不可曙，昨夜共登樓。"]'),
('cb67157d-5696-4952-b121-e34f7731fb27','白馬寺不出院僧','許渾','唐','唐诗','tang','','[]','禪空心已寂，世路任多岐。',48,'全唐诗/poet.tang.28000.json','["禪空心已寂，世路任多岐。", "到院客長見，閉關人不知。", "寺喧聽講絕，廚遠送齋遲。", "牆外洛陽道，東西無盡時。"]'),
('50a329cd-54ac-44a6-886f-3de53073a127','寄袁校書','許渾','唐','唐诗','tang','','[]','擾擾換時節，舊山琪樹陰。',48,'全唐诗/poet.tang.28000.json','["擾擾換時節，舊山琪樹陰。", "猶乖清漢志，空負白雲心。", "廣陌埃塵遠，重門管吹深。", "勞歌極西望，芸省有知音。"]'),
('c74cfdd9-73ed-4d4c-bb74-4c4232447ee2','贈柳璟馮陶二校書','許渾','唐','唐诗','tang','','[]','霄漢兩飛鳴，喧喧動禁城。',48,'全唐诗/poet.tang.28000.json','["霄漢兩飛鳴，喧喧動禁城。", "桂堂同日盛，芸閣間年榮。", "香掩蕙蘭氣，韻高鸞鶴聲。", "應憐茂陵客，未有子虛名。"]'),
('b47a8a2a-336a-46c8-9274-89c4ea7f625c','王秀才自越見尋不遇題詩而迴因以酬寄','許渾','唐','唐诗','tang','','[]','南齋知數宿，半爲木蘭開。',48,'全唐诗/poet.tang.28000.json','["南齋知數宿，半爲木蘭開。", "晴閣留詩遍，春帆載酒回。", "煙深楊子宅，雲斷越王臺。", "自有孤舟興，何妨更一來。"]'),
('c1769695-570c-42b2-b2b4-d390c920112e','秋霽潼關驛亭','許渾','唐','唐诗','tang','','[]','霽色明高巘，關河獨望遙。',48,'全唐诗/poet.tang.28000.json','["霽色明高巘，關河獨望遙。", "殘雲歸太華，疎雨過中條。", "鳥散綠蘿靜，蟬鳴紅樹凋。", "何言此時節，去去任蓬飄。"]'),
('f5540c14-8205-4149-b323-d169a0706fb1','送客歸蘭谿','許渾','唐','唐诗','tang','','[]','花下送歸客，路長應過秋。',48,'全唐诗/poet.tang.28000.json','["花下送歸客，路長應過秋。", "暮隨江鳥宿，寒共嶺猨愁。", "衆水喧嚴瀨，羣峰抱沈樓。", "因君幾南望，曾向此中遊。"]'),
('a3b00404-8b22-433a-a292-803a77e1015d','貽終南山隱者','許渾','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','中巖多少隱，提榼抱琴遊。',48,'全唐诗/poet.tang.28000.json','["中巖多少隱，提榼抱琴遊。", "潭冷薜蘿晚，山香松桂秋。", "瓢閑高樹挂，杯急曲池流。", "獨有迷津客，東西南北愁。"]'),
('fa7d9f7f-642b-495e-947e-24b0ff36a165','送李文明下第鄜州覲兄','許渾','唐','唐诗','tang','','[]','征夫天一涯，醉贈別吾詩。',48,'全唐诗/poet.tang.28000.json','["征夫天一涯，醉贈別吾詩。", "鴈迥參差遠，龍多次第遲。", "寧歌還夜苦，宋賦更秋悲。", "的的遙相待，清風白露時。"]'),
('accc2622-4cfe-4709-a70d-cda0f9c13e73','送段覺歸東陽兼寄竇使君','許渾','唐','唐诗','tang','','[]','山水引歸路，陸郎從此諳。',48,'全唐诗/poet.tang.28000.json','["山水引歸路，陸郎從此諳。", "秋茶垂露細，寒菊帶霜甘。", "臺倚烏龍嶺，樓侵白鴈潭。", "沈公如借問，心在浙河南。"]'),
('981b0ac2-a0b4-40a2-b506-9cbca656cd4a','韶州送竇司直北歸','許渾','唐','唐诗','tang','','[]','江曲山如畫，貪程亦駐舟。',48,'全唐诗/poet.tang.28000.json','["江曲山如畫，貪程亦駐舟。", "果隨巖狖落，槎帶水禽流。", "客散他鄉夜，人歸故國秋。", "樽前挂帆去，風雨下西樓。"]'),
('acd0964e-4217-4615-b3f9-1aff4c25bcd3','傷馮秀才','許渾','唐','唐诗','tang','','[]','旅葬不可問，茫茫西隴頭。',48,'全唐诗/poet.tang.28000.json','["旅葬不可問，茫茫西隴頭。", "水雲青草濕，山月白楊愁。", "琴信有時罷，劒傷無處留。", "淮南舊煙月，孤棹更逢秋。"]'),
('0ee9135f-a5fa-4900-86fe-c8a8f23bff83','送鄭寂上人南行','許渾','唐','唐诗','tang','','[]','儒家有釋子，年少學支公。',48,'全唐诗/poet.tang.28000.json','["儒家有釋子，年少學支公。", "心出是非外，跡辭榮辱中。", "錫寒秦嶺月，杯急楚江風。", "離怨故園思，小秋梨葉紅。"]'),
('f78c04bf-1973-48aa-a05b-7ef368e12c51','贈王處士','許渾','唐','唐诗','tang','','[]','歸臥養天真，鹿裘烏角巾。',48,'全唐诗/poet.tang.28000.json','["歸臥養天真，鹿裘烏角巾。", "茂陵閑久病，彭澤醉長貧。", "冠蓋西園夜，笙歌北里春。", "誰憐清渭曲，又老釣魚人。"]'),
('c7e07a0b-9797-4ad7-9696-0aaf14c35046','送友人歸荆楚','許渾','唐','唐诗','tang','','[]','調瑟勸離酒，苦諳荆楚門。',48,'全唐诗/poet.tang.28000.json','["調瑟勸離酒，苦諳荆楚門。", "竹斑悲帝女，草綠怨王孫。", "潮落九疑迥，雨連三峽昏。", "同來不同去，迢遰更傷魂。"]'),
('b671e637-ed10-4b19-8796-d2af74da6ae0','重傷楊攀處士二首 一','許渾','唐','唐诗','tang','','[]','綠雲多學術，黃髪竟無成。',48,'全唐诗/poet.tang.28000.json','["綠雲多學術，黃髪竟無成。", "酒縱山中性，詩留海上名。", "讀書新樹老，垂釣舊磯平。", "今日悲前事，西風聞哭聲。"]'),
('4c6d27cd-3758-43fb-a6f9-99e9a301e1a4','重傷楊攀處士二首 二','許渾','唐','唐诗','tang','','[]','從官任直道，幾處脫長裾。',48,'全唐诗/poet.tang.28000.json','["從官任直道，幾處脫長裾。", "歿後兒猶小，葬來人漸疎。", "新隣占池館，長史覓圖書。", "身賤難相報，平生恨有餘。"]'),
('f1e81aed-9e20-498e-be9f-ea7722680f44','送友人罷舉歸東海','許渾','唐','唐诗','tang','','[]','滄波天塹外，何島是新羅。',48,'全唐诗/poet.tang.28000.json','["滄波天塹外，何島是新羅。", "舶主辭番遠，碁僧入漢多。", "海風吹白鶴，沙日曬紅螺。", "此去知投筆，須求利劒磨。"]'),
('9ce48e57-0b3f-4217-a7cb-0994036bab6e','西園','許渾','唐','唐诗','tang','','[]','西園春欲盡，芳草徑難分。',48,'全唐诗/poet.tang.28000.json','["西園春欲盡，芳草徑難分。", "靜語唯幽鳥，閑眠獨使君。", "密林生雨氣，古石帶苔文。", "雖去清朝遠，朝朝見白雲。"]'),
('2cdc4b5a-abdc-4551-9b3d-b05727f9a807','苦雨','許渾','唐','唐诗','tang','','[]','江昏山半晴，南阻絕人行。',48,'全唐诗/poet.tang.28000.json','["江昏山半晴，南阻絕人行。", "葭菼連雲色，杉松共雨聲。", "早秋仍燕舞，深夜更鼉鳴。", "爲報迷津客，訛言未可輕。"]'),
('59b6bf32-ea9b-421e-bf4a-230fda0c878e','遊茅山','許渾','唐','唐诗','tang','','[]','步步入山門，仙家鳥徑分。',48,'全唐诗/poet.tang.28000.json','["步步入山門，仙家鳥徑分。", "漁樵不到處，麋鹿自成羣。", "石面迸出水，松頭穿破雲。", "道人星月下，相次禮茅君。"]'),
('6b18371c-f32a-4e6d-b708-f9e37cd9d63d','洛陽道中','許渾','唐','唐诗','tang','','[]','洛陽多舊迹，一日幾堪愁。',36,'全唐诗/poet.tang.28000.json','["洛陽多舊迹，一日幾堪愁。", "風起林花晚，月明陵樹秋。", "興亡不可問，自古水東流。"]'),
('da3132c7-2f84-4d31-962c-97a5560e2618','江上燕別','許渾','唐','唐诗','tang','','[]','雲物如故鄉，山川異岐路。',48,'全唐诗/poet.tang.28000.json','["雲物如故鄉，山川異岐路。", "年來未歸客，馬上春欲暮。", "一樽花下酒，殘日水西樹。", "不待管弦終，搖鞭背花去。"]'),
('d170bf96-3a39-4c70-be03-7e0a1560f2b9','卜居招書侶','許渾','唐','唐诗','tang','','[]','憶昨未知道，臨川每羨魚。',48,'全唐诗/poet.tang.28000.json','["憶昨未知道，臨川每羨魚。", "世途行處見，人事病來疎。", "微雨秋栽竹，孤燈夜讀書。", "憐君亦同志，晚歲傍山居。"]'),
('bba63f2f-a1ed-428a-8a9c-1e8447b8ef5b','西山草堂','許渾','唐','唐诗','tang','','[]','何處少人事，西山舊草堂。',48,'全唐诗/poet.tang.28000.json','["何處少人事，西山舊草堂。", "晒書秋日晚，洗藥石泉香。", "浚嶺有朝雨，北窗生夜涼。", "從勞問歸路，峰疊遶家鄉。"]'),
('bd1f2c3a-f0c4-409f-829b-a7a7e8e854e1','贈隱者','許渾','唐','唐诗','tang','','[]','回報隱居士，莫愁山興闌。',48,'全唐诗/poet.tang.28000.json','["回報隱居士，莫愁山興闌。", "求人顏色盡，知道性情寬。", "信譜彈琴誤，緣崖劚藥難。", "東臯亦自給，殊愧遠相安。"]'),
('831e1360-a726-42e6-b403-50ce04f1907e','舟次武陵寄天竺僧無晝','許渾','唐','唐诗','tang','','[]','谿長山幾重，十里萬株松。',48,'全唐诗/poet.tang.28000.json','["谿長山幾重，十里萬株松。", "秋日下丹檻，暮雲歸碧峰。", "樹棲新放鶴，潭隱舊降龍。", "還在孤舟宿，臥聞初夜鐘。"]'),
('75e3368e-aa81-4bad-9172-31cd39602335','寄小弟','許渾','唐','唐诗','tang','','[]','江城紅葉盡，旅思復悽傷。',48,'全唐诗/poet.tang.28000.json','["江城紅葉盡，旅思復悽傷。", "孤夢家山遠，獨眠秋夜長。", "道存空倚命，身賤未歸鄉。", "南望空垂淚，天邊鴈一行。"]'),
('8846f916-f34a-4123-807e-ec16c465d8fa','秋日','許渾','唐','唐诗','tang','','[]','有計自安業，秋風罷苦吟。',48,'全唐诗/poet.tang.28000.json','["有計自安業，秋風罷苦吟。", "買山兼種竹，對客更彈琴。", "煙起藥園晚，杵聲松院深。", "閑眠得真性，惆悵舊時心。"]'),
('d8468516-e8e1-4ba5-a5bf-4d6b6119d9c3','石池','許渾','唐','唐诗','tang','','[]','通竹引泉脉，泓澄瀲石盆。',48,'全唐诗/poet.tang.28000.json','["通竹引泉脉，泓澄瀲石盆。", "驚魚翻藻葉，浴鳥上松根。", "殘月留山影，高風耗水痕。", "誰家秋洗藥，來往自開門。"]'),
('9bda99da-d73a-4127-be83-435c4e5e49e2','留題李侍御書齋','許渾','唐','唐诗','tang','','[]','昔話平生志，高齋曾見留。',48,'全唐诗/poet.tang.28000.json','["昔話平生志，高齋曾見留。", "道孤心易感，恩重力難酬。", "獨立千峰曉，頻來一葉秋。", "雞鳴應有處，不覺淚空流。"]'),
('ad4f3106-4987-4343-bae0-4c11e7167530','行次白沙館先寄上河南王侍御','許渾','唐','唐诗','tang','','[]','夜程何處宿，山疊樹層層。',48,'全唐诗/poet.tang.28000.json','["夜程何處宿，山疊樹層層。", "孤館閉秋雨，空堂停曙燈。", "歌慙漁浦客，詩學鴈門僧。", "此意無人識，明朝見李膺。"]'),
('963a756e-4b6a-4b0d-924a-e48c9ce93f38','紫藤','許渾','唐','唐诗','tang','','[]','綠蘿縈數匝，本在草堂間。',48,'全唐诗/poet.tang.28000.json','["綠蘿縈數匝，本在草堂間。", "秋色寄高樹，晝陰籠遠山。", "移花疎處種，劚藥困時攀。", "日暮微風起，難尋舊徑還。"]'),
('5cd3431c-26c9-4049-90d6-f5049ca88c3e','暝投靈智寺渡谿不得却取沿江路往','許渾','唐','唐诗','tang','','[]','雙巖瀉一川，回馬斷橋前。',48,'全唐诗/poet.tang.28000.json','["雙巖瀉一川，回馬斷橋前。", "古廟陰風地，寒鐘暮雨天。", "沙虛留虎跡，水滑帶龍涎。", "却下臨江路，潮深無渡船。"]'),
('e57774bf-1620-4f7b-8366-e4510951e6bb','下第歸蒲城墅居','許渾','唐','唐诗','tang','','[]','失意歸三徑，傷春別九門。',48,'全唐诗/poet.tang.28000.json','["失意歸三徑，傷春別九門。", "薄煙楊柳路，微雨杏花村。", "牧豎還呼犢，隣翁亦抱孫。", "不知余正苦，迎馬問寒溫。"]'),
('f2562194-d1c6-4565-9f22-6a43aec65eab','重賦鷺鷥','許渾','唐','唐诗','tang','','[]','何年去此地，南浦滿鳧雛。',48,'全唐诗/poet.tang.28000.json','["何年去此地，南浦滿鳧雛。", "雲漢知心遠，林塘覺思孤。", "低飛下晚樹，獨睡映新蒲。", "爲爾多歸興，前年在五湖。"]'),
('8d38ae55-3a46-4607-b6be-362248664d71','途中寒食','許渾','唐','唐诗','tang','','[]','處處哭聲悲，行人馬亦遲。',48,'全唐诗/poet.tang.28000.json','["處處哭聲悲，行人馬亦遲。", "店閑無火日，村暖斫桑時。", "泣路同楊子，燒山憶介推。", "清明明日是，甘負故園期。"]'),
('0bfee4d8-2855-4b03-b000-f9ecc8cdd5c0','深春','許渾','唐','唐诗','tang','','[]','故里千帆外，深春一鴈飛。',48,'全唐诗/poet.tang.28000.json','["故里千帆外，深春一鴈飛。", "干名頻慟哭，將老欲何歸。", "未穀拋還憶，交親晚更稀。", "空持望鄉淚，霑灑寄來衣。"]'),
('b97cae5b-8e62-40e1-96d2-2422315eb31c','歲首懷甘露寺自省上人','許渾','唐','唐诗','tang','','[]','心悟覺身勞，雲中棄寶刀。',48,'全唐诗/poet.tang.28000.json','["心悟覺身勞，雲中棄寶刀。", "久閑生䏶肉，多壽長眉毫。", "客棹春潮急，禪齋暮雪高。", "南𤃩一回首，山碧水滔滔。"]'),
('e2c8a9d7-81c3-454f-bfc6-4f303672f097','尋周鍊師不遇留贈','許渾','唐','唐诗','tang','','[]','閉門池館靜，云訪紫芝翁。',48,'全唐诗/poet.tang.28000.json','["閉門池館靜，云訪紫芝翁。", "零落槿花雨，參差荷葉風。", "夜碁全局在，春酒半壺空。", "長嘯倚西閣，悠悠名利中。"]'),
('e3b86677-69e0-41a3-aa83-56ae7364cfda','題灞西駱隱居','許渾','唐','唐诗','tang','','[]','志凌三蜀客，心愛五湖人。',48,'全唐诗/poet.tang.28000.json','["志凌三蜀客，心愛五湖人。", "𢬵死酒中老，謀生書外貧。", "掃花眠石榻，擣藥轉溪輪。", "往往乘黃牸，鹿裘烏角巾。"]'),
('5b52231a-a838-41a4-aa12-7e0876ce48cc','旅夜懷遠客','許渾','唐','唐诗','tang','','[]','異鄉多遠情，夢斷落江城。',48,'全唐诗/poet.tang.28000.json','["異鄉多遠情，夢斷落江城。", "病起慙書癖，貧家負酒名。", "過春花自落，竟曉月空明。", "獨此一長嘯，故人天際行。"]'),
('4079b65c-9a7a-40c5-8510-c8f943a8327d','秋夜櫂舟訪李隱君','許渾','唐','唐诗','tang','','[]','望月憶披襟，長溪柳半陰。',48,'全唐诗/poet.tang.28000.json','["望月憶披襟，長溪柳半陰。", "高齋初釀酒，孤棹遠攜琴。", "犬吠秋山迥，雞鳴曉樹深。", "開門更攲枕，誰識野人心。"]'),
('60c1ee80-ab05-4465-b52d-7dd34da06849','臥病寄諸公','許渾','唐','唐诗','tang','','[]','飛蓋集蘭堂，清歌遰柏觴。',48,'全唐诗/poet.tang.28000.json','["飛蓋集蘭堂，清歌遰柏觴。", "高城榆柳蔭，虛閣芰荷香。", "海月秋偏靜，山風夜更涼。", "自憐書萬卷，扶病對螢光。"]'),
('1650ca54-664a-4e3b-b01a-1f343cc88e3a','寓崇聖寺懷李校書','許渾','唐','唐诗','tang','','[]','幾日臥南亭，卷簾秋月清。',48,'全唐诗/poet.tang.28000.json','["幾日臥南亭，卷簾秋月清。", "河關初罷夢，池閣更含情。", "寒露潤金井，高風飄玉箏。", "前年共遊客，刀筆事戎旌。"]'),
('3c064166-83bb-49be-91ba-1c9e10f5b468','秋日行次關西','許渾','唐','唐诗','tang','','[]','金風蕩天地，關西羣木凋。',48,'全唐诗/poet.tang.28000.json','["金風蕩天地，關西羣木凋。", "早霜雞喔喔，殘月馬蕭蕭。", "紫陌秦山近，青楓楚樹遙。", "還同長卿志，題字滿河橋。"]'),
('ca23a19c-aaf0-447d-9b26-89227da55dac','山居冬夜喜魏扶見訪因贈','許渾','唐','唐诗','tang','','[]','霜風露葉下，遠思獨裴回。',48,'全唐诗/poet.tang.28000.json','["霜風露葉下，遠思獨裴回。", "夜久草堂靜，月明山客來。", "遣貧相勸酒，憶字共書灰。", "何事清平世，干名待有媒。"]'),
('d54b3143-f029-414a-873b-da6670b5ebbb','喜李詡秀才見訪因贈','許渾','唐','唐诗','tang','','[]','浙南分首日，誰謂別經時。',48,'全唐诗/poet.tang.28000.json','["浙南分首日，誰謂別經時。", "路遠遙相訪，家貧喜見知。", "不須辭小酌，更請續新詩。", "但得心中劒，酬恩會有期。"]'),
('6a43d6cc-e2ba-4cb9-8b91-49119364c9d5','晚投慈恩寺呈俊上人','許渾','唐','唐诗','tang','','[]','雙巖瀉一川，十里絕人煙。',48,'全唐诗/poet.tang.28000.json','["雙巖瀉一川，十里絕人煙。", "古廟陰風地，寒鐘暮雨天。", "沙虛留虎跡，水滑帶龍涎。", "不及曹溪侶，空林已夜禪。"]'),
('41103129-3b0a-4e4e-a1c7-7ceb8da4d59e','行次虎頭巖酬寄路中丞','許渾','唐','唐诗','tang','','[]','樟亭去已遠，來上虎頭巖。',48,'全唐诗/poet.tang.28000.json','["樟亭去已遠，來上虎頭巖。", "灘急水移棹，山回風滿帆。", "石梯迎雨滑，沙井落潮醎。", "何以慰行旅，如公書一緘。"]'),
('f686881d-d8e5-4ab5-b8aa-267d085b8f3c','送荔浦蔣明府赴任','許渾','唐','唐诗','tang','','[]','路長春欲盡，歌怨酒初酣。',48,'全唐诗/poet.tang.28000.json','["路長春欲盡，歌怨酒初酣。", "白社蓮宮北，青袍桂水南。", "驛行盤鳥道，船宿避龍潭。", "真得詩人趣，煙霞處處諳。"]'),
('0628cb36-de19-48ab-91b5-529bf3915cef','懷政禪師院','許渾','唐','唐诗','tang','','[]','山齋路幾層，敗衲學真乘。',48,'全唐诗/poet.tang.28000.json','["山齋路幾層，敗衲學真乘。", "寒暑移雙樹，光陰盡一燈。", "風飄高竹雪，泉漲小池冰。", "莫訝頻來此，修身欲到僧。"]'),
('1d83d53e-72cb-4952-9d3b-23f39b2dc327','秋夕有懷','許渾','唐','唐诗','tang','','[]','念遠坐西閣，華池涵月涼。',48,'全唐诗/poet.tang.28000.json','["念遠坐西閣，華池涵月涼。", "書回秋欲盡，酒醒夜初長。", "露白蓮衣淺，風清蕙帶香。", "前年此佳景，蘭棹醉橫塘。"]'),
('21f7ad17-52fc-4b03-9b3c-d4ae667ed27e','秋霽寄遠','許渾','唐','唐诗','tang','','[]','初霽獨登賞，西樓多遠風。',48,'全唐诗/poet.tang.28000.json','["初霽獨登賞，西樓多遠風。", "橫煙秋水上，疎雨夕陽中。", "高樹下山鳥，平蕪飛草蟲。", "唯應待明月，千里與君同。"]'),
('a0cb521b-e9a6-495e-8d79-137ead276e48','聞范秀才自蜀遊江湖','許渾','唐','唐诗','tang','','[]','蜀道下湘渚，客帆應不迷。',48,'全唐诗/poet.tang.28000.json','["蜀道下湘渚，客帆應不迷。", "江分三峽響，山並九華齊。", "秋泊鴈初宿，夜吟猨乍啼。", "歸時慎行李，莫到石城西。"]'),
('dfff9164-145b-4853-ac0f-1388ddbb95ab','惜春','許渾','唐','唐诗','tang','','[]','花開又花落，時節暗中遷。',48,'全唐诗/poet.tang.28000.json','["花開又花落，時節暗中遷。", "無計延春日，可能留少年。", "小藂初散蝶，高柳即聞蟬。", "繁豔歸何處，滿山啼杜鵑。"]'),
('f42d1dec-f5ef-49ca-9457-6b9eca0dba16','題愁','許渾','唐','唐诗','tang','','[]','聚散竟無形，迴腸百結成。',48,'全唐诗/poet.tang.28000.json','["聚散竟無形，迴腸百結成。", "古今銷不得，離別覺潛生。", "降虜將軍思，窮秋遠客情。", "何人更憔悴，落第泣秦京。"]'),
('eba0d782-e195-4bbc-b490-c82a72f57c23','鴛鴦','許渾','唐','唐诗','tang','','[]','兩兩戲沙汀，長疑畫不成。',48,'全唐诗/poet.tang.28000.json','["兩兩戲沙汀，長疑畫不成。", "錦機爭織樣，歌曲愛呼名。", "好□顧栖息，堪憐泛淺情。", "鳧鷗皆爾類，唯羨獨含情。"]'),
('6fbfe40e-2275-4b4c-9e80-76cb9579615c','聞鴈','許渾','唐','唐诗','tang','','[]','帶霜南去鴈，夜好宿汀沙。',48,'全唐诗/poet.tang.28000.json','["帶霜南去鴈，夜好宿汀沙。", "驚起向何處，高飛極海涯。", "入雲聲漸遠，離岳路猶賒。", "歸夢當時斷，參差欲到家。"]'),
('85a04775-5bbd-4432-bec9-bd7b74d713c0','不寢','許渾','唐','唐诗','tang','','[]','到曉不成夢，思量堪白頭。',48,'全唐诗/poet.tang.28000.json','["到曉不成夢，思量堪白頭。", "多無百年命，長有萬般愁。", "世事應難盡，營生卒未休。", "莫言名與利，名利是身讐。"]'),
('7cc982de-af2c-42c1-91c1-cc961e43726a','宿東橫山','許渾','唐','唐诗','tang','','[]','孤舟路漸賒，時見碧桃花。',52,'全唐诗/poet.tang.28000.json','["孤舟路漸賒，時見碧桃花。", "溪雨灘聲急，巖風樹勢斜。", "獼猴垂弱蔓，鸛鶴[睡]橫槎。", "謾向仙林宿，無人[識]阮家。"]'),
('f2536a51-596f-48d2-ab0c-bbf89ad63d8f','早行','許渾','唐','唐诗','tang','','[]','失枕驚先起，人家半夢中。',48,'全唐诗/poet.tang.28000.json','["失枕驚先起，人家半夢中。", "聞雞憑早晏，占斗認西東。", "轡濕知行露，衣單覺曉風。", "秋陽弄光影，忽吐半林紅。"]'),
('8b655e14-26ee-4390-9e54-a890202b1194','陪鄭史君泛舟晚歸','許渾','唐','唐诗','tang','','[]','南郭望歸處，郡樓高卷簾。',48,'全唐诗/poet.tang.28000.json','["南郭望歸處，郡樓高卷簾。", "平橋低皂蓋，曲岸轉彤襜。", "江晚笙歌促，山晴鼓角嚴。", "羊公莫先醉，清曉月纖纖。"]'),
('f06c7d03-cb39-43df-aa4d-012ecae0504f','詶殷堯藩','許渾','唐','唐诗','tang','','[]','相如愧許詢，寥落向溪濱。',48,'全唐诗/poet.tang.28000.json','["相如愧許詢，寥落向溪濱。", "竹馬兒猶小，荆釵婦慣貧。", "獨愁憂過日，多病不如人。", "莫怪青袍選，長安隱舊春。"]'),
('49031c97-ebf6-4985-96b6-c29aa3b200ff','贈遷客','許渾','唐','唐诗','tang','','[]','無機還得罪，直道不傷情。',48,'全唐诗/poet.tang.28000.json','["無機還得罪，直道不傷情。", "微雨昏山色，疎籠閉鶴聲。", "閑居多野客，高枕見江城。", "門外長谿水，憐君又濯纓。"]'),
('b4400596-1ff0-48eb-b424-0c5fb8db9fe7','征西舊卒','許渾','唐','唐诗','tang','','[]','少年乘勇氣，百戰過烏孫。',48,'全唐诗/poet.tang.28000.json','["少年乘勇氣，百戰過烏孫。", "力盡邊城難，功加上將恩。", "曉風聽戍角，殘月倚營門。", "自說輕生處，金瘡有舊痕。"]'),
('fe1451a6-7b5d-41a5-98e7-e49699332293','南陵留別段氏兄弟','許渾','唐','唐诗','tang','','[]','不知身老大，猶似舊時狂。',48,'全唐诗/poet.tang.28000.json','["不知身老大，猶似舊時狂。", "爲酒遊山縣，留詩遍草堂。", "歸期秋未盡，離恨日偏長。", "更羨君兄弟，參差鴈一行。"]'),
('24f44c0d-8200-4142-9478-31d01f861603','旅中別姪暐','許渾','唐','唐诗','tang','','[]','相見又南北，中宵淚滿襟。',48,'全唐诗/poet.tang.28000.json','["相見又南北，中宵淚滿襟。", "旅遊知世薄，貧別覺情深。", "歌管一尊酒，山川萬里心。", "此身多在路，休誦異鄉吟。"]'),
('e200fdcc-28e7-4987-b9d2-0ae0e3d810fa','松江渡送人','許渾','唐','唐诗','tang','','[]','故國今何在，扁舟竟不歸。',48,'全唐诗/poet.tang.28000.json','["故國今何在，扁舟竟不歸。", "雲移山漠漠，江闊樹依依。", "晚色千帆落，秋聲一鴈飛。", "此時兼送客，憑檻欲霑衣。"]'),
('11039f7d-7cf1-47c5-8701-e5c3c84f307a','過鮑溶宅有感','許渾','唐','唐诗','tang','','[]','寥落故人宅，重來身已亡。',48,'全唐诗/poet.tang.28000.json','["寥落故人宅，重來身已亡。", "古苔殘墨沼，深竹舊書堂。", "秋色館池靜，雨聲雲木涼。", "無因展交道，日暮倍心傷。"]'),
('26d0076f-779c-46ca-bea9-a5caeb529729','金陵懷古','許渾','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u767b\u9ad8", "\u5199\u666f", "\u548f\u53f2\u6000\u53e4"]','玉樹歌殘王氣終，景陽兵合戍樓空。',64,'全唐诗/poet.tang.28000.json','["玉樹歌殘王氣終，景陽兵合戍樓空。", "松楸遠近千官塚，禾黍高低六代宮。", "石燕拂雲晴亦雨，江豚吹浪夜還風。", "英雄一去豪華盡，唯有青山似洛中。"]'),
('3ed571de-5397-40a0-a262-febbf957e1a4','姑蘇懷古','許渾','唐','唐诗','tang','','[]','宮館餘基輟棹過，黍苗無限獨悲歌。',64,'全唐诗/poet.tang.28000.json','["宮館餘基輟棹過，黍苗無限獨悲歌。", "荒臺麋鹿爭新草，空苑鳧鷖占淺莎。", "吳岫雨來虛檻冷，楚江風急遠帆多。", "可憐國破忠臣死，日日東流生白波。"]'),
('116c803d-b32f-45fd-ad7d-3cb453dcfbdd','凌歊臺','許渾','唐','唐诗','tang','','[]','宋祖凌高樂未回，三千歌舞宿層臺。',64,'全唐诗/poet.tang.28000.json','["宋祖凌高樂未回，三千歌舞宿層臺。", "湘潭雲盡暮山出，巴蜀雪消春水來。", "行殿有基荒薺合，寢園無主野棠開。", "百年便作萬年計，嵒畔古碑空綠苔。"]'),
('fbb27494-21bd-446d-b1b4-ff9567d63c03','驪山','許渾','唐','唐诗','tang','','[]','聞說先皇醉碧桃，日華浮動鬱金袍。',64,'全唐诗/poet.tang.28000.json','["聞說先皇醉碧桃，日華浮動鬱金袍。", "風隨玉輦笙歌逈，雲捲珠簾劒佩高。", "鳳駕北歸山寂寂，龍旟西幸水滔滔。", "貴妃沒後巡遊少，瓦落宮墻見野蒿。"]'),
('ae5ca477-e66f-423f-bed6-944ed737f66b','咸陽城東樓','許渾','唐','唐诗','tang','','["\u540a\u53e4\u4f24\u4eca", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5199\u666f"]','一上高城萬里愁，蒹葭楊柳似汀洲。',64,'全唐诗/poet.tang.28000.json','["一上高城萬里愁，蒹葭楊柳似汀洲。", "溪雲初起日沈閣，山雨欲來風滿樓。", "鳥下綠蕪秦苑夕，蟬鳴黃葉漢宮秋。", "行人莫問當年事，故國東來渭水流。"]'),
('62a679ba-aae0-49ef-9f88-417c5ec8529c','京口閑居寄京洛友人','許渾','唐','唐诗','tang','','[]','吳門煙月昔同遊，楓葉蘆花並客舟。',64,'全唐诗/poet.tang.29000.json','["吳門煙月昔同遊，楓葉蘆花並客舟。", "聚散有期雲北去，浮沈無計水東流。", "一尊酒盡青山暮，千里書回碧樹秋。", "何處相思不相見，鳳城龍闕楚江頭。"]'),
('584e5331-0d9c-4af4-94a6-c5250764f2b4','冬日登越王臺懷歸','許渾','唐','唐诗','tang','','[]','月沈高岫宿雲開，萬里歸心獨上來。',64,'全唐诗/poet.tang.29000.json','["月沈高岫宿雲開，萬里歸心獨上來。", "河畔雪飛揚子宅，海邊花盛越王臺。", "瀧分桂嶺魚難過，瘴近衡峯鴈却回。", "鄉信漸稀人漸老，只應頻看一枝梅。"]'),
('16e667ab-12e3-49a0-88d3-ea8c3122ff19','對雪','許渾','唐','唐诗','tang','','[]','雲度龍山暗倚城，先飛淅瀝引輕盈。',64,'全唐诗/poet.tang.29000.json','["雲度龍山暗倚城，先飛淅瀝引輕盈。", "素娥冉冉拜瑤闕，皓鶴紛紛朝玉京。", "陰嶺有風梅豔散，寒林無月桂華生。", "剡溪一醉十年事，忽憶棹回天未明。"]'),
('c1c4fd2b-87b4-438a-8803-bbf5ade86b4f','送蕭處士歸緱嶺別業','許渾','唐','唐诗','tang','','[]','醉斜烏帽髪如絲，曾看仙人一局棋。',64,'全唐诗/poet.tang.29000.json','["醉斜烏帽髪如絲，曾看仙人一局棋。", "賓館有魚爲客久，鄉書無鴈到家遲。", "緱山住近吹笙廟，湘水行逢鼓瑟祠。", "今夜月明何處宿，九疑雲盡碧參差。"]'),
('51d5dd08-f139-4c99-a2c6-6a3d8191894a','與鄭二秀才同舟東下洛中親朋送至景雲寺','許渾','唐','唐诗','tang','','[]','三十六峰橫一川，綠波無路草芊芊。',64,'全唐诗/poet.tang.29000.json','["三十六峰橫一川，綠波無路草芊芊。", "牛羊晚食鋪平地，鵰鶚晴飛摩遠天。", "洛客盡回臨水寺，楚人皆逐下江船。", "東西未有相逢日，更把繁華共醉眠。"]'),
('5ed0e43e-41ac-46bd-8723-329282f5036d','長安歲暮','許渾','唐','唐诗','tang','','[]','獨望天門倚劒歌，干時無計老關河。',64,'全唐诗/poet.tang.29000.json','["獨望天門倚劒歌，干時無計老關河。", "東歸萬里慙張翰，西上四年羞卞和。", "花暗楚城春醉少，月涼秦塞夜愁多。", "三山歲歲有人去，唯恐海風生白波。"]'),
('500c34e5-1431-4022-b031-9f4355d6bdba','贈茅山高拾遺','許渾','唐','唐诗','tang','','[]','諫獵歸來綺季歌，大茅峯影滿秋波。',64,'全唐诗/poet.tang.29000.json','["諫獵歸來綺季歌，大茅峯影滿秋波。", "山齋留客掃紅葉，野艇送僧披綠莎。", "長覆舊圖棊勢盡，遍添新品藥名多。", "雲中黃鵠日千里，自宿自飛無網羅。"]'),
('979c2ce0-f38c-4374-b446-413a4969495b','李秀才近自塗口遷居新安適枉緘書見寛悲戚因以此答','許渾','唐','唐诗','tang','','[]','遠書開罷更依依，晨坐高臺竟落暉。',64,'全唐诗/poet.tang.29000.json','["遠書開罷更依依，晨坐高臺竟落暉。", "顏巷雪深人已去，庾樓花盛客初歸。", "東堂望絕遷鶯起，南國哀餘候鴈飛。", "今日勞君猶問訊，一官唯長故山薇。"]'),
('c336e75d-4716-4826-aae6-ceefdec37f34','贈蕭兵曹先輩','許渾','唐','唐诗','tang','','[]','廣陵堤上昔離居，帆轉瀟湘萬里餘。',64,'全唐诗/poet.tang.29000.json','["廣陵堤上昔離居，帆轉瀟湘萬里餘。", "楚客病時無鵩鳥，越鄉歸處有鱸魚。", "潮生水郭蒹葭響，雨過山城橘柚疎。", "聞說攜琴兼載酒，邑人爭識馬相如。"]'),
('f605356f-b9ac-428c-bed0-02829db16142','題舒女廟','許渾','唐','唐诗','tang','','[]','山樂來迎去不言，廟前高柳水禽喧。',64,'全唐诗/poet.tang.29000.json','["山樂來迎去不言，廟前高柳水禽喧。", "綺羅無色雨侵帳，珠翠有聲風繞幡。", "妝鏡尚疑山月滿，寢屏猶認野花繁。", "孤舟夢斷行雲散，何限離心寄曉猨。"]'),
('3cff78c1-915a-4ca4-8f08-33e7ccd21378','姑孰官舍','許渾','唐','唐诗','tang','','[]','草生官舍似閑居，雪照南窗滿素書。',64,'全唐诗/poet.tang.29000.json','["草生官舍似閑居，雪照南窗滿素書。", "貧後始知爲吏拙，病來還喜識人疎。", "青雲豈有窺梁燕，濁水應無避釣魚。", "不待秋風便歸去，紫陽山下是吾廬。"]'),
('9891018f-1c27-4e20-8503-1998a6273022','凌歊臺送韋秀才','許渾','唐','唐诗','tang','','[]','雲起高臺日未沈，數村殘照半巖陰。',66,'全唐诗/poet.tang.29000.json','["雲起高臺日未沈，數村殘照半巖陰。", "野蠶成繭桑柘盡，溪鳥引雛蒲稗深。", "帆勢依依投極浦，鐘聲[杳杳]隔前林。", "故山迢遰故人去，一夜月明千里心。"]'),
('9e0ad576-af17-4be9-a874-7b41216cde36','送嶺南盧判官罷職歸華陰山居','許渾','唐','唐诗','tang','','[]','曾事劉琨鴈塞空，十年書劒任飄蓬。',64,'全唐诗/poet.tang.29000.json','["曾事劉琨鴈塞空，十年書劒任飄蓬。", "東堂舊屈移山志，南國新留煮海功。", "還挂一帆青海上，更開三逕碧蓮中。", "關西舊友如相問，已許滄浪伴釣翁。"]'),
('593d815a-910b-4b76-9b8e-5e4df97707ce','將度故城湖阻風夜泊永陽戍','許渾','唐','唐诗','tang','','[]','行盡青溪日已蹉，雲容山影水嵯峨。',64,'全唐诗/poet.tang.29000.json','["行盡青溪日已蹉，雲容山影水嵯峨。", "樓前歸客怨清夢，樓上美人凝夜歌。", "獨樹高高風勢急，平湖渺渺月明多。", "終期一艇載樵去，來往使帆凌白波。"]'),
('b35d7a78-6d97-4bbf-af77-c204ff9b7728','鄭侍御廳翫鶴','許渾','唐','唐诗','tang','','[]','碧天飛舞下晴莎，金閣瑤池絕網羅。',64,'全唐诗/poet.tang.29000.json','["碧天飛舞下晴莎，金閣瑤池絕網羅。", "嵒響數聲風滿樹，岸移孤影雪凌波。", "緱山去遠雲霄迥，遼海歸遲歲月多。", "雙翅一開千萬里，秖應棲隱戀喬柯。"]'),
('94710607-3d19-4640-b897-4a37c5f9c8d7','南亭夜坐貽開元禪定二道者','許渾','唐','唐诗','tang','','[]','暮暮焚香何處宿，西巖一室映疎藤。',64,'全唐诗/poet.tang.29000.json','["暮暮焚香何處宿，西巖一室映疎藤。", "光陰難駐跡如客，寒暑不驚心似僧。", "高樹有風聞夜磬，遠山無月見秋燈。", "身閑境靜日爲樂，若問其餘非我能。"]'),
('5577901c-fd3f-4c29-b633-dbc3617bf237','朱坡故少保杜公池亭','許渾','唐','唐诗','tang','','[]','杜陵池榭綺城東，孤島回汀路不窮。',64,'全唐诗/poet.tang.29000.json','["杜陵池榭綺城東，孤島回汀路不窮。", "高岫乍疑三峽近，遠波初似五湖通。", "楸梧葉暗瀟瀟雨，菱荇花香淡淡風。", "還有昔時巢燕在，飛來飛去畫堂中。"]'),
('c2fd4060-decf-49f0-90d8-0f718b902a9b','秋日早朝','許渾','唐','唐诗','tang','','[]','宵衣應待絕更籌，環佩鏘鏘月下樓。',64,'全唐诗/poet.tang.29000.json','["宵衣應待絕更籌，環佩鏘鏘月下樓。", "井轉轆轤千樹曉，鏁開閶闔萬山秋。", "龍旗盡列趨金殿，雉扇才分見玉旒。", "虛戴鐵冠無一事，滄江歸去老漁舟。"]'),
('b35bf541-f8f6-4422-b30b-532eedfe4500','滄浪峽','許渾','唐','唐诗','tang','','[]','纓帶流塵髪半霜，獨尋殘月下滄浪。',64,'全唐诗/poet.tang.29000.json','["纓帶流塵髪半霜，獨尋殘月下滄浪。", "一聲溪鳥暗雲散，萬片野花流水香。", "昔日未知方外樂，暮年初信夢中忙。", "紅蝦青鯽紫芹脆，歸去不辭來路長。"]'),
('af3013bf-efd1-4f45-80f3-ad50c980c9f1','故洛城','許渾','唐','唐诗','tang','','[]','禾黍離離半野蒿，昔人城此豈知勞。',64,'全唐诗/poet.tang.29000.json','["禾黍離離半野蒿，昔人城此豈知勞。", "水聲東去市朝變，山勢北來宮殿高。", "鴉噪暮雲歸古堞，鴈迷寒雨下空壕。", "可憐緱嶺登仙子，猶自吹笙醉碧桃。"]'),
('1c7bad4c-fd1c-4615-9bd6-df8feed4bfd3','聞釋子栖玄欲奉道因寄','許渾','唐','唐诗','tang','','[]','欲求真訣戀禪扃，羽帔方袍盡有情。',64,'全唐诗/poet.tang.29000.json','["欲求真訣戀禪扃，羽帔方袍盡有情。", "仙骨本微靈鶴遠，法心潛動毒龍驚。", "三山未有偷桃計，四海初傳問菊名。", "今日勸師師莫惑，長生難學證無生。"]'),
('e1a14989-773a-413b-95b0-c3a868beda94','南海府罷南康阻淺行侶稍登陸而邁主人燕餞至頻暮宿東溪','許渾','唐','唐诗','tang','','[]','暗灘水落漲虛沙，灘去秦吳萬里賒。',64,'全唐诗/poet.tang.29000.json','["暗灘水落漲虛沙，灘去秦吳萬里賒。", "馬上折殘江北柳，舟中開盡嶺南花。", "離歌不斷如留客，歸夢初驚似到家。", "山鳥一聲人未起，半牀春月在天涯。"]'),
('53ed7d72-b353-485e-b746-07574de6a42e','秋晚雲陽驛西亭蓮池','許渾','唐','唐诗','tang','','[]','心憶蓮池秉燭遊，葉殘花敗尚維舟。',64,'全唐诗/poet.tang.29000.json','["心憶蓮池秉燭遊，葉殘花敗尚維舟。", "煙開翠扇清風曉，水泥紅衣白露秋。", "神女暫來雲易散，仙娥初去月難留。", "空懷遠道難持贈，醉倚闌干盡日愁。"]'),
('7f702ef8-9af6-410f-a375-c3ac88e8e3d8','題勤尊師歷陽山居','許渾','唐','唐诗','tang','','[]','二十知兵在羽林，中年潛識子房心。',64,'全唐诗/poet.tang.29000.json','["二十知兵在羽林，中年潛識子房心。", "蒼鷹出塞胡塵滅，白鶴還鄉楚水深。", "春坼酒瓶浮藥氣，晚攜棊局帶松陰。", "雞籠山上雲多處，自斸黃精不可尋。"]'),
('5308b242-865a-4ed9-a716-9a6592c45590','懷舊居','許渾','唐','唐诗','tang','','[]','兵書一篋老無功，故國郊扉在夢中。',64,'全唐诗/poet.tang.29000.json','["兵書一篋老無功，故國郊扉在夢中。", "藤蔓覆梨張谷暗，草花侵菊庾園空。", "朱門跡忝登龍客，白屋心期失馬翁。", "楚水吳山何處是，北窗殘月照屏風。"]'),
('36269a84-1558-48df-a0b9-5c998f12590d','祗命許昌自郊居移就公館秋日寄茅山高拾遺','許渾','唐','唐诗','tang','','[]','一笛迎風萬葉飛，強攜刀筆換荷衣。',64,'全唐诗/poet.tang.29000.json','["一笛迎風萬葉飛，強攜刀筆換荷衣。", "潮寒水國秋砧早，月暗山城夜漏稀。", "巖響遠聞樵客過，浦深遙送釣童歸。", "中年未識從軍樂，虛近三茅望少微。"]'),
('be76603e-2575-4ff5-9999-8c1828582755','傷虞將軍','許渾','唐','唐诗','tang','','[]','白首從軍未有名，近將孤劒到江城。',64,'全唐诗/poet.tang.29000.json','["白首從軍未有名，近將孤劒到江城。", "巴童戍久能番語，胡馬調多解漢行。", "對雪夜窮黃石略，望雲秋計黑山程。", "可憐身死家猶遠，汴水東流無哭聲。"]'),
('8a1b4524-d02f-407b-92e4-2be633993da7','晚自朝臺津至韋隱居郊園','許渾','唐','唐诗','tang','','[]','秋來鳧鴈下方塘，繫馬朝臺步夕陽。',64,'全唐诗/poet.tang.29000.json','["秋來鳧鴈下方塘，繫馬朝臺步夕陽。", "村徑繞山松葉暗，野門臨水稻花香。", "雲連海氣琴書潤，風帶潮聲枕簟涼。", "西下磻溪猶萬里，可能垂白待文王。"]'),
('319a9b28-fbea-4a75-8929-ad524ff4751f','寓居開元精舍酬薛秀才見貽','許渾','唐','唐诗','tang','','[]','知己蕭條信陸沈，茂陵扶疾臥西林。',64,'全唐诗/poet.tang.29000.json','["知己蕭條信陸沈，茂陵扶疾臥西林。", "芰荷風起客堂靜，松桂月高僧院深。", "清露下時傷旅鬢，白雲歸處寄鄉心。", "憐君詩句猶相憶，題在空齋夜夜吟。"]'),
('34445d84-93cc-43fd-b651-97b205aeddf9','別劉秀才','許渾','唐','唐诗','tang','','[]','三獻無功玉有瑕，更攜書劒客天涯。',64,'全唐诗/poet.tang.29000.json','["三獻無功玉有瑕，更攜書劒客天涯。", "孤帆夜別瀟湘雨，廣陌春期鄠杜花。", "燈照水螢千點滅，棹驚灘鴈一行斜。", "關河萬里秋風急，望見鄉山不到家。"]'),
('ed535503-69a1-4623-9738-a55aba7365a3','早發天台中巖寺度關嶺次天姥岑','許渾','唐','唐诗','tang','','[]','來往天台天姥間，欲求真訣駐衰顏。',64,'全唐诗/poet.tang.29000.json','["來往天台天姥間，欲求真訣駐衰顏。", "星河半落巖前寺，雲霧初開嶺上關。", "丹壑樹多風浩浩，碧溪苔淺水潺潺。", "可知劉阮逢人處，行盡深山又是山。"]'),
('2a5fe5e1-1054-4b9e-a5db-60accc6effbf','遊錢塘青山李隱居西齋','許渾','唐','唐诗','tang','','[]','小隱西亭爲客開，翠蘿深處遍蒼苔。',64,'全唐诗/poet.tang.29000.json','["小隱西亭爲客開，翠蘿深處遍蒼苔。", "林間掃石安棊局，巖下分泉遞酒盃。", "蘭葉露光秋月上，蘆花風起夜潮來。", "雲山遶屋猶嫌淺，欲棹漁舟近釣臺。"]'),
('a0e5764c-b083-4019-8e88-a0629aab8431','春日郊園戲贈楊嘏評事','許渾','唐','唐诗','tang','','[]','十里蒹葭入薜蘿，春風誰許暫鳴珂。',64,'全唐诗/poet.tang.29000.json','["十里蒹葭入薜蘿，春風誰許暫鳴珂。", "相如渴後狂還減，曼倩歸來語更多。", "門枕碧溪冰皓耀，檻齊青嶂雪嵯峨。", "野橋沽酒茅簷醉，誰羨紅樓一曲歌。"]'),
('c3a601c5-78a8-4db0-be89-9210d3ff375b','晚自東郭回留一二遊侶','許渾','唐','唐诗','tang','','[]','鄉心迢遰宦情微，吏散尋幽竟落暉。',64,'全唐诗/poet.tang.29000.json','["鄉心迢遰宦情微，吏散尋幽竟落暉。", "林下草腥巢鷺宿，洞前雲濕雨龍歸。", "鐘隨野艇回孤棹，鼓絕山城掩半扉。", "今夜西齋好風月，一瓢春酒莫相違。"]'),
('67a338bc-7a8a-4fd1-845e-46c11606671b','與鄭秀才叔姪會送楊秀才昆仲東歸','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','書劒功遲白髮新，異鄉仍送故鄉人。',64,'全唐诗/poet.tang.29000.json','["書劒功遲白髮新，異鄉仍送故鄉人。", "阮公留客竹林晚，田氏到家荆樹春。", "雪盡塞鴻南翥少，風來胡馬北嘶頻。", "洞庭煙月如終老，誰是長楊諫獵臣。"]'),
('0b9cb934-5554-4eb2-a792-56a9062ca2d4','送郭秀才遊天台','許渾','唐','唐诗','tang','','[]','雲埋陰壑雪凝峯，半壁天台已萬重。',64,'全唐诗/poet.tang.29000.json','["雲埋陰壑雪凝峯，半壁天台已萬重。", "人度碧溪疑輟棹，僧歸蒼嶺似聞鐘。", "暖眠鸂鶒晴灘草，高挂獼猴暮澗松。", "曾約共遊今獨去，赤城西面水溶溶。"]'),
('005b0e22-126e-408a-a3cd-0b3f6057ae5e','送張尊師歸洞庭','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','能琴道士洞庭西，風滿歸帆路不迷。',64,'全唐诗/poet.tang.29000.json','["能琴道士洞庭西，風滿歸帆路不迷。", "對岸水花霜後淺，傍簷山果雨來低。", "杉松近晚移茶竈，巖谷初寒蓋藥畦。", "他日相思兩行字，無人知處武陵溪。"]'),
('6ea2d0fa-d677-42cf-9877-5c9b09e13ace','移攝太平寄前李明府','許渾','唐','唐诗','tang','','[]','病移嵒邑稱閑身，何處風光貰酒頻。',64,'全唐诗/poet.tang.29000.json','["病移嵒邑稱閑身，何處風光貰酒頻。", "溪柳遶門彭澤令，野花連洞武陵人。", "嬌歌自駐壺中景，豔舞長留海上春。", "早晚高臺更同醉，綠蘿如帳草如茵。"]'),
('df1590b2-d8e8-492a-b7b3-eee0a614e565','再遊姑蘇玉芝觀','許渾','唐','唐诗','tang','','[]','高梧一葉下秋初，迢遰重廊舊寄居。',64,'全唐诗/poet.tang.29000.json','["高梧一葉下秋初，迢遰重廊舊寄居。", "月過碧窗今夜酒，雨昏紅壁去年書。", "玉池露冷芙蓉淺，瓊樹風高薜荔疎。", "明日挂帆更東去，仙翁應笑爲鱸魚。"]'),
('d0b93745-247b-41d1-af1a-678878f8c731','夜歸驛樓','許渾','唐','唐诗','tang','','[]','水晚雲秋山不窮，自疑身在畫屏中。',64,'全唐诗/poet.tang.29000.json','["水晚雲秋山不窮，自疑身在畫屏中。", "孤舟移棹一江月，高閣捲簾千樹風。", "窗下覆棋殘局在，橘邊沽酒半壜空。", "早炊香稻待鱸鱠，南渚未明尋釣翁。"]'),
('8e2e07b9-33aa-4331-bd48-9ab9b49745a9','題靈山寺行堅師院','許渾','唐','唐诗','tang','','[]','西巖一逕不通樵，八十持杯未覺遙。',64,'全唐诗/poet.tang.29000.json','["西巖一逕不通樵，八十持杯未覺遙。", "龍在石潭聞夜雨，鴈移沙渚見秋潮。", "經函露濕文多暗，香印風吹字半銷。", "應笑東歸又南去，越山無路水迢迢。"]'),
('01089f7e-faae-4503-9174-b836f6ebdacf','湖州韋長史山居','許渾','唐','唐诗','tang','','[]','一官唯買晝公堂，但得身閑日自長。',64,'全唐诗/poet.tang.29000.json','["一官唯買晝公堂，但得身閑日自長。", "琴曲少聲重勘譜，藥丸多忌更尋方。", "溪浮箬葉添醅綠，泉遶松根助茗香。", "明日鱖魚何處釣，門前春水似滄浪。"]'),
('23d0926b-c071-448c-85af-737df08e22d6','贈李伊闕','許渾','唐','唐诗','tang','','[]','桐履如飛不可尋，一壺雙笈嶧陽琴。',64,'全唐诗/poet.tang.29000.json','["桐履如飛不可尋，一壺雙笈嶧陽琴。", "舟橫野度寒風急，門掩荒山夜雪深。", "貧笑白駒無去意，病慙黃鵠有歸心。", "雲間二室勞君畫，水墨蒼蒼半壁陰。"]'),
('6bd3176d-6a22-4757-b5f4-bf1ad16aa60a','重遊綀湖懷舊','許渾','唐','唐诗','tang','','[]','西風渺渺月連天，同醉蘭舟未十年。',64,'全唐诗/poet.tang.29000.json','["西風渺渺月連天，同醉蘭舟未十年。", "鵩鳥賦成人已沒，嘉魚詩在世空傳。", "榮枯盡寄浮雲外，哀樂猶驚逝水前。", "日暮長隄更回首，一聲鄰笛舊山川。"]'),
('b6ecb19a-f6b6-45f5-9e2a-e3057569f3b8','乘月棹舟送大曆寺靈聰上人不及','許渾','唐','唐诗','tang','','[]','萬峰秋盡百泉清，舊鎖禪扉在赤城。',64,'全唐诗/poet.tang.29000.json','["萬峰秋盡百泉清，舊鎖禪扉在赤城。", "楓浦客來煙未散，竹窗僧去月猶明。", "杯浮野渡魚龍遠，錫響空山虎豹驚。", "一字不留何足訝，白雲無路水無情。"]'),
('8341c4f7-04b1-4c38-b0aa-2103807662cf','汴河亭','許渾','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6292\u60c5", "\u548f\u53f2"]','廣陵花盛帝東游，先劈崑崙一派流。',64,'全唐诗/poet.tang.29000.json','["廣陵花盛帝東游，先劈崑崙一派流。", "百二禁兵辭象闕，三千宮女下龍舟。", "凝雲鼓震星辰動，拂浪旗開日月浮。", "四海義師歸有道，迷樓還似景陽樓。"]'),
('9b272de0-513c-470b-8d8a-2d802b5fd73c','村舍二首 一','許渾','唐','唐诗','tang','','[]','自翦青莎織雨衣，南峰煙火是柴扉。',64,'全唐诗/poet.tang.29000.json','["自翦青莎織雨衣，南峰煙火是柴扉。", "萊妻早報蒸藜熟，童子遙迎種豆歸。", "魚下碧潭當鏡躍，鳥還青嶂拂屏飛。", "花時未免人來往，欲買嚴光舊釣磯。"]'),
('ece41fd2-3321-4e1b-a32c-3c61f692c30d','村舍二首 二','許渾','唐','唐诗','tang','','[]','尚平多累自歸難，一日身閑一日安。',64,'全唐诗/poet.tang.29000.json','["尚平多累自歸難，一日身閑一日安。", "山逕曉雲收獵網，水門涼月挂魚竿。", "花間酒氣春風暖，竹裏棋聲暮雨寒。", "三頃水田秋更熟，北窗誰拂舊塵冠。"]'),
('ce3a66a7-1ce1-4c22-aaeb-437a84f6a730','鄭秀才東歸憑達家書','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','欲寄家書少客過，閉門心遠洞庭波。',64,'全唐诗/poet.tang.29000.json','["欲寄家書少客過，閉門心遠洞庭波。", "兩巖花落夜風急，一逕草荒春雨多。", "愁泛楚江吟浩渺，憶歸吳岫夢嵯峨。", "貧居不問應知處，溪上閑船繫綠蘿。"]'),
('a5c32cf7-392f-4562-80b4-cdae2ee192d7','傷故湖州李郎中','許渾','唐','唐诗','tang','','[]','政成身沒共興衰，鄉路兵戈旅櫬迴。',64,'全唐诗/poet.tang.29000.json','["政成身沒共興衰，鄉路兵戈旅櫬迴。", "城上暮雲凝鼓角，海邊春草閉池臺。", "經年未葬家人散，昨夜因齋故吏來。", "南北相逢皆掩泣，白蘋洲暖百花開。"]'),
('8abd41dd-11fd-4885-b603-80d48230b720','和友人送僧歸桂州靈巖寺','許渾','唐','唐诗','tang','','[]','楚客送僧歸桂陽，海門帆勢極瀟湘。',64,'全唐诗/poet.tang.29000.json','["楚客送僧歸桂陽，海門帆勢極瀟湘。", "碧雲千里暮愁合，白雪一聲春思長。", "柳絮擁堤添衲軟，松花浮水注瓶香。", "南京長老幾年別，聞道半巖多影堂。"]'),
('ef407373-3f8b-403d-be5c-cb10e19aff82','淮陰阻風寄呈楚州韋中丞','許渾','唐','唐诗','tang','','[]','垂釣京江欲白頭，江魚堪釣却西游。',64,'全唐诗/poet.tang.29000.json','["垂釣京江欲白頭，江魚堪釣却西游。", "劉伶臺下稻花晚，韓信廟前楓葉秋。", "淮月未明先倚檻，海雲初起更維舟。", "河橋有酒無人醉，獨上高城望庾樓。"]'),
('8ab08a25-3566-4685-bc84-135b01ff8b76','途經敷水','許渾','唐','唐诗','tang','','[]','脩蛾顰翠倚柔桑，遙謝春風白面郎。',64,'全唐诗/poet.tang.29000.json','["脩蛾顰翠倚柔桑，遙謝春風白面郎。", "五夜有情隨暮雨，百年無節待秋霜。", "重尋繡帶朱藤合，更認羅帬碧草長。", "何處野花何處水，下峰流出一渠香。"]'),
('56c90199-7634-48a5-8718-69c170939617','和人賀楊僕射致政','許渾','唐','唐诗','tang','','[]','蓮府公卿拜後塵，手持優詔挂朱輪。',64,'全唐诗/poet.tang.29000.json','["蓮府公卿拜後塵，手持優詔挂朱輪。", "從軍暮下三千客，聞禮庭中七十人。", "錦帳麗詞推北巷，畫堂清樂掩南鄰。", "豈同王謝山陰會，空敘流杯醉暮春。"]'),
('df76ec52-49a3-4754-b7d9-32134fe039dc','題四皓廟','許渾','唐','唐诗','tang','','[]','桂香松暖廟門開，獨瀉椒漿奠一杯。',64,'全唐诗/poet.tang.29000.json','["桂香松暖廟門開，獨瀉椒漿奠一杯。", "秦法欲興鴻已去，漢儲將廢鳳還來。", "紫芝翳翳多青草，白石蒼蒼半綠苔。", "山下驛塵南竄路，不知冠蓋幾人回。"]'),
('a8fd7fd1-7129-4704-9da4-39b0f585ff15','鶴林寺中秋夜翫月','許渾','唐','唐诗','tang','','[]','待月東林月正圓，廣庭無樹草無煙。',64,'全唐诗/poet.tang.29000.json','["待月東林月正圓，廣庭無樹草無煙。", "中秋雲盡出滄海，半夜露寒當碧天。", "輪彩漸移金殿外，鏡光猶挂玉樓前。", "莫辭達曙殷勤望，一墮西巖又隔年。"]'),
('72ad73af-d452-47f2-9aee-63d0a1926b17','南海府罷歸京口經大庾嶺贈張明府','許渾','唐','唐诗','tang','','[]','樓船旌斾極天涯，一劍從軍兩鬢華。',64,'全唐诗/poet.tang.29000.json','["樓船旌斾極天涯，一劍從軍兩鬢華。", "回日眼明河畔草，去時腸斷嶺頭花。", "陶詩盡寫行過縣，張賦初成臥到家。", "官滿知君有歸處，姑蘇臺上舊煙霞。"]'),
('79f3675d-ca4e-40e3-b4f4-e851c9eba61f','題衛將軍廟','許渾','唐','唐诗','tang','','[]','武牢關下護龍旗，挾槊彎弧馬上飛。',64,'全唐诗/poet.tang.29000.json','["武牢關下護龍旗，挾槊彎弧馬上飛。", "漢業未興王霸在，秦軍纔散魯連歸。", "墳穿大澤埋金劍，廟枕長溪挂鐵衣。", "欲奠忠魂何處問，葦花楓葉雨霏霏。"]'),
('e3a4e04f-e9d3-4333-964a-3c3146edad00','訪別韋隱居不值','許渾','唐','唐诗','tang','','[]','犬吠雙巖碧樹間，主人朝出半開關。',64,'全唐诗/poet.tang.29000.json','["犬吠雙巖碧樹間，主人朝出半開關。", "湯師閣上留詩別，杜叟橋邊載酒還。", "櫟塢炭煙晴過嶺，蓼村漁火夜移灣。", "故鄉蕪沒兵戈後，憑向溪南買一山。"]'),
('aea5b341-7410-48c7-9578-dabf5dc34e46','送前東陽于明府由鄂渚歸故林','許渾','唐','唐诗','tang','','[]','結束征車換黑貂，灞西風雨正瀟瀟。',64,'全唐诗/poet.tang.29000.json','["結束征車換黑貂，灞西風雨正瀟瀟。", "茂陵久病書千卷，彭澤初歸酒一瓢。", "帆背夕陽湓水闊，棹經滄海甑山遙。", "殷勤爲謝南溪客，白首螢窗未見招。"]'),
('7de37ff7-b0be-49c7-8266-0532cea36445','聽歌鷓鴣辭','許渾','唐','唐诗','tang','','[]','南國多情多豔詞，鷓鴣清怨遶梁飛。',64,'全唐诗/poet.tang.29000.json','["南國多情多豔詞，鷓鴣清怨遶梁飛。", "甘棠城上客先醉，苦竹嶺頭人未歸。", "響轉碧霄雲駐影，曲終清漏月沈暉。", "山行水宿不知遠，猶夢玉釵金縷衣。"]'),
('f309e84e-fe0a-464f-8f77-37fd3e63dc2e','寄題華嚴韋秀才院','許渾','唐','唐诗','tang','','[]','三面樓臺百丈峰，西巖高枕樹重重。',64,'全唐诗/poet.tang.29000.json','["三面樓臺百丈峰，西巖高枕樹重重。", "晴攀翠竹題詩滑，秋摘黃花釀酒濃。", "山殿日斜喧鳥雀，石潭波動戲魚龍。", "今來故國遙相憶，月照千山半夜鐘。"]'),
('f8fffc9d-a2e2-47e7-9aae-0f794790adda','戲代李協律松江有贈','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蜀客操琴吳女歌，明珠十斛是天河。',64,'全唐诗/poet.tang.29000.json','["蜀客操琴吳女歌，明珠十斛是天河。", "霜凝薜荔怯秋樹，露滴芙蓉愁晚波。", "蘭浦遠鄉應解珮，柳堤殘月未鳴珂。", "西樓沈醉不知散，潮落洞庭洲渚多。"]'),
('9b5586c1-bacb-4ffa-971a-47322ed6a974','送黃隱居歸南海','許渾','唐','唐诗','tang','','[]','瘴霧南邊久寄家，海中來往信流槎。',64,'全唐诗/poet.tang.29000.json','["瘴霧南邊久寄家，海中來往信流槎。", "林藏●●多殘笋，樹過猩猩少落花。", "深洞有雲龍蛻骨，半巖無草象生牙。", "知君愛宿層峰頂，坐到三更見日華。"]'),
('c8f07dd3-8ebc-41cc-bdbb-ca8e8777de12','朝臺送客有懷','許渾','唐','唐诗','tang','','[]','趙佗西拜已登壇，馬援南征土宇寬。',64,'全唐诗/poet.tang.29000.json','["趙佗西拜已登壇，馬援南征土宇寬。", "越國舊無唐印綬，蠻鄉今有漢衣冠。", "江雲帶日秋偏熱，海雨隨風夏亦寒。", "嶺北歸人莫回首，蓼花楓葉萬重灘。"]'),
('aea87c55-b0c8-40d1-8de9-42af0a04941a','自楞伽寺晨起汎舟道中有懷','許渾','唐','唐诗','tang','','[]','碧樹蒼蒼茂苑東，佳期迢遰路何窮。',64,'全唐诗/poet.tang.29000.json','["碧樹蒼蒼茂苑東，佳期迢遰路何窮。", "一聲山鳥曙雲外，萬點水螢秋草中。", "門掩竹齋微有月，棹移蘭渚淡無風。", "欲知此路堪惆悵，菱葉蓼花連故宮。"]'),
('37ebc5b7-0042-47f4-ba70-21fe5fb0e106','十二月拜起居表回','許渾','唐','唐诗','tang','','[]','一章西奏拜仙曹，回馬天津北望勞。',64,'全唐诗/poet.tang.29000.json','["一章西奏拜仙曹，回馬天津北望勞。", "寒水欲春冰彩薄，曉山初霽雪峰高。", "樓形向日攢飛鳳，宮勢凌波壓抃鼇。", "空鎖煙霞絕巡幸，周人誰識鬱金袍。"]'),
('b466b514-5cc0-43b7-ac2f-124e16a9717f','觀章中丞夜按歌舞','許渾','唐','唐诗','tang','','[]','夜按雙娃禁曲新，東西簫鼓接雲津。',64,'全唐诗/poet.tang.29000.json','["夜按雙娃禁曲新，東西簫鼓接雲津。", "舞衫未換紅鉛濕，歌扇初移翠黛顰。", "彩檻燭煙光吐日，畫屏香霧暖如春。", "西樓月在襄王醉，十二山高不見人。"]'),
('cdc8b6c6-510b-4fce-89bb-902748f76b09','重遊飛泉觀題故梁道士宿龍池','許渾','唐','唐诗','tang','','[]','西巖泉落水容寬，靈物蜿蜒黑處蟠。',64,'全唐诗/poet.tang.29000.json','["西巖泉落水容寬，靈物蜿蜒黑處蟠。", "松葉正秋琴韻響，菱花初曉鏡光寒。", "雲開星月浮山殿，雨過風雷遶石壇。", "仙客不歸龍亦去，稻畦長滿此池乾。"]'),
('cbe6c582-80c9-4c5d-9ccc-d4a9dd2cde6f','下第貽友人','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','身在關西家洞庭，夜寒歌苦燭熒熒。',64,'全唐诗/poet.tang.29000.json','["身在關西家洞庭，夜寒歌苦燭熒熒。", "人心高下月中桂，客思往來波上萍。", "馬氏識君眉最白，阮公留我眼長青。", "花前失意共寥落，莫遣東風吹酒醒。"]'),
('3636ccf3-83e5-4971-9515-ffbbe2076098','晚登龍門驛樓','許渾','唐','唐诗','tang','','[]','魚龍多處鑿門開，萬古人知夏禹材。',64,'全唐诗/poet.tang.29000.json','["魚龍多處鑿門開，萬古人知夏禹材。", "青嶂遠分從地斷，洪流高瀉自天來。", "風雲有路皆燒尾，波浪無程盡曝腮。", "心感膺門身過此，晚山秋樹獨徘徊。"]'),
('5b55d90d-c7cb-44c8-9af1-1815da24adb3','題故李秀才居','許渾','唐','唐诗','tang','','[]','曾醉笙歌日正遲，醉中相送易前期。',64,'全唐诗/poet.tang.29000.json','["曾醉笙歌日正遲，醉中相送易前期。", "橘花滿地人亡後，菰葉連天鴈過時。", "琴倚舊窗塵漠漠，劍埋新塚草離離。", "河橋酒熟平生事，更向東流奠一巵。"]'),
('715b7527-abf9-4f7f-bc9d-c7a8602722f1','韶州韶陽樓夜讌','許渾','唐','唐诗','tang','','[]','待月西樓捲翠羅，玉杯瑤瑟近星河。',64,'全唐诗/poet.tang.29000.json','["待月西樓捲翠羅，玉杯瑤瑟近星河。", "簾前碧樹窮秋密，窗外青山薄暮多。", "鸜鵒未知狂客醉，鷓鴣先讓美人歌。", "使君莫惜通宵飲，刀筆初從馬伏波。"]'),
('aa0d9975-9221-4550-86f8-6feecc7de0e5','聞韶州李相公移拜郴州因寄','許渾','唐','唐诗','tang','','[]','詔移丞相木蘭舟，桂水潺湲嶺北流。',64,'全唐诗/poet.tang.29000.json','["詔移丞相木蘭舟，桂水潺湲嶺北流。", "青漢夢歸雙闕曙，白雲吟過五湖秋。", "恩迴玉扆人先喜，道在金縢世不憂。", "聞說公卿盡南望，甘堂花暖鳳池頭。"]'),
('69f6930a-1b7f-442e-a8f9-3e49b9d6dc41','游江令舊宅','許渾','唐','唐诗','tang','','[]','身沒南朝宅已荒，邑人猶賞舊風光。',64,'全唐诗/poet.tang.29000.json','["身沒南朝宅已荒，邑人猶賞舊風光。", "芹根生葉石池淺，桐樹落花金井香。", "帶暖山蜂巢畫閣，欲陰溪燕集書堂。", "閑愁此地更西望，潮侵臺城春草長。"]'),
('d1fa5e04-8812-4be1-bfec-c6c46ee9b123','灞上逢元九處士東歸','許渾','唐','唐诗','tang','','[]','瘦馬頻嘶灞水寒，灞南高處望長安。',64,'全唐诗/poet.tang.29000.json','["瘦馬頻嘶灞水寒，灞南高處望長安。", "何人更結王生韤，此客虛彈貢氏冠。", "江上蟹螯沙渺渺，塢中蝸殻雪漫漫。", "舊交已變新知少，却伴漁郎把釣竿。"]'),
('77720722-e794-4784-af17-a45629f48ffc','別張秀才','許渾','唐','唐诗','tang','','[]','不知何計寫離憂，萬里山川半舊遊。',64,'全唐诗/poet.tang.29000.json','["不知何計寫離憂，萬里山川半舊遊。", "風捲暮沙和雪起，日融春水帶冰流。", "凌晨客淚分東郭，竟夕鄉心共北樓。", "青桂一枝年少事，莫因鱸鱠涉窮秋。"]'),
('6af20330-720f-421a-9053-fac494afe21f','別表兄軍倅','許渾','唐','唐诗','tang','','[]','盧橘花香拂釣磯，佳人猶舞越羅衣。',64,'全唐诗/poet.tang.29000.json','["盧橘花香拂釣磯，佳人猶舞越羅衣。", "三洲水淺魚來少，五嶺山高鴈到稀。", "客路晚依紅樹宿，鄉關朝望白雲歸。", "交親不念征南吏，昨夜風帆去似飛。"]'),
('2756ce65-b929-4076-8890-3edd27e5f2fa','題蘇州虎丘寺僧院','許渾','唐','唐诗','tang','','[]','暫引寒泉濯遠塵，此生多是異鄉人。',64,'全唐诗/poet.tang.29000.json','["暫引寒泉濯遠塵，此生多是異鄉人。", "荆溪夜雨花開疾，吳苑秋風月滿頻。", "萬里高低門外路，百年榮辱夢中身。", "世間誰似西林客，一臥煙霞四十春。"]'),
('2af6b992-2527-4dc6-afe4-ea147e6ae83e','酬郭少府先奉使巡澇見寄兼呈裴明府','許渾','唐','唐诗','tang','','[]','載書攜榼別池龍，十幅輕帆處處通。',64,'全唐诗/poet.tang.29000.json','["載書攜榼別池龍，十幅輕帆處處通。", "謝朓宅荒山翠裏，王敦城古月明中。", "江村夜漲浮天水，澤國秋生動地風。", "飽食鱠魚榜歸檝，待君琴酒醉陶公。"]'),
('80340874-0693-46e9-ae66-13a66ffbc102','出永通門經李氏莊','許渾','唐','唐诗','tang','','[]','飛軒危檻百花堂，朝讌歌鐘暮已荒。',64,'全唐诗/poet.tang.29000.json','["飛軒危檻百花堂，朝讌歌鐘暮已荒。", "中散獄成琴自怨，步兵廚廢酒猶香。", "風池宿鳥喧朱閣，雨砌秋螢拂畫梁。", "力保山河家又慶，秪應中令敵汾陽。"]'),
('bf806992-1df3-4e62-aab9-07f7d54f4d1d','漢水傷稼','許渾','唐','唐诗','tang','','[]','西北樓開四望通，殘霞成綺月懸弓。',64,'全唐诗/poet.tang.29000.json','["西北樓開四望通，殘霞成綺月懸弓。", "江村夜漲浮天水，澤國秋生動地風。", "高下綠苗千頃盡，新陳紅粟萬厫空。", "才微分薄憂何益，却欲回心學釣翁。"]'),
('fa80cf56-96c7-4b4d-b5c8-4932bd463d34','送王總下第歸丹陽','許渾','唐','唐诗','tang','','[]','秦樓心斷楚江湄，繫馬春風酒一巵。',64,'全唐诗/poet.tang.29000.json','["秦樓心斷楚江湄，繫馬春風酒一巵。", "汴水月明東下疾，練塘花發北來遲。", "青蕪定沒安貧處，黃葉應催獻賦詩。", "憑寄家書爲回報，舊鄉還有故人知。"]'),
('8f77823c-b072-4d3f-9a75-092270339072','南陽道中','許渾','唐','唐诗','tang','','[]','月斜孤館傍村行，野店高低帶古城。',64,'全唐诗/poet.tang.29000.json','["月斜孤館傍村行，野店高低帶古城。", "籬上曉花齋後落，井邊秋葉社前生。", "飢烏索哺隨雛叫，乳牸慵歸望犢鳴。", "荒草連天風動地，不知誰學武侯耕。"]'),
('6333f99b-7315-4c72-9e26-1abacd63737d','破北虜太和公主歸宮闕','許渾','唐','唐诗','tang','','[]','毳幕承秋極斷蓬，飄颻一劍黑山空。',64,'全唐诗/poet.tang.29000.json','["毳幕承秋極斷蓬，飄颻一劍黑山空。", "匈奴北走荒秦壘，貴主西還盛漢宮。", "定是廟謨傾種落，必知邊寇畏驍雄。", "恩霑殘類從歸去，莫使華人雜犬戎。"]'),
('c40b2a94-60bc-499b-b9ef-c05f20f3088c','李定言自殿院銜命歸闕拜員外郎遷右史因寄','許渾','唐','唐诗','tang','','[]','白筆南征變二毛，越山愁瘴海驚濤。',64,'全唐诗/poet.tang.29000.json','["白筆南征變二毛，越山愁瘴海驚濤。", "才歸龍尾含雞舌，更立螭頭運兔毫。", "閶闔欲開宮漏盡，冕旒初坐御香高。", "吳中舊侶君先貴，曾憶王祥與佩刀。"]'),
('7bc887f7-4db4-4fe3-b256-00bdfd813813','早秋韶陽夜雨','許渾','唐','唐诗','tang','','[]','宋玉含悽夢亦驚，芙蓉山響一猨聲。',64,'全唐诗/poet.tang.29000.json','["宋玉含悽夢亦驚，芙蓉山響一猨聲。", "陰雲迎雨枕先潤，夜電引雷窗暫明。", "暗惜水花飄廣檻，遠愁風葉下高城。", "西歸萬里未千里，應到故園春草生。"]'),
('d84c01f4-7bec-4af9-8115-f9c0488f02a8','將爲南行陪尚書崔公宴海榴堂','許渾','唐','唐诗','tang','','[]','朝讌華堂暮未休，幾人偏得謝公留。',64,'全唐诗/poet.tang.29000.json','["朝讌華堂暮未休，幾人偏得謝公留。", "風傳鼓角霜侵戟，雲捲笙歌月上樓。", "賓館盡開徐穉榻，客帆空戀李膺舟。", "謾誇書劍無知己，水遠山長步步愁。"]'),
('1b765a61-6bd5-4495-8656-e18b25d5f07f','贈王山人','許渾','唐','唐诗','tang','','[]','貰酒攜琴訪我頻，始知城市有閑人。',64,'全唐诗/poet.tang.29000.json','["貰酒攜琴訪我頻，始知城市有閑人。", "君臣藥在寧憂病，子母錢成豈患貧。", "年長每勞推甲子，夜寒初共守庚申。", "近來聞說燒丹處，玉洞桃花萬樹春。"]'),
('5e822a39-3f65-49b3-945c-3ce524349604','宣城崔大夫召聯句偶疾不獲赴因獻','許渾','唐','唐诗','tang','','[]','心慕知音命自拘，畫堂聞欲試吹竽。',64,'全唐诗/poet.tang.29000.json','["心慕知音命自拘，畫堂聞欲試吹竽。", "茂陵罷酒慙中聖，漳浦題詩怯大巫。", "鬐鬣幾年傷在藻，羽毛終日羨棲梧。", "還愁旅棹空歸去，楓葉荷花釣五湖。"]'),
('0206f6dc-bd9e-4493-970f-0cafc6182d06','贈鄭處士','許渾','唐','唐诗','tang','','[]','道傍年少莫矜誇，心在重霄鬢未華。',64,'全唐诗/poet.tang.29000.json','["道傍年少莫矜誇，心在重霄鬢未華。", "楊子可曾過北里，魯人何必敬東家。", "寒雲曉散千峰雪，暖雨晴開一逕花。", "且賣湖田釀春酒，與君書劍是生涯。"]'),
('1beb4e80-dac6-4601-9037-54d728c4742f','正元','許渾','唐','唐诗','tang','','[]','高揭雞竿闢帝閽，祥風微暖瑞雲屯。',64,'全唐诗/poet.tang.29000.json','["高揭雞竿闢帝閽，祥風微暖瑞雲屯。", "千官共削姦臣迹，萬國初銜聖主恩。", "宮殿雪華齊紫閣，關河春色到青門。", "華夷一軌人方泰，莫學論兵誤至尊。"]'),
('307680c8-bffb-452d-a569-92f95a985a6c','登尉佗樓','許渾','唐','唐诗','tang','','[]','劉項持兵鹿未窮，自乘黃屋島夷中。',64,'全唐诗/poet.tang.29000.json','["劉項持兵鹿未窮，自乘黃屋島夷中。", "南來作尉任囂力，北向稱臣陸賈功。", "簫鼓尚陳今世廟，旌旗猶鎮昔時宮。", "越人未必知虞舜，一奏薰弦萬古風。"]'),
('5de7e026-c57f-446b-96e5-76da05392c43','詔州驛樓宴罷','許渾','唐','唐诗','tang','','[]','簷外千帆背夕陽，歸心杳杳鬢蒼蒼。',64,'全唐诗/poet.tang.29000.json','["簷外千帆背夕陽，歸心杳杳鬢蒼蒼。", "嶺猨羣宿夜山靜，沙鳥獨飛秋水涼。", "露墮桂花棋局濕，風吹荷葉酒瓶香。", "主人不醉下樓去，月在南軒更漏長。"]'),
('1adcd8fe-d00a-4794-ba69-a36f0807c30a','和淮南王相公與賓僚同游瓜洲別業題舊書齋','許渾','唐','唐诗','tang','','[]','碧油紅斾想青衿，積雪窗前盡日吟。',64,'全唐诗/poet.tang.29000.json','["碧油紅斾想青衿，積雪窗前盡日吟。", "巢鶴去時雲樹老，臥龍歸處石潭深。", "道傍苦李猶垂實，城外甘棠已布陰。", "賓御莫辭巖下醉，武丁高枕待爲霖。"]'),
('87c548cc-0250-4e37-83e8-c72ad7d38bb5','送盧先輩自衡岳赴復州嘉禮二首 一','許渾','唐','唐诗','tang','','["\u957f\u6c5f"]','名振金閨步玉京，暫留滄海見高情。',64,'全唐诗/poet.tang.29000.json','["名振金閨步玉京，暫留滄海見高情。", "衆花盡處松千尺，羣鳥喧時鶴一聲。", "朱閣簟涼疎雨過，碧溪船動早潮生。", "離心不異西江水，直送征帆萬里行。"]'),
('bc45bbb9-48b7-47e0-b76e-c228dec705e5','送盧先輩自衡岳赴復州嘉禮二首 二','許渾','唐','唐诗','tang','','[]','湘南詩客海中行，鵬翅垂雲不自矜。',64,'全唐诗/poet.tang.29000.json','["湘南詩客海中行，鵬翅垂雲不自矜。", "秋水靜磨金鏡土，夜風寒結玉壺冰。", "萬重嶺嶠辭衡岳，千里山陂問竟陵。", "醉倚西樓人已遠，柳溪無浪月澄澄。"]'),
('96739c37-563c-4388-997b-021f963caaf1','哭楊攀處士','許渾','唐','唐诗','tang','','[]','先生憂道樂清貧，白髮終爲不仕身。',64,'全唐诗/poet.tang.29000.json','["先生憂道樂清貧，白髮終爲不仕身。", "嵇阮沒來無酒客，應劉亡後少詩人。", "山前月照荒墳曉，溪上花開舊宅春。", "昨夜回舟更惆悵，至今鐘磬滿南鄰。"]'),
('7a133e01-9bdb-4643-94f4-2ae5ee9e71d3','宿松江驛却寄蘇州一二同志','許渾','唐','唐诗','tang','','[]','候館人稀夜自長，姑蘇臺遠樹蒼蒼。',64,'全唐诗/poet.tang.29000.json','["候館人稀夜自長，姑蘇臺遠樹蒼蒼。", "江湖潮落高樓迥，河漢秋歸廣簟涼。", "月轉碧梧移鵲影，露低紅葉濕螢光。", "西園詩侶應多思，莫醉笙歌掩畫堂。"]'),
('d89b7239-db88-4797-85ba-3d44fe8e69d6','盧山人自巴蜀由湘潭歸茅山因贈','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','太乙靈方鍊紫荷，紫荷飛盡髪皤皤。',64,'全唐诗/poet.tang.29000.json','["太乙靈方鍊紫荷，紫荷飛盡髪皤皤。", "猨啼巫峽曉雲薄，鴈宿洞庭秋月多。", "導引豈如桃葉舞，步虛寧比竹枝歌。", "華陽舊隱莫歸去，水沒芝田生綠莎。"]'),
('d6d2ba3a-f3a7-479e-b4d7-705ef40659fc','潁州從事西湖亭讌餞','許渾','唐','唐诗','tang','','["\u897f\u6e56"]','西湖清宴不知回，一曲離歌酒一杯。',64,'全唐诗/poet.tang.29000.json','["西湖清宴不知回，一曲離歌酒一杯。", "城帶夕陽聞鼓角，寺臨秋水見樓臺。", "蘭堂客散蟬猶噪，桂檝人稀鳥自來。", "獨想征車過鞏洛，此中霜菊遶潭開。"]'),
('33a6b7e8-bb42-453c-a7f8-9be2693f18fd','瓜洲留別李詡','許渾','唐','唐诗','tang','','[]','泣玉三年一見君，白衣顦顇更離羣。',64,'全唐诗/poet.tang.29000.json','["泣玉三年一見君，白衣顦顇更離羣。", "柳堤惜別春潮落，花榭留歡夜漏分。", "孤館宿時風帶雨，遠帆歸處水連雲。", "悲歌曲盡莫重奏，心遶關河不忍聞。"]'),
('2d8f3075-99c5-41a3-ba13-67a91119a601','余謝病東歸王秀才見寄今潘秀才南櫂奉酬','許渾','唐','唐诗','tang','','[]','酷似牢之玉不如，落星山下白雲居。',64,'全唐诗/poet.tang.29000.json','["酷似牢之玉不如，落星山下白雲居。", "春耕旋搆金門客，夜學兼修玉府書。", "風掃碧雲迎鷙鳥，水還滄海養嘉魚。", "莫將年少輕時節，王氏家風在石渠。"]'),
('99d8f0c4-310a-4a90-a365-1b59cd3f0799','獻韶陽相國崔公','許渾','唐','唐诗','tang','','[]','一匱爲功極九層，康莊猶自劍稜稜。',64,'全唐诗/poet.tang.29000.json','["一匱爲功極九層，康莊猶自劍稜稜。", "舟回北渚經年泊，門接東山盡日登。", "萬國已聞傳玉璽，百官猶望啓金縢。", "賢臣會致唐虞世，獨倚江樓笑范增。"]'),
('8996f97b-e892-464e-82cd-d4243c29f2c6','郡齋夜坐寄舊鄉二姪','許渾','唐','唐诗','tang','','[]','千官奉職衮龍垂，旅臥淮陽鬢日衰。',64,'全唐诗/poet.tang.29000.json','["千官奉職衮龍垂，旅臥淮陽鬢日衰。", "三月已乖棠樹政，二年空負竹林期。", "樓侵白浪風來遠，城抱丹巖日到遲。", "長欲挂帆君莫笑，越禽花晚夢南枝。"]'),
('0fdf21e7-c157-41ed-92f7-ff05fb4085af','病間寄郡中文士','許渾','唐','唐诗','tang','','[]','盧橘含花處處香，老人依舊臥清漳。',64,'全唐诗/poet.tang.29000.json','["盧橘含花處處香，老人依舊臥清漳。", "心同客舍驚秋早，跡似僧齋厭夜長。", "風捲翠簾琴自響，露凝朱閣簟先涼。", "明朝欲醉文中彥，猶覺吟聲帶越鄉。"]'),
('0284d1c9-9be7-41a1-9d22-fc0a4e4b520a','賀少師相公致政','許渾','唐','唐诗','tang','','[]','六十懸車自古稀，我公年少獨忘機。',64,'全唐诗/poet.tang.29000.json','["六十懸車自古稀，我公年少獨忘機。", "門臨二室留侯隱，櫂倚三川越相歸。", "不擬優遊同陸賈，已回清白遺胡威。", "龍城鳳沼棠陰在，只恐歸鴻更北飛。"]'),
('4898ea89-d27c-441c-aa79-673c163c6ff6','題崔處士山居','許渾','唐','唐诗','tang','','[]','坐窮今古掩書堂，二頃湖田一半荒。',64,'全唐诗/poet.tang.29000.json','["坐窮今古掩書堂，二頃湖田一半荒。", "荆樹有花兄弟樂，橘林無實子孫忙。", "龍歸曉洞雲猶濕，麝過春山草自香。", "向夜欲歸心萬里，故園松月更蒼蒼。"]'),
('9e07c080-8f4d-44cf-9d59-5427832dadca','疾後與郡中羣公讌李秀才','許渾','唐','唐诗','tang','','[]','強留佳客讌王孫，巖上餘花落酒樽。',64,'全唐诗/poet.tang.29000.json','["強留佳客讌王孫，巖上餘花落酒樽。", "書院欲開蟲網戶，訟庭猶掩雀羅門。", "耳虛盡日疑琴癖，眼暗經秋覺鏡昏。", "莫引劉安倚西檻，夜來紅葉下江村。"]'),
('edb8d270-6674-43e3-8a3c-189365ea0ee6','晨起白雲樓寄龍興江準上人兼呈竇秀才','許渾','唐','唐诗','tang','','[]','茲樓今是望鄉臺，鄉信全稀曉鴈哀。',64,'全唐诗/poet.tang.29000.json','["茲樓今是望鄉臺，鄉信全稀曉鴈哀。", "山翠萬重當檻出，水華千里抱城來。", "東巖月在僧初定，南浦花殘客未回。", "欲弔靈均能賦否，秋風還有木蘭開。"]'),
('3e49f19d-ff9e-4084-a579-8e4402cc53bd','醼餞李員外','許渾','唐','唐诗','tang','','[]','病守江城眼暫開，昔年吳越共銜杯。',64,'全唐诗/poet.tang.29000.json','["病守江城眼暫開，昔年吳越共銜杯。", "膺舟出鎮虛陳榻，鄭履還京下隗臺。", "雲葉漸低朱閣掩，浪花初起畫檣回。", "心期解印同君醉，九曲池西望月來。"]'),
('816e9dc3-3f40-4290-b851-a447e7a8f973','詶錢汝州','許渾','唐','唐诗','tang','','[]','白雪多隨漢水流，謾勞旌斾晚悠悠。',64,'全唐诗/poet.tang.29000.json','["白雪多隨漢水流，謾勞旌斾晚悠悠。", "笙歌暗寫終年恨，臺榭潛消盡日憂。", "鳥散落花人自醉，馬嘶芳草客先愁。", "怪來雅韻清無敵，三十六峰當庾樓。"]'),
('5fc69cf4-3bc3-47b5-8600-8bd4cb5515e6','將歸姑蘇南樓餞送李明府','許渾','唐','唐诗','tang','','[]','無處登臨不繫情，一憑春酒醉高城。',64,'全唐诗/poet.tang.29000.json','["無處登臨不繫情，一憑春酒醉高城。", "暫移羅綺見山色，纔駐管弦聞水聲。", "花落西亭添別恨，柳陰南浦促歸程。", "前期迢遰今宵短，更倚朱闌待月明。"]'),
('47b0d54b-9f1c-4124-92d4-59f9312be617','和浙西從事劉三復送僧南歸','許渾','唐','唐诗','tang','','[]','楚客送僧歸故鄉，海門帆勢極瀟湘。',64,'全唐诗/poet.tang.29000.json','["楚客送僧歸故鄉，海門帆勢極瀟湘。", "碧雲千里暮愁合，白雪一聲春思長。", "滿院草花平講席，繞龕藤葉蓋禪牀。", "憐師不得隨師去，已戴儒冠事素王。"]'),
('4e3810b3-0ca1-40c8-a8d9-19156b51460a','送上元王明府赴任','許渾','唐','唐诗','tang','','[]','莫言名重懶驅雞，六代江山碧海西。',64,'全唐诗/poet.tang.29000.json','["莫言名重懶驅雞，六代江山碧海西。", "日照蒹葭明楚塞，煙分楊柳見隋堤。", "荒城樹暗沈書浦，舊宅花連罨畫溪。", "官滿定知歸未得，九重霄漢有丹梯。"]'),
('a803e904-ec95-442b-b8f3-4477f0c0ee9f','送沈卓少府任江都','許渾','唐','唐诗','tang','','[]','煬帝都城春水邊，笙歌夜上木蘭船。',64,'全唐诗/poet.tang.29000.json','["煬帝都城春水邊，笙歌夜上木蘭船。", "三千宮女自塗地，十萬人家如洞天。", "豔豔花枝官舍晚，重重雲影寺牆連。", "少年作尉須兢慎，莫向樓前墜馬鞭。"]'),
('7ee1895a-17b4-4e66-8377-308dc408d24c','酬邢杜二員外','許渾','唐','唐诗','tang','','[]','雪帶東風洗畫屏，客星懸處聚文星。',64,'全唐诗/poet.tang.29000.json','["雪帶東風洗畫屏，客星懸處聚文星。", "未歸嵩嶺暮雲碧，久別杜陵春草青。", "熊軾並驅因雀噪，隼旟齊駐是鴻冥。", "豈知京洛舊親友，夢繞潺湲江上亭。"]'),
('5a51dd2a-aa07-4658-9c14-17c686a47e4f','經故丁補闕郊居','許渾','唐','唐诗','tang','','[]','死酧知己道終全，波暖孤冰且自堅。',64,'全唐诗/poet.tang.29000.json','["死酧知己道終全，波暖孤冰且自堅。", "鵩上承塵纔一日，鶴歸華表已千年。", "風吹藥蔓迷樵徑，雨暗蘆花失釣船。", "四尺孤墳何處是，闔閭城外草連天。"]'),
('3c17bd85-8502-487c-8bf2-0fb87c33e3b8','陪宣城大夫崔公泛後池兼北樓讌二首 一','許渾','唐','唐诗','tang','','[]','陪汎芳池醉北樓，水花繁豔照膺舟。',64,'全唐诗/poet.tang.29000.json','["陪汎芳池醉北樓，水花繁豔照膺舟。", "亭臺陰合樹初晝，弦管韻高山欲秋。", "皆賀虢巖終選傅，自傷燕谷未逢鄒。", "昔時恩遇今能否，一尉滄洲已白頭。"]'),
('f47ae2fa-2bc3-488f-8bb8-fd2984a643ed','陪宣城大夫崔公泛後池兼北樓讌二首 二','許渾','唐','唐诗','tang','','[]','江上西來共鳥飛，翦荷浮汎似輕肥。',64,'全唐诗/poet.tang.29000.json','["江上西來共鳥飛，翦荷浮汎似輕肥。", "王珣作簿公曾喜，劉表爲邦客盡依。", "雲外軒窗通早景，風前簫鼓送殘暉。", "宛陵行樂金陵住，遙對家山未憶歸。"]'),
('89694013-f59f-42a4-be7d-d65a14196ccf','留別趙端公','許渾','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','海門征櫂赴龍瀧，暫寄華筵倒玉缸。',64,'全唐诗/poet.tang.29000.json','["海門征櫂赴龍瀧，暫寄華筵倒玉缸。", "簫鼓散時逢夜雨，綺羅分處下秋江。", "孤帆已過滕王閣，高榻留眠謝守窗。", "却願煙波阻風雪，待君同拜碧油幢。"]'),
('fd6f957f-ee7f-457a-a664-544531da50b1','寄陽陵處士','許渾','唐','唐诗','tang','','[]','舊隱青山紫桂陰，一書迢遰寄歸心。',64,'全唐诗/poet.tang.29000.json','["舊隱青山紫桂陰，一書迢遰寄歸心。", "謝公樓上晚花盛，楊子宅前春草深。", "吳岫雨來溪鳥浴，楚江雲暗嶺猨吟。", "野人寧憶滄洲畔，會待吹噓定至音。"]'),
('d4bfbf60-807d-4b5b-adb3-4850fccec952','與張道士同訪李隱君不遇','許渾','唐','唐诗','tang','','[]','千巖萬壑獨攜琴，知在陵陽不可尋。',64,'全唐诗/poet.tang.29000.json','["千巖萬壑獨攜琴，知在陵陽不可尋。", "去轍已平秋草遍，空齋長掩暮雲深。", "霜寒橡栗留山鼠，月冷菰蒲散水禽。", "唯有西鄰張仲蔚，坐來同愴別離心。"]'),
('dceaf0ae-da50-421e-8bf2-3f81c53bc475','聞州中有讌寄崔大夫兼簡邢羣評事','許渾','唐','唐诗','tang','','[]','簫管筵間列翠蛾，玉杯金液耀金波。',64,'全唐诗/poet.tang.29000.json','["簫管筵間列翠蛾，玉杯金液耀金波。", "池邊雨過飄帷幕，海上風來動綺羅。", "顏子巷深青草遍，庾君樓迥碧山多。", "甘心不及同年友，臥聽行雲一曲歌。"]'),
('3a5a14ae-2d4c-4761-8097-c4172980b419','寄殷堯藩先輩','許渾','唐','唐诗','tang','','[]','十載功名翰墨林，爲從知己信浮沈。',64,'全唐诗/poet.tang.29000.json','["十載功名翰墨林，爲從知己信浮沈。", "青山有雪諳松性，碧落無雲稱鶴心。", "帶月獨歸蕭寺遠，翫花頻醉庾樓深。", "思君一見如瓊樹，空把新詩盡日吟。"]'),
('8ba36582-927b-4654-b37f-d0d2de6cfb3f','贈河東虞押衙二首 一','許渾','唐','唐诗','tang','','[]','長劍高歌換素衣，君恩未報不言歸。',64,'全唐诗/poet.tang.29000.json','["長劍高歌換素衣，君恩未報不言歸。", "舊精鳥篆諳書體，新授龍韜識戰機。", "萬里往來征馬瘦，十年離別故人稀。", "生平志氣何人見，空上西樓望落暉。"]'),
('0388111a-99bc-4f44-8ec0-32290cb53e4e','贈河東虞押衙二首 二','許渾','唐','唐诗','tang','','[]','吳門風水各萍流，月滿花開懶獨遊。',64,'全唐诗/poet.tang.29000.json','["吳門風水各萍流，月滿花開懶獨遊。", "萬里山川分曉夢，四鄰歌管送春愁。", "昔年顧我長青眼，今日逢君盡白頭。", "莫向尊前更惆悵，古來投筆盡封侯。"]'),
('4d853097-278c-4891-8a3c-22f39c71b878','陵陽春日寄汝洛舊游','許渾','唐','唐诗','tang','','[]','百年身世似飄蓬，澤國移家疊嶂中。',64,'全唐诗/poet.tang.29000.json','["百年身世似飄蓬，澤國移家疊嶂中。", "萬里綠波魚戀釣，九重青漢鶴愁籠。", "西池水冷春巖雪，南浦花香曉樹風。", "縱倒芳尊心不醉，故人多在洛城東。"]'),
('75340376-04dc-4aaf-860c-86ddadba733c','酬杜補闕初春雨中舟次橫江喜裴郎中相迎見寄','許渾','唐','唐诗','tang','','[]','江館維舟爲庾公，暖波微淥雨濛濛。',64,'全唐诗/poet.tang.29000.json','["江館維舟爲庾公，暖波微淥雨濛濛。", "紅橋迤邐春巖下，朱斾聯翩曉樹中。", "柳滴圓波生細浪，梅含香豔吐輕風。", "郢歌莫問青山吏，魚在深池鳥在籠。"]'),
('04f84781-2c74-4eed-a4bc-c10457f14ed9','送張厚浙東謁丁常侍','許渾','唐','唐诗','tang','','[]','涼露清蟬柳陌空，故人遙指浙江東。',64,'全唐诗/poet.tang.29000.json','["涼露清蟬柳陌空，故人遙指浙江東。", "青山有雪松當澗，碧落無雲鶴出籠。", "齊唱離歌愁晚月，獨看征棹怨秋風。", "定知洛下聲名士，共說膺門得孔融。"]'),
('a8e7bfe1-cce1-4bf8-b300-ae465898f9f5','酬副使鄭端公見寄','許渾','唐','唐诗','tang','','[]','一日高名遍九州，玄珠仍向道中求。',64,'全唐诗/poet.tang.29000.json','["一日高名遍九州，玄珠仍向道中求。", "郢中白雪慙新唱，塗上青山憶舊遊。", "笙磬有文終易別，珠璣無價竟難酬。", "柳營迢遰江風闊，夜夜孤吟月下樓。"]'),
('be64b039-6c88-48d7-9e09-82d13654fceb','酬綿州于中丞使君見寄','許渾','唐','唐诗','tang','','[]','故人書信越襃斜，新意雖多舊約賒。',64,'全唐诗/poet.tang.29000.json','["故人書信越襃斜，新意雖多舊約賒。", "皆就一麾先去國，共謀三逕未還家。", "荆巫夜隔巴西月，鄢郢春連漢上花。", "半月離居猶悵望，可堪垂白各天涯。"]'),
('65d71f2c-3ca3-4972-ba5f-64bd528c3075','春早郡樓書事寄呈府中羣公','許渾','唐','唐诗','tang','','[]','兩鬢垂絲髪半霜，石城孤夢繞襄陽。',64,'全唐诗/poet.tang.29000.json','["兩鬢垂絲髪半霜，石城孤夢繞襄陽。", "鴛鴻幕裏蓮披檻，虎豹營中柳拂牆。", "畫舸欲行春水急，翠簾初捲暮山長。", "峴亭風起花千片，流入南湖盡日香。"]'),
('de53db97-52bf-48cb-a0d4-340e1e6ba8f1','元處士自洛歸宛陵山居見示詹事相公餞行之什因贈','許渾','唐','唐诗','tang','','[]','紫霄峰下絕韋編，舊隱相如結韈前。',64,'全唐诗/poet.tang.29000.json','["紫霄峰下絕韋編，舊隱相如結韈前。", "月落尚留東閤醉，風高還憶北窗眠。", "江城夜別瀟瀟雨，山檻晴歸漠漠煙。", "一頃豆花三頃竹，想應拋却釣魚船。"]'),
('fd74383b-d6a0-421a-ad3b-b7b837b436f4','送元晝上人歸蘇州兼寄張厚二首 一','許渾','唐','唐诗','tang','','[]','自卜閑居荆水頭，感時相別思悠悠。',64,'全唐诗/poet.tang.29000.json','["自卜閑居荆水頭，感時相別思悠悠。", "一樽酒盡青山暮，千里書回碧樹秋。", "深巷久貧知寂寞，小詩多病尚風流。", "晝公此去應相問，爲說沾巾憶舊遊。"]'),
('07b44017-861c-4383-9383-6fc6a284e535','送元晝上人歸蘇州兼寄張厚二首 二','許渾','唐','唐诗','tang','','[]','三年無事客吳鄉，南陌春園碧草長。',64,'全唐诗/poet.tang.29000.json','["三年無事客吳鄉，南陌春園碧草長。", "共醉八門回畫舸，獨還三徑掩書堂。", "前山雨過池塘滿，小院秋歸枕簟涼。", "經歲別離心自苦，何堪黃葉落清漳。"]'),
('73473f8c-8930-4b1b-805e-39058c3e5c45','送陸拾遺東歸','許渾','唐','唐诗','tang','','[]','獨振儒風遇盛時，紫泥初降世人知。',64,'全唐诗/poet.tang.29000.json','["獨振儒風遇盛時，紫泥初降世人知。", "文章報主非無意，書劍還家素有期。", "秋寺臥雲移棹晚，暮江乘月落帆遲。", "東歸自是緣清興，莫比商山詠紫芝。"]'),
('6fbfcea6-fdd6-449f-867a-31115ca512f4','湖南徐明府余之南鄰久不還家因題林館','許渾','唐','唐诗','tang','','[]','湘南官罷不歸來，高閣經年掩綠苔。',64,'全唐诗/poet.tang.29000.json','["湘南官罷不歸來，高閣經年掩綠苔。", "魚溢池塘秋雨過，鳥還洲島暮潮回。", "階前石穩棋終局，窗外山寒酒滿杯。", "借問先生獨何處，一籬疎菊又花開。"]'),
('bd8a4b00-617e-45d8-8d7a-8254f28c1efd','酬和杜侍御','許渾','唐','唐诗','tang','','[]','花時曾省杜陵遊，聞下書帷不舉頭。',64,'全唐诗/poet.tang.29000.json','["花時曾省杜陵遊，聞下書帷不舉頭。", "因過石城先訪戴，欲朝金闕暫依劉。", "征帆夜轉鸕鷀穴，騁騎春辭鸛雀樓。", "正把新詩望南浦，棹歌應是木蘭舟。"]'),
('d87d9f56-8560-40ae-9a95-1006100f0635','酬河中杜侍御重寄','許渾','唐','唐诗','tang','','[]','五色如絲下碧空，片帆還遶楚王宮。',64,'全唐诗/poet.tang.29000.json','["五色如絲下碧空，片帆還遶楚王宮。", "文章已變南山霧，羽翼應摶北海風。", "春雪預呈霜簡白，曉霞先染繡衣紅。", "十千沽酒留君醉，莫道歸心似轉蓬。"]'),
('af269292-808a-4710-ac33-0089d4cc4b61','寄獻三川守劉公 一','許渾','唐','唐诗','tang','','[]','三川歌頌徹咸秦，十二樓前侍從臣。',64,'全唐诗/poet.tang.29000.json','["三川歌頌徹咸秦，十二樓前侍從臣。", "休閉玉籠留鸑鷟，早開金埒縱麒麟。", "花深穉榻迎何客，月在膺舟醉幾人。", "自笑東風過寒食，茂陵寥落未知春。"]'),
('da333783-256b-458a-ad39-0698e596e9ed','寄獻三川守劉公 二','許渾','唐','唐诗','tang','','[]','半年三度轉蓬居，錦帳心闌羨隼旟。',64,'全唐诗/poet.tang.29000.json','["半年三度轉蓬居，錦帳心闌羨隼旟。", "老去自驚秦塞鴈，病來先憶楚江魚。", "長聞季氏千金諾，更望劉公一紙書。", "春雪未晴春酒貴，莫教愁殺馬相如。"]'),
('c92f5167-d1af-41bc-b92b-def9a469dcfe','送段覺之西蜀結婚','許渾','唐','唐诗','tang','','[]','詞賦名高身不閑，綵衣如錦度函關。',64,'全唐诗/poet.tang.29000.json','["詞賦名高身不閑，綵衣如錦度函關。", "鏡中鸞影胡威去，劍外花歸衛玠還。", "秋浪遠侵黃鶴嶺，暮雲遙斷碧雞山。", "時人若問西遊客，心在重霄鬢欲斑。"]'),
('d990f982-aca7-4915-83bb-72059b45f36a','長慶寺遇常州阮秀才','許渾','唐','唐诗','tang','','[]','高閣晴軒對一峰，毗陵書客此相逢。',64,'全唐诗/poet.tang.29000.json','["高閣晴軒對一峰，毗陵書客此相逢。", "晚收紅葉題詩遍，秋待黃花釀酒濃。", "山館日斜喧鳥雀，石潭波動戲魚龍。", "上方有路應知處，疎磬寒蟬樹幾重。"]'),
('52f5edfc-5afb-47dd-80a6-2aa8e679b3b4','贈閑師','許渾','唐','唐诗','tang','','[]','近日高僧更有誰，宛陵山下遇閑師。',64,'全唐诗/poet.tang.29000.json','["近日高僧更有誰，宛陵山下遇閑師。", "東林共許三乘學，南國爭傳五字詩。", "初到庾樓紅葉墜，夜投蕭寺碧雲隨。", "秋江莫惜題佳句，正是磷磷見底時。"]'),
('15e4cee1-9e6c-4ad7-acae-f21f07320c0c','東遊留別李叢秀才','許渾','唐','唐诗','tang','','[]','煩君沽酒強登樓，罷唱離歌說遠遊。',64,'全唐诗/poet.tang.29000.json','["煩君沽酒強登樓，罷唱離歌說遠遊。", "文字豈勞諸子重，風塵多幸故人憂。", "數程山路長侵夜，千里家書動隔秋。", "起憑欄干各垂淚，又驅羸馬向東州。"]'),
('a4df33db-e607-485e-bde9-902e47857293','竹林寺別友人','許渾','唐','唐诗','tang','','[]','騷人吟罷起鄉愁，暗覺年華似水流。',64,'全唐诗/poet.tang.29000.json','["騷人吟罷起鄉愁，暗覺年華似水流。", "花滿謝城傷共別，蟬鳴蕭寺喜同遊。", "前山月落杉松晚，深夜風清枕簟秋。", "明日分襟又何處，江南江北路悠悠。"]'),
('60303547-3ae7-4608-9fbd-7a2b1d3d7c71','送處士武君歸章洪山居','許渾','唐','唐诗','tang','','[]','形影無羣消息沈，登聞三擊血沾襟。',64,'全唐诗/poet.tang.29000.json','["形影無羣消息沈，登聞三擊血沾襟。", "皇綱一日開冤氣，青史千年重壯心。", "却望烏臺春樹老，獨歸蝸舍暮雲深。", "他時縱有徵書至，雪滿空山不可尋。"]'),
('ee56e25b-e97d-4a94-9116-0c3a74a42fa9','題義女亭','許渾','唐','唐诗','tang','','[]','身沒蘭閨道日明，郭南尋得舊池亭。',64,'全唐诗/poet.tang.29000.json','["身沒蘭閨道日明，郭南尋得舊池亭。", "詩人愁立暮山碧，賈客怨離秋草青。", "四望月沈疑掩鏡，兩簷花動認收屏。", "至今鄉里風猶在，借問誰傳義女銘。"]'),
('2635058f-3712-485b-a8bb-37b01a193cd6','吳門送振武李從事','許渾','唐','唐诗','tang','','[]','晚促離筵醉玉缸，伊州一曲淚雙雙。',64,'全唐诗/poet.tang.29000.json','["晚促離筵醉玉缸，伊州一曲淚雙雙。", "欲攜刀筆從新幕，更宿烟霞別舊窗。", "胡馬近秋侵紫塞，吳帆乘月下清江。", "嫖姚若許傳書檄，坐築三城看受降。"]'),
('61eb02b7-0955-41f3-8e89-99739cd129db','郊居春日有懷府中諸公幷柬王兵曹','許渾','唐','唐诗','tang','','[]','欲學漁翁釣艇新，濯纓猶惜九衢塵。',64,'全唐诗/poet.tang.29000.json','["欲學漁翁釣艇新，濯纓猶惜九衢塵。", "花前更謝依劉客，雪後空懷訪戴人。", "僧舍覆碁消白日，市樓賒酒過青春。", "一山桃杏同時發，誰似東風不厭貧。"]'),
('89735a19-c227-4556-84fe-71599e1eef96','同韋少尹傷故衛尉李少卿','許渾','唐','唐诗','tang','','[]','客醉更長樂未窮，似知身世一宵空。',64,'全唐诗/poet.tang.29000.json','["客醉更長樂未窮，似知身世一宵空。", "香街寶馬嘶殘月，暖閣佳人哭曉風。", "未捲繡筵朱閣上，已開塵席畫屏中。", "何須更賦山陽笛，寒月沈西水向東。"]'),
('992ae4d9-15a2-4f55-99ca-43d93875e85e','舟行早發廬陵郡郭寄滕郎中','許渾','唐','唐诗','tang','','[]','楚客停橈太守知，露凝丹葉自秋悲。',64,'全唐诗/poet.tang.29000.json','["楚客停橈太守知，露凝丹葉自秋悲。", "蟹螯只恐相如渴，鱸鱠應防曼倩飢。", "風捲曙雲飄角遠，雨昏寒浪挂帆遲。", "離心更羨高齋夕，巫峽花深醉玉巵。"]'),
('81548238-fab4-4640-a71c-77249bd3bd0a','聞邊將劉臯無辜受戮','許渾','唐','唐诗','tang','','[]','外監多假帝王尊，威脅偏裨勢不存。',64,'全唐诗/poet.tang.29000.json','["外監多假帝王尊，威脅偏裨勢不存。", "纔許誓心安玉壘，已傷傳首動金門。", "三千客裏寧無義，五百人中必有恩。", "却賴漢庭多烈士，至今猶自伏蒲輪。"]'),
('adacb016-80c1-43ec-8438-9bd8610aa4e6','送薛秀才南遊','許渾','唐','唐诗','tang','','[]','姑蘇城外柳初凋，同上江樓更寂寥。',64,'全唐诗/poet.tang.29000.json','["姑蘇城外柳初凋，同上江樓更寂寥。", "遶壁舊詩塵漠漠，對窗寒竹雨瀟瀟。", "憐君別路隨秋鴈，盡我離觴任晚潮。", "從此草玄應有處，白雲青嶂一相招。"]'),
('280875c7-9ec4-4d0e-9022-ecf6b1d67705','夜歸孤山寺却寄盧郎中','許渾','唐','唐诗','tang','','[]','青山有志路猶賒，心在琴書自憶家。',64,'全唐诗/poet.tang.29000.json','["青山有志路猶賒，心在琴書自憶家。", "醉別庾樓山色曉，夜歸蕭寺月光斜。", "落帆露濕回塘柳，別院風驚滿地花。", "他日此身須報德，莫言空愛舊烟霞。"]'),
('8a770979-4299-46a7-8b87-cbf54e2de6a9','贈桐廬房明府先輩','許渾','唐','唐诗','tang','','[]','帝城春榜謫靈仙，四海聲華二十年。',64,'全唐诗/poet.tang.29000.json','["帝城春榜謫靈仙，四海聲華二十年。", "闕下書功無後輩，卷中文字掩前賢。", "官閑每喜江山靜，道在寧憂雨露偏。", "自笑小儒非一鶚，亦趨門屏冀相憐。"]'),
('79551141-ba7a-4174-afa9-11ec1fb2ae79','甘露寺感事貽同志','許渾','唐','唐诗','tang','','[]','雲蔽長安路更賒，獨隨漁艇老天涯。',64,'全唐诗/poet.tang.29000.json','["雲蔽長安路更賒，獨隨漁艇老天涯。", "青山盡日尋黃絹，滄海經年夢絳紗。", "雪憤有期心自壯，報恩無處髪先華。", "東堂舊侶勤書劍，同出膺門是一家。"]'),
('0e30479e-6de0-492f-8b8b-60cb82165ffd','泛溪夜回寄道玄上人','許渾','唐','唐诗','tang','','[]','南郭煙光異世間，碧桃紅杏水潺潺。',64,'全唐诗/poet.tang.29000.json','["南郭煙光異世間，碧桃紅杏水潺潺。", "猨來近嶺獼猴散，魚下深潭翡翠閑。", "猶阻晚風停桂檝，欲乘春月訪松關。", "幾回策杖終難去，洞口雲歸不見山。"]'),
('6a24e4a8-7235-4b12-a713-4cb2d40e2cc4','客至','許渾','唐','唐诗','tang','','[]','得路逢津更俊才，可憐鞍馬照春來。',64,'全唐诗/poet.tang.29000.json','["得路逢津更俊才，可憐鞍馬照春來。", "殘花幾日小齋閉，大笑一聲幽抱開。", "袖拂碧溪寒繚繞，冠欹紅樹晚徘徊。", "相逢少別更堪恨，何必秋風江上臺。"]'),
('de60a434-7a6c-427d-b25e-5973eaf337c7','經李給事舊居','許渾','唐','唐诗','tang','','[]','歸作儒翁出致君，故山誰復有遺文。',64,'全唐诗/poet.tang.29000.json','["歸作儒翁出致君，故山誰復有遺文。", "漢庭使氣摧張禹，楚國懷憂送范雲。", "楓葉暗時迷舊宅，芳花落處認荒墳。", "朱弦一奏沈湘怨，風起寒波日欲曛。"]'),
('7b38e04f-ff49-45ee-8d98-246067381473','新興道中','許渾','唐','唐诗','tang','','[]','芙蓉村步失官金，折獄無功不可尋。',64,'全唐诗/poet.tang.29000.json','["芙蓉村步失官金，折獄無功不可尋。", "初挂海帆逢歲暮，却開山館值春深。", "波渾未辨魚龍跡，霧暗寧知蚌鷸心。", "夜榜歸舟望漁火，一溪風雨兩巖陰。"]'),
('7b462969-fc43-4e39-aee8-df9671c0312c','下第有懷親友','許渾','唐','唐诗','tang','','[]','萬山晴雪九衢塵，何處風光寄夢頻？',64,'全唐诗/poet.tang.29000.json','["萬山晴雪九衢塵，何處風光寄夢頻？", "花盛庾園攜酒客，草深顏巷讀書人。", "征帆又過湘南月，旅館還悲渭水春。", "無限別情多病後，杜陵寥落在漳濱。"]'),
('545dc6a4-3260-4440-b04d-d784288f4c7d','中秋夕寄大梁劉尚書','許渾','唐','唐诗','tang','','[]','汴人迎拜洛人留，虎豹旌旗擁碧油。',66,'全唐诗/poet.tang.29000.json','["汴人迎拜洛人留，虎豹旌旗擁碧油。", "[刁]斗嚴更軍耳目，戈鋋長控國咽喉。", "柳營出號風生纛，蓮幕題詩月上樓。", "應念散郎千里外，去年今夜醉蘭舟。"]'),
('8b012a42-9286-4620-9602-ba1231af33e6','臥病','許渾','唐','唐诗','tang','','[]','寒窗燈盡月斜暉，珮馬朝天獨掩扉。',64,'全唐诗/poet.tang.29000.json','["寒窗燈盡月斜暉，珮馬朝天獨掩扉。", "清露已凋秦塞柳，白雲空長越山薇。", "病中送客難爲別，夢裏還家不當歸。", "惟有寄書書未得，臥聞燕鴈向南飛。"]'),
('8f0d2f08-f56e-44e7-b169-9db09f396aa6','殘雪','許渾','唐','唐诗','tang','','[]','憶昨新春霰雪飛，堦前簷上鬬寒姿。',64,'全唐诗/poet.tang.29000.json','["憶昨新春霰雪飛，堦前簷上鬬寒姿。", "狂風送在竹深處，隔日未消花發時。", "輕壓嫩蔬旁出土，冷衝幽鳥別尋枝。", "晚來又喜登樓見，一曲高歌和者誰。"]'),
('1e4c7b5b-286c-4a4c-b41c-28f01f9854fd','和常秀才寄簡歸州鄭使君借猨','許渾','唐','唐诗','tang','','[]','謝守攜猨東路長，褭藤穿竹似瀟湘。',64,'全唐诗/poet.tang.29000.json','["謝守攜猨東路長，褭藤穿竹似瀟湘。", "碧山初鳴嘯秋月，紅樹生寒啼曉霜。", "陌上楚人皆駐馬，里中巴客半歸鄉。", "心知欲借南遊侶，未到三聲恐斷腸。"]'),
('ab08dd28-14cb-4e19-ad5c-5ee1475cc0f6','送人之任邛州','許渾','唐','唐诗','tang','','[]','綠髮監州丹府歸，還家樂事我先知。',64,'全唐诗/poet.tang.29000.json','["綠髮監州丹府歸，還家樂事我先知。", "羣童竹馬交迎日，二老蘭觴初見時。", "黃卷新書芸委積，青山舊路菊離披。", "亨衢自有橫飛勢，便到西垣視訓辭。"]'),
('8ed89f0f-c3ef-4368-b2ab-41a6e0dbb6a2','和河南楊少尹奉陪薛司空石笋詩','許渾','唐','唐诗','tang','','[]','暖溪寒井碧巖前，謝傅賓朋盛綺筵。',64,'全唐诗/poet.tang.29000.json','["暖溪寒井碧巖前，謝傅賓朋盛綺筵。", "雲斷石峰高竝笋，日臨山勢遠開蓮。", "閑留幢節低春水，醉擁笙歌出暮煙。", "聞道詩成歸已夕，柳風花露月初圓。"]'),
('d2779e5d-a0ee-4d06-8e64-39ab4d5d6b40','獻鄜坊丘常侍','許渾','唐','唐诗','tang','','[]','詔選將軍護北戎，身騎白馬臂彤弓。',64,'全唐诗/poet.tang.29000.json','["詔選將軍護北戎，身騎白馬臂彤弓。", "柳營遠識金貂貴，榆塞遙知玉帳雄。", "秋檻鼓鼙驚朔雪，曉階旗纛起邊風。", "蓬萊每望平安火，應奏班超定遠功。"]'),
('bb9a55e7-9256-4677-b699-ba051b47b4ff','寄當塗李遠','許渾','唐','唐诗','tang','','[]','賦擬相如詩似陶，雲陽烟月又同袍。',64,'全唐诗/poet.tang.29000.json','["賦擬相如詩似陶，雲陽烟月又同袍。", "車前驥病駑駘逸，架上鷹閑鳥雀高。", "舊日樂貧能飲水，他時隨俗願餔糟。", "不須倚向青山住，詠雪題詩用意勞。"]'),
('b44675aa-e4ad-4035-a190-bf500f535e59','和崔大夫新廣北樓登眺','許渾','唐','唐诗','tang','','[]','北望高樓夏亦寒，山重水闊接長安。',64,'全唐诗/poet.tang.29000.json','["北望高樓夏亦寒，山重水闊接長安。", "修梁暗換丹楹小，疎牖全開彩檻寬。", "風卷浮雲披睥睨，露涼明月墜闌干。", "庾公戀闕懷鄉處，目送歸帆下遠灘。"]'),
('b5cf9d4c-ef1c-4735-a1f6-8874a0363147','送客自兩河歸江南','許渾','唐','唐诗','tang','','[]','兩河庶事已堪傷，南客秋歸路更長。',64,'全唐诗/poet.tang.29000.json','["兩河庶事已堪傷，南客秋歸路更長。", "臺畔古松悲魏帝，苑邊脩竹弔梁王。", "山行露變茱萸色，水宿風披菡萏香。", "遙羨落帆逢舊友，綠蛾青鬢醉橫塘。"]'),
('5c6d9217-b2f8-48f5-afab-b3a225323e4e','題陸侍御林亭','許渾','唐','唐诗','tang','','[]','野水通池石疊臺，五營無事隱雄才。',64,'全唐诗/poet.tang.29000.json','["野水通池石疊臺，五營無事隱雄才。", "松齋下馬書千卷，蘭舫逢人酒一杯。", "寒樹雪晴紅豔吐，遠山雲曉翠光來。", "定知別後無多日，海柳江花次第開。"]'),
('b5c75d33-b0b2-4295-81e9-8a7504ac0b0b','泊蒜山津聞東林寺光儀上人物故','許渾','唐','唐诗','tang','','[]','雲齋曾宿借方袍，因說浮生大夢勞。',64,'全唐诗/poet.tang.29000.json','["雲齋曾宿借方袍，因說浮生大夢勞。", "言下是非齊虎尾，宿來榮辱比鴻毛。", "孤舟千棹水猶闊，寒殿一燈夜更高。", "明日東林有誰在，不堪秋磬拂煙濤。"]'),
('dd72a57b-767f-40ec-aa38-6acc90c327d4','春日思舊遊寄南徐從事劉三復','許渾','唐','唐诗','tang','','[]','風暖曲江花半開，忽思京口共銜杯。',64,'全唐诗/poet.tang.29000.json','["風暖曲江花半開，忽思京口共銜杯。", "湘潭雲盡暮山出，巴蜀雪消春水來。", "懷玉尚悲迷楚塞，捧金猶羨樂燕臺。", "薊門高處極歸思，隴鴈北飛雙燕迴。"]'),
('498ff761-8d92-40ec-9438-b74ceaed7b4b','郊園秋日寄洛中友人','許渾','唐','唐诗','tang','','[]','楚水西來天際流，感時傷別思悠悠。',64,'全唐诗/poet.tang.29000.json','["楚水西來天際流，感時傷別思悠悠。", "一尊酒盡青山莫，萬里書迴碧樹秋。", "日落遠波驚宿鴈，風吹輕浪起眠鷗。", "嵩陽親友如相問，潘岳閑居欲白頭。"]'),
('1a75c701-e7ec-453d-97dd-ba70181e07b5','送杜秀才歸桂林','許渾','唐','唐诗','tang','','[]','桂州南去與誰同，處處山連水自通。',64,'全唐诗/poet.tang.29000.json','["桂州南去與誰同，處處山連水自通。", "兩岸曉霞千里草，半帆斜日一江風。", "瘴雨欲來楓樹黑，火雲初起荔枝紅。", "愁君路遠銷年月，莫滯三湘五嶺中。"]'),
('a96ae6b8-8c3a-4218-b457-b8b777d1ad26','春雨舟中次和橫江裴使君見迎李趙二秀才同來因書四韻兼寄江南','許渾','唐','唐诗','tang','','[]','芳草渡頭微雨時，萬株楊柳拂波垂。',64,'全唐诗/poet.tang.29000.json','["芳草渡頭微雨時，萬株楊柳拂波垂。", "蒲根水暖鴈初落，梅徑香寒蜂未知。", "詞客倚風吹暗淡，使君迴馬濕旌旗。", "江南仲蔚多情調，悵望青雲幾首詩。"]'),
('471078c4-1f0a-4335-beef-82ed33e0b5c4','東陵赴京道病東歸寓居開元寺寄盧員外宋魏二先輩','許渾','唐','唐诗','tang','','[]','西風吹雨鴈初時，病寄僧齋罷獻書。',64,'全唐诗/poet.tang.29000.json','["西風吹雨鴈初時，病寄僧齋罷獻書。", "萬里咸秦勞我馬，四鄰松桂憶吾廬。", "滄洲有約心還靜，青漢無媒跡自疎。", "不是醉眠愁不散，莫言琴酒學相如。"]'),
('800459a9-3b15-4c28-bd7d-a4f0cbef09b7','聞開江宋相公申錫下世二首 一','許渾','唐','唐诗','tang','','[]','權門陰奏奪移才，馹騎如星墮峽來。',64,'全唐诗/poet.tang.29000.json','["權門陰奏奪移才，馹騎如星墮峽來。", "鼂氏有恩忠作禍，賈生無罪直爲災。", "貞魂誤向崇山歿，冤氣疑從汩水回。", "畢竟功成何處是，五湖雲月一帆開。"]'),
('dcb6cff0-b9dc-468c-bd3c-68207cd2f7cc','聞開江宋相公申錫下世二首 二','許渾','唐','唐诗','tang','','[]','月落湘潭棹不喧，玉杯瑤瑟奠蘋蘩。',64,'全唐诗/poet.tang.29000.json','["月落湘潭棹不喧，玉杯瑤瑟奠蘋蘩。", "誰能力制乘時鶴，自取機沈在檻猨。", "位極乾坤三事貴，謗興華夏一夫冤。", "宵衣旰食明天子，日伏青蒲不敢言。"]'),
('47020bcc-b367-4b8d-9f4c-ef4d92311916','贈所知','許渾','唐','唐诗','tang','','[]','因釣鱸魚住淛河，挂帆千里亦相過。',64,'全唐诗/poet.tang.29000.json','["因釣鱸魚住淛河，挂帆千里亦相過。", "茅簷夜醉平階月，蘭棹春歸拍岸波。", "湖日似陰鼉鼓響，海雲纔起蜃樓多。", "明時又作閑居賦，誰薦東門策四科。"]'),
('d5158f1e-b1fe-4b53-b379-792967a9cb44','謝人贈鞭','許渾','唐','唐诗','tang','','[]','蜀國名鞭見惠稀，駑駘從此長光輝。',64,'全唐诗/poet.tang.29000.json','["蜀國名鞭見惠稀，駑駘從此長光輝。", "獨根擁腫來雲岫，紫陌提攜在繡衣。", "幾度拂花香裏過，也曾敲𩍐月中歸。", "莫言三尺長無用，百萬軍中要指揮。"]'),
('d19937e9-56ce-4e0f-9744-5899a8d73a20','早秋寄劉尚書','許渾','唐','唐诗','tang','','[]','天生心識富人侯，將相門中第一流。',66,'全唐诗/poet.tang.29000.json','["天生心識富人侯，將相門中第一流。", "旗纛早開擒虎帳，戈[鋋]初發斬鯨舟。", "柳營書號海山暝，菌閣賦詩江樹秋。", "昨夜雨涼今夜月，笙歌應醉最高樓。"]'),
('dc1d76f5-fac3-4c38-859c-18c33f071b7e','及第後春情','許渾','唐','唐诗','tang','','[]','世間得意是春風，散誕經過觸處通。',64,'全唐诗/poet.tang.29000.json','["世間得意是春風，散誕經過觸處通。", "細搖柳臉牽長帶，慢撼桃株舞碎紅。", "也從吹幌驚殘夢，何處飄香別故叢？", "猶以西都名下客，今年一月始相逢。"]'),
('56db2c39-3151-46eb-979b-bc83bda14daf','歸長安','許渾','唐','唐诗','tang','','[]','三年何處淚汍瀾，白帝城邊曉角殘。',64,'全唐诗/poet.tang.29000.json','["三年何處淚汍瀾，白帝城邊曉角殘。", "非是無心戀巫峽，自緣□臂到長安。", "黔江水暖還曾飲，楚岫雲深不識寒。", "大抵莫教聞雨後，此時腸斷不應難。"]'),
('65ea21f5-cf90-4931-8ba0-edf0b1a9e8ba','經古行宮','許渾','唐','唐诗','tang','','[]','臺閣參差倚太陽，年年花發滿山香。',64,'全唐诗/poet.tang.29000.json','["臺閣參差倚太陽，年年花發滿山香。", "重門堪鎖青春晚，深院垂簾白晝長。", "草色芊綿侵御路，泉聲嗚咽繞宮牆。", "先皇一去無迴駕，紅粉雲鬟空斷腸。"]'),
('fbc7e327-1e4e-497e-8287-020b100770ed','秋晚懷茅山石涵村舍','許渾','唐','唐诗','tang','','[]','十畝山田近石涵，村居風俗舊曾諳。',64,'全唐诗/poet.tang.29000.json','["十畝山田近石涵，村居風俗舊曾諳。", "簾前白艾驚春燕，籬上青桑待晚蠶。", "雲暖採茶來嶺北，月明沽酒過溪南。", "陵陽秋盡多歸思，紅樹蕭蕭覆碧潭。"]'),
('bcee5cb9-8093-4ec0-ad9c-53cfcc717292','貴游','許渾','唐','唐诗','tang','','[]','朝回佩馬早淒淒，年少恩深衛霍齊。',64,'全唐诗/poet.tang.29000.json','["朝回佩馬早淒淒，年少恩深衛霍齊。", "斧鉞舊威龍塞北，池臺新賜鳳城西。", "門通碧樹開金鎖，樓對青山倚玉梯。", "南陌行人盡回首，笙歌一曲暮雲低。"]'),
('243bebda-5020-47a7-ba9f-80d46e1ea847','贈別','許渾','唐','唐诗','tang','','[]','眼前迎送不曾休，相續輪蹄似水流。',64,'全唐诗/poet.tang.29000.json','["眼前迎送不曾休，相續輪蹄似水流。", "門外若無南北路，人間應免別離愁。", "蘇秦六印歸何日，潘岳雙毛去值秋。", "莫怪分襟銜淚語，十年耕釣憶滄洲。"]'),
('9d654c12-b466-4236-86fd-ea22bc62f0b7','秋夜與友人宿','許渾','唐','唐诗','tang','','[]','楚國同游過十霜，萬重心事幾堪傷。',64,'全唐诗/poet.tang.29000.json','["楚國同游過十霜，萬重心事幾堪傷。", "蒹葭露白蓮塘淺，砧杵夜清河漢涼。", "雲外山川歸夢遠，天涯岐路客愁長。", "塞城欲曉聞吹笛，猶臥東軒月滿牀。"]'),
('76f35975-4f72-491f-a6a2-4deaf25a9439','將赴京留贈僧院','許渾','唐','唐诗','tang','','[]','九衢塵土遞追攀，馬跡軒車日暮間。',64,'全唐诗/poet.tang.29000.json','["九衢塵土遞追攀，馬跡軒車日暮間。", "玄髪盡驚爲客換，白頭曾見幾人閑。", "空悲浮世雲無定，多感流年水不還。", "謝却從前受恩地，歸來依止叩禪關。"]'),
('cd9871b5-c027-48b8-8617-e9dc38134f92','寄湘中友人','許渾','唐','唐诗','tang','','[]','莫戀醉鄉迷酒杯，流年長怕老年催。',64,'全唐诗/poet.tang.29000.json','["莫戀醉鄉迷酒杯，流年長怕老年催。", "西陵水闊魚難到，南國路遙書未回。", "匹馬計程愁日盡，一蟬何事引秋來。", "相如已定題橋志，江上無由夢釣臺。"]'),
('194bda4e-ebea-47c6-ad2d-52f6e72f5ae4','江上逢友人','許渾','唐','唐诗','tang','','[]','故國歸人酒一杯，暫停蘭棹共徘徊。',64,'全唐诗/poet.tang.29000.json','["故國歸人酒一杯，暫停蘭棹共徘徊。", "村連三峽暮雲起，潮送九江寒雨來。", "已作相如投賦計，還憑殷浩寄書回。", "到時若見東籬菊，爲問經霜幾度開。"]'),
('74cf74fc-2b58-4a5f-97bb-0a38dcb3f446','金谷懷古','許渾','唐','唐诗','tang','','[]','淒涼遺跡洛川東，浮世榮枯萬古同。',64,'全唐诗/poet.tang.29000.json','["淒涼遺跡洛川東，浮世榮枯萬古同。", "桃李香銷金谷在，綺羅魂斷玉樓空。", "往年人事傷心外，今日風光屬夢中。", "□□□□□□□，□□□□□□□。"]'),
('6928b5f1-e683-406d-8c61-7ef93fce7090','經行廬山東林寺','許渾','唐','唐诗','tang','','["\u5e90\u5c71"]','離魂斷續楚江壖，葉墜初紅十月天。',64,'全唐诗/poet.tang.29000.json','["離魂斷續楚江壖，葉墜初紅十月天。", "紫陌事多難數悉，青山長在好閑眠。", "方趨上國期干祿，未得空堂學坐禪。", "他歲若教如范蠡，也應須入五湖煙。"]'),
('a3c5e473-825c-484a-8074-18a549f9ec29','途中逢故人話西山讀書早曾游覽','許渾','唐','唐诗','tang','','[]','西巖曾到讀書堂，穿竹行沙十里強。',64,'全唐诗/poet.tang.29000.json','["西巖曾到讀書堂，穿竹行沙十里強。", "湖上夢餘波灩灩，嶺頭愁斷路茫茫。", "經過事寄煙霞遠，名利塵隨日月長。", "莫道少年頭不白，君看潘岳幾莖霜。"]'),
('b51cf31a-cc2e-45b8-9843-0759538e03db','將赴京題陵陽王氏水居','許渾','唐','唐诗','tang','','[]','簾捲平蕪接遠天，暫寬行役到尊前。',64,'全唐诗/poet.tang.29000.json','["簾捲平蕪接遠天，暫寬行役到尊前。", "是非境裏有閑日，榮辱塵中無了年。", "山簇暮雲千野雨，江分秋水九條煙。", "馬蹄不道貪西去，爭向一聲高樹蟬。"]'),
('2645d81c-e7c0-4693-b3c7-bccbbff58c17','冬日五浪館水亭懷別','許渾','唐','唐诗','tang','','[]','蘆荻花多觸處飛，獨憑虛檻雨微微。',64,'全唐诗/poet.tang.29000.json','["蘆荻花多觸處飛，獨憑虛檻雨微微。", "寒林葉落鳥巢出，古渡浪高魚艇稀。", "雲抱四山終日在，草荒三徑幾時歸。", "江城向暝東風急，一半鄉愁聞擣衣。"]'),
('73a98d35-21df-4623-8f7d-35b8c26caf98','送別','許渾','唐','唐诗','tang','','[]','溪邊楊柳色參差，攀折年年贈別離。',64,'全唐诗/poet.tang.29000.json','["溪邊楊柳色參差，攀折年年贈別離。", "一片風帆望已極，三湘煙水返何時？", "多緣去棹將愁遠，猶倚危樓欲下遲。", "莫殢酒杯閑過日，碧雲深處是佳期。"]'),
('36b114b0-5eb3-4167-82df-539143815797','寄遠','許渾','唐','唐诗','tang','','[]','兩葉愁眉愁不開，獨含惆悵上層臺。',64,'全唐诗/poet.tang.29000.json','["兩葉愁眉愁不開，獨含惆悵上層臺。", "碧雲空斷鴈行處，紅葉已凋人未來。", "塞外音書無信息，道傍車馬起塵埃。", "功名待寄凌烟閣，力盡遼城不肯回。"]'),
('cf0976a1-a812-4a23-8351-278e20c77e55','新柳','許渾','唐','唐诗','tang','','[]','無力搖風曉色新，細腰爭妒看來頻。',64,'全唐诗/poet.tang.29000.json','["無力搖風曉色新，細腰爭妒看來頻。", "綠陰未覆長堤水，金穗先迎上苑春。", "幾處傷心懷遠路，一枝和日送行塵。", "東□門外多離別，愁殺朝朝暮暮人。"]'),
('555f9e74-ec5f-42a3-be1f-d669a4b08f55','旅懷作','許渾','唐','唐诗','tang','','[]','促促因吟晝短詩，朝驚穠色暮空枝。',64,'全唐诗/poet.tang.29000.json','["促促因吟晝短詩，朝驚穠色暮空枝。", "無情春色不長久，有限年光多盛衰。", "往事只應隨夢裏，勞生何處是閑時。", "眼前擾擾日一日，暗送白頭人不知。"]'),
('b31b2b15-a6a6-4614-8f7c-70af0c4b9a95','鴈','許渾','唐','唐诗','tang','','[]','萬里銜蘆別故鄉，雲飛水宿向瀟湘。',64,'全唐诗/poet.tang.29000.json','["萬里銜蘆別故鄉，雲飛水宿向瀟湘。", "數聲孤枕堪垂淚，幾處高樓欲斷腸。", "度日翩翩斜避影，臨風一一直成行。", "年年辛苦來衡岳，羽翼摧殘隴塞霜。"]'),
('bb4e987f-a755-4a95-ae4a-4ed6fdbb5c60','出關','許渾','唐','唐诗','tang','','[]','朝纓初解佐江濱，麋鹿心知自有羣。',64,'全唐诗/poet.tang.29000.json','["朝纓初解佐江濱，麋鹿心知自有羣。", "漢囿獵稀慵獻賦，楚山耕早任移文。", "臥歸漁浦月連海，行望鳳城花隔雲。", "關吏不須迎馬笑，去時無意學終軍。"]'),
('d1da88c9-ff35-4efc-a94a-3dd3db72548c','寄房千里博士','許渾','唐','唐诗','tang','','[]','春風白馬紫絲韁，正值蠶眠未採桑。',64,'全唐诗/poet.tang.29000.json','["春風白馬紫絲韁，正值蠶眠未採桑。", "五夜有心隨暮雨，百年無節待秋霜。", "重尋繡帶朱藤合，更認羅裙碧草長。", "爲報西遊減離恨，阮郎纔去嫁劉郎。"]'),
('bd8c31b2-bd05-4db4-8857-ba6c160d6f9d','泛五雲溪','許渾','唐','唐诗','tang','','[]','此溪何處路，遙問白髯翁。',72,'全唐诗/poet.tang.29000.json','["此溪何處路，遙問白髯翁。", "佛廟千巖裏，人家一島中。", "魚傾荷葉露，蟬噪柳林風。", "急瀨鳴車軸，微波漾釣筒。", "石苔縈棹綠，山果拂舟紅。", "更就千村宿，溪橋與剡通。"]'),
('e8c58d42-53a2-40c0-91dd-cef51c70e3db','寄郴州李相公','許渾','唐','唐诗','tang','','[]','高樓王與謝，逸韻比南金。',96,'全唐诗/poet.tang.29000.json','["高樓王與謝，逸韻比南金。", "不遇銷憂日，埃塵誰復尋。", "曠懷澹得喪，失意縱登臨。", "彩檻浮雲迥，綺窗明月深。", "虯龍壓滄海，鴛鴦思鄧林。", "青雲傷國器，白髮軫鄉心。", "功高恩自洽，道直謗徒侵。", "應笑靈均恨，江畔獨行吟。"]'),
('c1c42b46-54f6-4dc0-97c1-0c740c9c7ec9','贈蕭鍊師','許渾','唐','唐诗','tang','','[]','曾試昭陽曲，瑤齋帝自臨。',240,'全唐诗/poet.tang.29000.json','["曾試昭陽曲，瑤齋帝自臨。", "紅珠絡繡帽，翠鈿束羅襟。", "雙闕胡塵起，千門宿露陰。", "出宮迷國步，回駕軫皇心。", "桂殿春空晚，椒房夜自深。", "急宣求故劒，冥契得遺簪。", "暗記神仙傳，潛封女史箴。", "壺中知日永，掌上畏年侵。", "莫比班家扇，寧同卓氏琴。", "雲車辭鳳輦，羽帔別鴛衾。", "網斷魚遊藻，籠開鶴戲林。", "洛煙浮碧漢，嵩月上丹岑。", "露草爭三秀，風篁共八音。", "吹笙延鶴舞，敲磬引龍吟。", "旄節纖腰舉，霞杯皓腕斟。", "還磨照寶鏡，猶插辟寒金。", "東海人情變，南山聖壽沈。", "朱顏常似渥，綠髪已如尋。", "養氣齊生死，留形盡古今。", "更求應不見，雞犬日駸駸。"]'),
('2b55e673-26f6-4c1b-bde3-ae7a06d67698','冬日宣城開元寺贈元孚上人','許渾','唐','唐诗','tang','','[]','一鉢事南宗，僧儀稱病容。',240,'全唐诗/poet.tang.29000.json','["一鉢事南宗，僧儀稱病容。", "曹溪花裏別，蕭寺竹前逢。", "燭影深寒殿，經聲徹曙鐘。", "欲齋簷睡鴿，初定壁吟蛩。", "詩繼休遺韻，書傳永逸蹤。", "藝多人譽洽，機絕道情濃。", "汲澗瓶沈藻，眠堦錫挂松。", "雲鳴新放鶴，池臥舊降龍。", "露茗山廚焙，霜秔野碓舂。", "梵文明處譯，禪衲暖時縫。", "層塔題應遍，飛軒步不慵。", "繡梁交薜荔，畫井倒芙蓉。", "翠戶垂旗網，朱窗列劒鋒。", "寒風金磬遠，晴雪玉樓重。", "妙理三乘達，清才萬象供。", "山高橫睥睨，灘淺聚艨艟。", "微霧蒼平楚，殘暉淡遠峰。", "林疎霜摵摵，波靜月溶溶。", "劒出因雷煥，琴全遇蔡邕。", "西方知有社，支許合相從。"]'),
('a4317b99-3ac8-476f-a825-b3eb745b1006','維舟秦淮過溫州李給事宅','許渾','唐','唐诗','tang','','[]','給事爲郎日，青溪醉隱銜。',120,'全唐诗/poet.tang.29000.json','["給事爲郎日，青溪醉隱銜。", "冰池通極浦，雪逕遶高巖。", "珠玉砂同棄，松筠草共芟。", "帝圖憂一失，臣節恥三緘。", "代有王陵戇，時無靳尚讒。", "定應標直筆，寧爲發空函。", "霧黑連雲棧，風狂截海帆。", "石梯迎雨潤，沙井待潮鹹。", "蠟屐青筇杖，藍輿白罽衫。", "應勞北歸夢，山路正巉巉。"]'),
('d1dc5bd7-2fe5-4341-81e5-b9d2a3e4a336','登蒜山觀發軍','許渾','唐','唐诗','tang','','[]','羽檄徵兵急，轅門選將雄。',120,'全唐诗/poet.tang.29000.json','["羽檄徵兵急，轅門選將雄。", "犬羊憂破竹，貔虎極飛蓬。", "定繫猖狂虜，何煩矍鑠翁。", "更探黃石略，重振黑山功。", "別馬嘶營柳，驚烏散井桐。", "低星連寶劍，殘月讓雕弓。", "浪曉戈鋋裏，山晴鼓角中。", "甲開魚照水，旗颺虎拏風。", "去想金河遠，行知玉塞空。", "漢庭應有問，師律在元戎。"]'),
('d4045d99-2c15-4797-9d52-637f5d70c11b','送從兄別駕歸蜀','許渾','唐','唐诗','tang','','[]','聞與湘南令，童年侍玉墀。',120,'全唐诗/poet.tang.29000.json','["聞與湘南令，童年侍玉墀。", "家留秦塞曲，官謫瘴溪湄。", "道直姦臣屏，冤深聖主知。", "逝川東去疾，霈澤北來遲。", "青漢龍髯絕，蒼岑馬鬣移。", "風淒聞笛處，月慘罷琴時。", "客路黃公廟，鄉關白帝祠。", "已稱鸚鵡賦，寧誦鶺鴒詩。", "遠道書難達，長亭酒莫持。", "當憑蜀江水，萬里寄相思。"]'),
('4cb80b1d-05c5-4ce1-aac2-cd50be0f795d','金陵阻風登延祚閣','許渾','唐','唐诗','tang','','[]','極目皆陳迹，披圖問遠公。',96,'全唐诗/poet.tang.29000.json','["極目皆陳迹，披圖問遠公。", "戈鋋三國後，冠蓋六朝中。", "葛蔓交殘壘，芒花沒後宮。", "水流簫鼓絕，山在綺羅空。", "極浦千艘聚，高臺一徑通。", "雲移吳岫雨，潮轉楚江風。", "登閣慙漂梗，停舟憶斷蓬。", "歸期與歸路，杉桂海門東。"]'),
('ceceb959-5df2-42d6-a3e1-52346582a259','送林處士自閩中道越由霅抵兩川','許渾','唐','唐诗','tang','','[]','書劒少青眼，煙波初白頭。',96,'全唐诗/poet.tang.29000.json','["書劒少青眼，煙波初白頭。", "鄉關背梨嶺，客路轉蘋洲。", "處困道難固，乘時恩易酬。", "鏡中非訪戴，劒外欲依劉。", "高枕海天暝，落帆江雨秋。", "鼉聲應遠鼓，蜃氣學危樓。", "智士役千慮，達人經百憂。", "唯聞陶靖節，多在醉鄉遊。"]'),
('8938a98a-d140-4c87-8f4c-bc8b7a14e428','宣城贈蕭兵曹','許渾','唐','唐诗','tang','','[]','桂檝謫湘渚，三年波上春。',96,'全唐诗/poet.tang.29000.json','["桂檝謫湘渚，三年波上春。", "舟寒剡溪雪，衣破洛城塵。", "客道恥搖尾，皇恩寬犯鱗。", "花時去國遠，月夕上樓頻。", "貪酒不辭病，傭書非爲貧。", "行吟值漁父，坐隱對樵人。", "紫陌罷雙轍，碧潭窮一綸。", "高歌更南去，煙水是通津。"]'),
('3af556b9-f9b8-4d73-afcb-ab5011717a57','秋夕宴李侍御宅','許渾','唐','唐诗','tang','','[]','公子徵詞客，秋堂遞玉杯。',96,'全唐诗/poet.tang.29000.json','["公子徵詞客，秋堂遞玉杯。", "月高羅幕卷，風度錦屏開。", "鳳管添簧品，鵾弦促柱哀。", "轉喉雲旋合，垂手露徐來。", "燭換三條燼，香銷十炷灰。", "蛩聲聞鼓歇，螢燄觸簾回。", "廣檻煙分柳，空庭露積苔。", "解酲須滿酌，應爲撥新醅。"]'),
('4a84cd5f-662d-44c7-b931-96c8424e8783','晨自竹徑至龍興寺崇隱上人院','許渾','唐','唐诗','tang','','[]','佛寺通南徑，僧堂倚北坡。',96,'全唐诗/poet.tang.29000.json','["佛寺通南徑，僧堂倚北坡。", "藤陰迷晚竹，苔滑仰晴莎。", "病憶春前別，閑宜雨後過。", "石橫聞水遠，林缺見山多。", "欲結三天社，初降十地魔。", "毒龍來有窟，靈鶴去無窠。", "客路隨萍梗，鄉園失薜蘿。", "禪心如可學，不藉魯陽戈。"]'),
('1e2a847a-b1a0-4626-9a35-b2fd83f36e03','歲暮自廣江至新興往復中題峽山寺四首 一','許渾','唐','唐诗','tang','','[]','夜醉晨方醒，孤吟恐失羣。',72,'全唐诗/poet.tang.29000.json','["夜醉晨方醒，孤吟恐失羣。", "海鰌潮上見，江鵠霧中聞。", "未臘梅先實，經冬草自薰。", "樹隨山崦合，泉到石稜分。", "虎跡空林雨，猨聲絕嶺雲。", "蕭蕭異鄉鬢，明日共絲棼。"]'),
('6ce95734-7eb6-40aa-a0d5-6e027bcfd08b','歲暮自廣江至新興往復中題峽山寺四首 二','許渾','唐','唐诗','tang','','[]','薄暮緣西峽，停橈一訪僧。',72,'全唐诗/poet.tang.29000.json','["薄暮緣西峽，停橈一訪僧。", "鷺巢橫臥柳，猨飲倒垂藤。", "水曲巖千疊，雲重樹百層。", "山風寒殿磬，溪雨夜船燈。", "灘漲危槎沒，泉衝怪石崩。", "中臺一襟淚，歲杪別良朋。"]'),
('ebcbe812-820c-4cc2-961e-f126020353d3','歲暮自廣江至新興往復中題峽山寺四首 三','許渾','唐','唐诗','tang','','[]','密樹分蒼壁，長溪抱碧岑。',60,'全唐诗/poet.tang.29000.json','["密樹分蒼壁，長溪抱碧岑。", "海風聞鶴遠，潭日見魚深。", "松蓋環清韵，榕根架綠陰。", "洞丁多斵石，蠻女半淘金。", "南浦驚春至，西樓送月沈。"]'),
('89450ca6-ce2b-474a-9da8-4c6c6f83d991','歲暮自廣江至新興往復中題峽山寺四首 四','許渾','唐','唐诗','tang','','[]','月在行人起，千峰復萬峰。',72,'全唐诗/poet.tang.29000.json','["月在行人起，千峰復萬峰。", "海虛爭翡翠，溪邏鬬芙蓉。", "古木高生槲，陰池滿種松。", "火探深洞燕，香送遠潭龍。", "藍塢寒先燒，禾堂晚併舂。", "更投何處宿，西峽隔雲鐘。"]'),
('995153fc-153b-4165-8a84-3cbad12232ef','南海使院對菊懷丁卯別墅','許渾','唐','唐诗','tang','','[]','何處曾移菊，溪橋鶴嶺東。',72,'全唐诗/poet.tang.29000.json','["何處曾移菊，溪橋鶴嶺東。", "籬疎還有豔，園小亦無叢。", "日晚秋煙裏，星繁曉露中。", "影搖金澗水，香染玉潭風。", "罷酒慙陶令，題詩答謝公。", "朝來數花發，身在尉佗宮。"]'),
('4f4d037c-df03-4ba7-8833-5c959dbe2d19','和李相國','許渾','唐','唐诗','tang','','[]','巨實珍吳果，馴雛重越禽。',72,'全唐诗/poet.tang.29000.json','["巨實珍吳果，馴雛重越禽。", "摘來漁浦上，攜在兔園陰。", "霜合凝丹頰，風披斂素襟。", "刀分瓊液散，籠簌雪華深。", "虎帳齋中設，龍樓洛下吟。", "含消兼受彩，應貴冢卿心。"]'),
('938f24c6-32d8-4947-babd-d31c17dc281c','陪少師李相國崔賓客宴居守狄僕射池亭','許渾','唐','唐诗','tang','','[]','池色似瀟湘，仙舟正日長。',72,'全唐诗/poet.tang.29000.json','["池色似瀟湘，仙舟正日長。", "燕飛驚蛺蝶，魚躍動鴛鴦。", "雲聚歌初轉，風回舞欲翔。", "暖醅松葉嫩，寒粥杏花香。", "羅綺留春色，笙竽送晚光。", "何須明月夜，紅燭在華堂。"]'),
('bcb950cd-3e82-4e28-99d0-7703b303511d','和賓客相國詠雪','許渾','唐','唐诗','tang','','[]','近臘千巖白，迎春四氣催。',192,'全唐诗/poet.tang.29000.json','["近臘千巖白，迎春四氣催。", "雲陰連海起，風急度山來。", "盡日隋堤絮，經冬越嶺梅。", "豔疑歌處散，輕似舞時迴。", "道蘊詩傳麗，相如賦騁才。", "霽添松篠媚，寒積蕙蘭猜。", "暗漲宮池水，平封輦路埃。", "燭龍初照耀，巢鶴乍裴回。", "簷日瓊先挂，牆風粉旋摧。", "五門環玉壘，雙闕對瑤臺。", "綺席陵寒坐，珠簾遠曙開。", "靈芝霜下秀，仙桂月中栽。", "卷幌書千帙，援琴酒百桮。", "垂休編太史，呈瑞表中台。", "皓夜迷三徑，浮光徹九垓。", "茲辰是豐歲，歌詠屬良哉。"]'),
('832310bd-8175-4083-a6b1-e4ab89759bbf','奉和盧大夫新立假山','許渾','唐','唐诗','tang','','[]','巖谷留心賞，爲山極自然。',72,'全唐诗/poet.tang.29000.json','["巖谷留心賞，爲山極自然。", "孤峰空迸笋，攢萼旋開蓮。", "黛色朱樓下，雲形繡戶前。", "砌塵凝積靄，簷溜挂飛泉。", "樹暗壺中月，花香洞裏天。", "何如謝康樂，海嶠獨題篇。"]'),
('422e404e-4c01-436b-9a49-dc2ec98add6e','奉命和後池十韻','許渾','唐','唐诗','tang','','[]','疊石通溪水，量波失舊規。',120,'全唐诗/poet.tang.29000.json','["疊石通溪水，量波失舊規。", "芳洲還屈曲，朱閣更逶迤。", "浴鳥翻荷葉，驚蟬出柳絲。", "翠煙秋檜聳，紅露曉蓮披。", "攀檻登樓近，停橈待客遲。", "野橋從浪沒，輕舸信風移。", "竹韻遷棊局，松陰遞酒巵。", "性閑鷗自識，心遠鶴先知。", "應想秦人會，休懷越相祠。", "當期穆天子，簫鼓宴瑤池。"]'),
('389ff335-4c86-4f7f-9e5f-5c00b8bce978','雨後思湖上居','許渾','唐','唐诗','tang','','[]','前山風雨涼，歇馬坐垂楊。',24,'全唐诗/poet.tang.29000.json','["前山風雨涼，歇馬坐垂楊。", "何處芙蓉落，南渠秋水香。"]'),
('206a9053-d835-4517-b91d-928e8015e4a0','聞歌','許渾','唐','唐诗','tang','','[]','新秋弦管清，時轉遏雲聲。',24,'全唐诗/poet.tang.29000.json','["新秋弦管清，時轉遏雲聲。", "曲盡不知處，月高風滿城。"]'),
('2590a5ec-50b9-41f7-860d-0b18cc6ddd11','思天台','許渾','唐','唐诗','tang','','[]','赤城雲雪深，山客負歸心。',24,'全唐诗/poet.tang.29000.json','["赤城雲雪深，山客負歸心。", "昨夜西齋宿，月明琪樹陰。"]'),
('c1f63452-0108-44fb-9e7f-c9895e39d8e2','長安早春懷江南','許渾','唐','唐诗','tang','','[]','雲月有歸處，故山清洛南。',24,'全唐诗/poet.tang.29000.json','["雲月有歸處，故山清洛南。", "如何一花發，春夢徧江潭。"]'),
('421c7cc0-287b-4b55-bb0d-4233d0cf0cee','塞下','許渾','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e", "\u540c\u60c5"]','夜戰桑乾北，秦兵半不歸。',24,'全唐诗/poet.tang.29000.json','["夜戰桑乾北，秦兵半不歸。", "朝來有鄉信，猶自寄征衣。"]'),
('07d523ec-3559-47a1-a9af-ec41e00e10a4','送客南歸','許渾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','野寺薜蘿晚，官渠楊柳春。',24,'全唐诗/poet.tang.29000.json','["野寺薜蘿晚，官渠楊柳春。", "歸心已無限，更送洞庭人。"]'),
('8cd3e922-6f07-444f-8418-9d15c469ebf5','寄桐江隱者','許渾','唐','唐诗','tang','','[]','潮去潮來洲渚春，山花如繡草如茵。',32,'全唐诗/poet.tang.29000.json','["潮去潮來洲渚春，山花如繡草如茵。", "嚴陵臺下桐江水，解釣鱸魚能幾人。"]'),
('7b9c1e01-17bc-47ef-bc6f-1f85bfcae47c','送曾主簿歸楚州省覲予亦明日歸姑孰','許渾','唐','唐诗','tang','','[]','帆轉清淮極鳥飛，落帆應換老萊衣。',32,'全唐诗/poet.tang.29000.json','["帆轉清淮極鳥飛，落帆應換老萊衣。", "河亭未醉先惆悵，明日還從此路歸。"]'),
('af0420cd-97dc-442a-a03c-77c7f7276dbe','重別','許渾','唐','唐诗','tang','','[]','淚沿紅粉濕羅巾，重繫蘭舟勸酒頻。',32,'全唐诗/poet.tang.29000.json','["淚沿紅粉濕羅巾，重繫蘭舟勸酒頻。", "留却一枝河畔柳，明朝猶有遠行人。"]'),
('eb5950fa-f3b3-481c-ad2e-d77835f0b9ee','湖上','許渾','唐','唐诗','tang','','[]','髣髴欲當三五夕，萬蟬清雜亂泉紋。',32,'全唐诗/poet.tang.29000.json','["髣髴欲當三五夕，萬蟬清雜亂泉紋。", "釣魚船上一尊酒，月出渡頭零落雲。"]'),
('fd395d3e-36e3-4c57-a468-73faab8671b8','夜泊永樂有懷','許渾','唐','唐诗','tang','','[]','蓮渚愁紅蕩碧波，吳娃齊唱採蓮歌。',32,'全唐诗/poet.tang.29000.json','["蓮渚愁紅蕩碧波，吳娃齊唱採蓮歌。", "橫塘一別已千里，蘆葦蕭蕭風雨多。"]'),
('5fa0657c-1edd-45f6-8350-eb3a8ed70056','宿水閤','許渾','唐','唐诗','tang','','[]','野客從來不解愁，等閑乘月海西頭。',32,'全唐诗/poet.tang.29000.json','["野客從來不解愁，等閑乘月海西頭。", "未知南陌誰家子，夜半吹笙入水樓。"]'),
('d453c853-bbb5-4159-8ba9-b847d5466639','謝亭送別','許渾','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u5199\u666f"]','勞歌一曲解行舟，紅葉青山水急流。',32,'全唐诗/poet.tang.29000.json','["勞歌一曲解行舟，紅葉青山水急流。", "日暮酒醒人已遠，滿天風雨下西樓。"]'),
('00ac54aa-6fb4-4680-b5fe-3d415aed851d','酬李當','許渾','唐','唐诗','tang','','[]','知有瑤華手自開，巴人虛唱懶封回。',32,'全唐诗/poet.tang.29000.json','["知有瑤華手自開，巴人虛唱懶封回。", "山陰一夜滿溪雪，借問扁舟來不來。"]'),
('7f32e213-8f47-4e3b-a4eb-64f8dadccde6','蟬','許渾','唐','唐诗','tang','','[]','噪柳鳴槐晚未休，不知何事愛悲秋。',32,'全唐诗/poet.tang.29000.json','["噪柳鳴槐晚未休，不知何事愛悲秋。", "朱門大有長吟處，剛傍愁人又送愁。"]'),
('8f6e07d0-b3fa-4ab0-b465-bb9bdb7ead53','夜過松江渡寄友人','許渾','唐','唐诗','tang','','[]','清露白雲明月天，與君齊棹木蘭船。',32,'全唐诗/poet.tang.29000.json','["清露白雲明月天，與君齊棹木蘭船。", "南湖風雨一相失，夜泊橫塘心渺然。"]'),
('39fce43a-b644-4a16-a3be-347a01e1eb4a','守風淮陰','許渾','唐','唐诗','tang','','[]','遙見江陰夜漁客，因思京口釣魚時。',32,'全唐诗/poet.tang.29000.json','["遙見江陰夜漁客，因思京口釣魚時。", "一潭明月萬株柳，自去自來人不知。"]'),
('454d1f56-4e0b-402a-8f88-e6ed7ef4d441','亡題','許渾','唐','唐诗','tang','','[]','商嶺採芝尋四老，紫陽收朮訪三茅。',32,'全唐诗/poet.tang.29000.json','["商嶺採芝尋四老，紫陽收朮訪三茅。", "欲求不死長生訣，骨裏無仙不肯教。"]'),
('faeb7219-b951-4dc3-a9df-da54029a4882','送楊發東歸','許渾','唐','唐诗','tang','','[]','紅花半落燕于飛，同客長安今獨歸。',32,'全唐诗/poet.tang.29000.json','["紅花半落燕于飛，同客長安今獨歸。", "一紙鄉書報兄弟，還家羞著別時衣。"]'),
('c1aeb4a0-79b9-4b3b-a2d4-c1f8a214c881','寄宋邧','許渾','唐','唐诗','tang','','[]','朱檻煙霜夜坐勞，美人南國舊同袍。',32,'全唐诗/poet.tang.29000.json','["朱檻煙霜夜坐勞，美人南國舊同袍。", "山長水遠無消息，瑤瑟一彈秋月高。"]'),
('6d7f8d32-d6d0-4c3d-89c6-f9941844fbff','題四老廟二首 一','許渾','唐','唐诗','tang','','[]','峨峨商嶺采芝人，雪頂霜髯虎豹茵。',32,'全唐诗/poet.tang.29000.json','["峨峨商嶺采芝人，雪頂霜髯虎豹茵。", "山酒一巵歌一曲，漢家天子忌功臣。"]'),
('41e686cc-ea20-409e-a417-8441c6ec8d55','題四老廟二首 二','許渾','唐','唐诗','tang','','[]','避秦安漢出藍關，松桂花陰滿舊山。',32,'全唐诗/poet.tang.29000.json','["避秦安漢出藍關，松桂花陰滿舊山。", "自是無人有歸意，白雲常在水潺潺。"]'),
('6aed28fd-a1f1-44ee-93a7-4a84b0d1ae55','夏日寄江上親友','許渾','唐','唐诗','tang','','[]','雨過前山日未斜，清蟬嘒嘒落槐花。',32,'全唐诗/poet.tang.29000.json','["雨過前山日未斜，清蟬嘒嘒落槐花。", "車輪南北已無限，江上故人纔到家。"]'),
('a5409f3b-9dd6-47ba-8aa9-eade79760d58','下第懷友人','許渾','唐','唐诗','tang','','[]','獨掩衡門花盛時，一封書信緩歸期。',32,'全唐诗/poet.tang.29000.json','["獨掩衡門花盛時，一封書信緩歸期。", "南宗更有瀟湘客，夜夜月明聞竹枝。"]'),
('1642fd97-bc35-4798-b40f-0174e0444fb8','客有卜居不遂薄遊汧隴因題','許渾','唐','唐诗','tang','','[]','海燕西飛白日斜，天門遙望五侯家。',32,'全唐诗/poet.tang.29000.json','["海燕西飛白日斜，天門遙望五侯家。", "樓臺深鎖無人到，落盡春風第一花。"]'),
('b154c70c-041b-4764-bed8-123f6c5750b9','陳宮怨二首 一','許渾','唐','唐诗','tang','','[]','風暖江城白日遲，昔人遺事後人悲。',32,'全唐诗/poet.tang.29000.json','["風暖江城白日遲，昔人遺事後人悲。", "草生宮闕國無主，玉樹後庭花爲誰。"]'),
('bc93b706-1335-4a13-bb33-c8cee82f28da','陳宮怨二首 二','許渾','唐','唐诗','tang','','[]','地雄山險水悠悠，不信隋兵到石頭。',32,'全唐诗/poet.tang.29000.json','["地雄山險水悠悠，不信隋兵到石頭。", "玉樹後庭花一曲，與君同上景陽樓。"]'),
('e38c69eb-8cda-4c2a-8a66-cf950b9e69bf','經故太尉段公廟','許渾','唐','唐诗','tang','','[]','靜想追兵緩翠華，古碑荒廟閉松花。',32,'全唐诗/poet.tang.29000.json','["靜想追兵緩翠華，古碑荒廟閉松花。", "紀生不向滎陽死，爭有山河屬漢家。"]'),
('44aa5f75-3db8-4657-a03d-7c45547482f2','途經秦始皇墓','許渾','唐','唐诗','tang','','["\u5199\u4eba", "\u6000\u53e4", "\u5199\u4eba\u8bd7"]','龍盤虎踞樹層層，勢入浮雲亦是崩。',32,'全唐诗/poet.tang.29000.json','["龍盤虎踞樹層層，勢入浮雲亦是崩。", "一種青山秋草裏，路人唯拜漢文陵。"]'),
('f17bae59-31ff-4374-8af6-f21a92f6cab3','游楞伽寺','許渾','唐','唐诗','tang','','[]','碧煙秋寺泛潮來，水浸城根古堞摧。',32,'全唐诗/poet.tang.29000.json','["碧煙秋寺泛潮來，水浸城根古堞摧。", "盡日傷心人不見，石榴花滿舊琴臺。"]'),
('db3f0de3-23ff-4bae-bd32-d2914e66b85c','緱山廟','許渾','唐','唐诗','tang','','[]','王子吹簫月滿臺，玉簫清轉鶴裴回。',32,'全唐诗/poet.tang.29000.json','["王子吹簫月滿臺，玉簫清轉鶴裴回。", "曲終飛去不知處，山下碧桃春自開。"]'),
('1be7b39c-8dbf-487d-a833-2309a90c67ab','送薛先輩入關','許渾','唐','唐诗','tang','','[]','一巵春酒送離歌，花落敬亭芳草多。',32,'全唐诗/poet.tang.29000.json','["一巵春酒送離歌，花落敬亭芳草多。", "欲問歸期已深醉，只應孤夢繞關河。"]'),
('55de26a1-098e-4916-be9d-1aea3b806a40','鴻溝','許渾','唐','唐诗','tang','','[]','相持未定各爲君，秦政山河此地分。',32,'全唐诗/poet.tang.29000.json','["相持未定各爲君，秦政山河此地分。", "力盡烏江千載後，古溝芳草起寒雲。"]'),
('849a010b-702a-4aff-9bb0-9f4508f7a243','韓信廟','許渾','唐','唐诗','tang','','[]','朝言雲夢暮南巡，已爲功名少退身。',32,'全唐诗/poet.tang.29000.json','["朝言雲夢暮南巡，已爲功名少退身。", "盡握兵權猶不得，更將心計託何人。"]'),
('0d68ad1c-84c0-4732-b82e-790aef17d280','過湘妃廟','許渾','唐','唐诗','tang','','[]','古木蒼山掩翠娥，月明南浦起微波。',32,'全唐诗/poet.tang.29000.json','["古木蒼山掩翠娥，月明南浦起微波。", "九疑望斷幾千載，斑竹淚痕今更多。"]'),
('c98ffd7a-46a0-4bf3-8274-cbeed7ed2384','寄雲際寺敬上人','許渾','唐','唐诗','tang','','[]','萬山秋雨水縈回，紅葉多從紫閣來。',32,'全唐诗/poet.tang.29000.json','["萬山秋雨水縈回，紅葉多從紫閣來。", "雲冷竹齋禪衲薄，已應飛錫過天台。"]'),
('366338ab-0519-49ed-ace6-1b297d0a54b1','秋思','許渾','唐','唐诗','tang','','[]','琪樹西風枕簟秋，楚雲湘水憶同遊。',32,'全唐诗/poet.tang.29000.json','["琪樹西風枕簟秋，楚雲湘水憶同遊。", "高歌一曲掩明鏡，昨日少年今白頭。"]'),
('1546c07e-a015-4682-bac9-a414629c95d3','送宋處士歸山','許渾','唐','唐诗','tang','','[]','賣藥修琴歸去遲，山風吹盡桂花枝。',32,'全唐诗/poet.tang.29000.json','["賣藥修琴歸去遲，山風吹盡桂花枝。", "世間甲子須臾事，逢著仙人莫看棋。"]'),
('77abf77b-9c3c-43dd-8866-3e600d028bb8','聽琵琶','許渾','唐','唐诗','tang','','[]','欲寫明妃萬里情，紫槽紅撥夜丁丁。',32,'全唐诗/poet.tang.29000.json','["欲寫明妃萬里情，紫槽紅撥夜丁丁。", "胡沙望盡漢宮遠，月落天山聞一聲。"]'),
('988039dc-1e67-4f3d-8306-f01e2e1c1e95','秦樓曲','許渾','唐','唐诗','tang','','[]','秦女夢餘仙路遙，月窗風簟夜迢迢。',32,'全唐诗/poet.tang.29000.json','["秦女夢餘仙路遙，月窗風簟夜迢迢。", "潘郎翠鳳雙飛去，三十六宮聞玉簫。"]'),
('ea81582e-0968-4517-9166-f004df071704','旌儒廟','許渾','唐','唐诗','tang','','[]','寒陌陰風萬古悲，儒冠相枕死秦時。',32,'全唐诗/poet.tang.29000.json','["寒陌陰風萬古悲，儒冠相枕死秦時。", "廟前亦有商山路，不學老翁歌紫芝。"]'),
('edae60a3-4137-4c0d-9f59-e9cfeeda3a49','覽故人題僧院詩','許渾','唐','唐诗','tang','','[]','高閣清吟寄遠公，四時雲月一篇中。',32,'全唐诗/poet.tang.29000.json','["高閣清吟寄遠公，四時雲月一篇中。", "今來借問獨何處，日暮槿花零落風。"]'),
('1c497abf-1636-472b-bc30-2b7722918ba3','楚宮怨二首 一','許渾','唐','唐诗','tang','','["\u5c71", "\u548f\u53f2"]','十二山晴花盡開，楚宮雙闕對陽臺。',32,'全唐诗/poet.tang.29000.json','["十二山晴花盡開，楚宮雙闕對陽臺。", "細腰爭舞君沈醉，白日秦兵天上來。"]'),
('d77482d7-0921-471d-92b5-f493fb8bc41e','楚宮怨二首 二','許渾','唐','唐诗','tang','','[]','獵騎秋來在內稀，渚宮雲雨濕龍衣。',32,'全唐诗/poet.tang.29000.json','["獵騎秋來在內稀，渚宮雲雨濕龍衣。", "騰騰戰鼓動城闕，江畔射麋殊未歸。"]'),
('33f7be51-d3f1-4b2d-9403-e16bd3c4bde3','聽唱山鷓鴣','許渾','唐','唐诗','tang','','[]','金谷歌傳第一流，鷓鴣清怨碧煙愁。',32,'全唐诗/poet.tang.29000.json','["金谷歌傳第一流，鷓鴣清怨碧煙愁。", "夜來省得曾聞處，萬里月明湘水秋。"]'),
('cd6e1da0-f5cb-43d4-b3d1-f617e81ffdf2','晨起西樓','許渾','唐','唐诗','tang','','[]','留情深處駐橫波，斂翠凝紅一曲歌。',32,'全唐诗/poet.tang.29000.json','["留情深處駐橫波，斂翠凝紅一曲歌。", "明月下樓人未散，共愁三徑是天河。"]'),
('9d517982-8603-4f46-af94-cbcae502099a','酬江西盧端公藍口阻風見寄之什','許渾','唐','唐诗','tang','','[]','又攜刀筆泛膺舟，藍口風高桂檝留。',32,'全唐诗/poet.tang.29000.json','["又攜刀筆泛膺舟，藍口風高桂檝留。", "還似郢中歌一曲，夜來春雪照西樓。"]'),
('1a4e6676-bfb1-4420-b3fa-f64cf5984489','贈何處士','許渾','唐','唐诗','tang','','[]','東別茅峰北去秦，梅仙書裏說真人。',32,'全唐诗/poet.tang.29000.json','["東別茅峰北去秦，梅仙書裏說真人。", "白頭主印青山下，雖遇唐生不敢親。"]'),
('cb4db05d-3fd1-4fcc-a762-4f9731ad5b85','鷺鷥','許渾','唐','唐诗','tang','','[]','西風澹澹水悠悠，雪點絲飄帶雨愁。',32,'全唐诗/poet.tang.29000.json','["西風澹澹水悠悠，雪點絲飄帶雨愁。", "何限歸心倚前閤，綠蒲紅蓼練塘秋。"]'),
('1755ac10-2864-48f1-8c2f-122f359dda70','學仙二首 一','許渾','唐','唐诗','tang','','[]','漢武迎仙紫禁秋，玉笙瑤瑟祀崑丘。',32,'全唐诗/poet.tang.29000.json','["漢武迎仙紫禁秋，玉笙瑤瑟祀崑丘。", "年年望斷無消息，空閉重城十二樓。"]'),
('f6a0fc25-c8f2-488b-a920-f4cd631c97cb','學仙二首 二','許渾','唐','唐诗','tang','','[]','心期仙訣意無窮，采畫雲車起壽宮。',32,'全唐诗/poet.tang.29000.json','["心期仙訣意無窮，采畫雲車起壽宮。", "聞有三山未知處，茂陵松柏滿西風。"]'),
('438e966a-8517-4270-a19c-d52b48063a3f','酬康州韋侍御同年','許渾','唐','唐诗','tang','','[]','桂楫美人歌木蘭，西風褭褭露溥溥。',32,'全唐诗/poet.tang.29000.json','["桂楫美人歌木蘭，西風褭褭露溥溥。", "夜長曲盡意不盡，月在清湘洲渚寒。"]'),
('adffb7af-5583-4ec6-8c2e-a68d2a161d63','紫藤','許渾','唐','唐诗','tang','','[]','綠蔓穠陰紫袖低，客來留坐小堂西。',32,'全唐诗/poet.tang.29000.json','["綠蔓穠陰紫袖低，客來留坐小堂西。", "醉中掩瑟無人會，家近江南罨畫溪。"]'),
('9bb4eba2-0aaa-4ee2-8ed6-839fa68a9d8f','宿咸宜觀','許渾','唐','唐诗','tang','','[]','羽袖飄飄杳夜風，翠幢歸殿玉壇空。',32,'全唐诗/poet.tang.29000.json','["羽袖飄飄杳夜風，翠幢歸殿玉壇空。", "步虛聲盡天未曉，露壓桃花月滿宮。"]'),
('04503c2d-97c7-4fe6-9805-215534b1b452','金谷園','許渾','唐','唐诗','tang','','[]','三惑沈身是此園，古藤荒草野禽喧。',32,'全唐诗/poet.tang.29000.json','["三惑沈身是此園，古藤荒草野禽喧。", "二十四友一朝盡，愛妾墜樓何足言。"]'),
('d4d43374-832a-4846-a518-0bd079946fc7','送崔珦入朝','許渾','唐','唐诗','tang','','[]','書劒功遲白髮新，強登蕭寺送歸秦。',32,'全唐诗/poet.tang.29000.json','["書劒功遲白髮新，強登蕭寺送歸秦。", "月斜松桂倚高閣，明夜江南江北人。"]'),
('e533b0ec-e6d5-4b1b-928a-865a95ea4fab','病中和大夫翫江月','許渾','唐','唐诗','tang','','[]','江上懸光海上生，仙舟迢遰繞軍營。',32,'全唐诗/poet.tang.29000.json','["江上懸光海上生，仙舟迢遰繞軍營。", "高歌一曲同筵醉，却是劉楨坐到明。"]'),
('0d5f2709-a375-4ded-a665-0871e0b63c7c','讀戾太子傳','許渾','唐','唐诗','tang','','[]','佞臣巫蠱已相疑，身沒湖邊築望思。',32,'全唐诗/poet.tang.29000.json','["佞臣巫蠱已相疑，身沒湖邊築望思。", "今日更歸何處是，年年芳草上臺基。"]'),
('5a6c6d2c-735f-4b5e-8fad-c407abf630d0','酬對雪見寄','許渾','唐','唐诗','tang','','[]','飛度龍山下遠空，拂簷縈竹晝濛濛。',32,'全唐诗/poet.tang.29000.json','["飛度龍山下遠空，拂簷縈竹晝濛濛。", "知君吟罷意無限，曾聽玉堂歌北風。"]'),
('72366286-73aa-49c3-9ac0-fa0017da8a4a','王可封臨終','許渾','唐','唐诗','tang','','[]','十世爲儒少子孫，一生長負信陵恩。',32,'全唐诗/poet.tang.29000.json','["十世爲儒少子孫，一生長負信陵恩。", "今朝埋骨寒山下，爲報慈親休倚門。"]'),
('8c29fe36-3fec-4c18-b3ff-342e9e816d01','僧院影堂','許渾','唐','唐诗','tang','','[]','香銷雲凝舊僧家，僧剎殘燈壁半斜。',32,'全唐诗/poet.tang.29000.json','["香銷雲凝舊僧家，僧剎殘燈壁半斜。", "日暮松煙空漠漠，秋風吹破妙蓮華。"]'),
('98140fff-28fa-4b59-9c60-ce456b6a4397','紀夢','許渾','唐','唐诗','tang','','[]','曉入瑤臺露氣清，座中唯有許飛瓊。',32,'全唐诗/poet.tang.29000.json','["曉入瑤臺露氣清，座中唯有許飛瓊。", "塵心未盡俗緣在，十里下山空月明。"]'),
('a154a9b3-bd7f-4dd9-af49-22eca32c51a7','三十六灣','許渾','唐','唐诗','tang','','[]','縹緲臨風思美人，荻花楓葉帶離聲。',32,'全唐诗/poet.tang.29000.json','["縹緲臨風思美人，荻花楓葉帶離聲。", "夜深吹笛移船去，三十六灣秋月明。"]'),
('93060e2d-d4a1-4d09-941b-e030136eaf17','越中','許渾','唐','唐诗','tang','','[]','石城花暖鷓鴣飛，征客春帆秋不歸。',32,'全唐诗/poet.tang.29000.json','["石城花暖鷓鴣飛，征客春帆秋不歸。", "猶自保郎心似石，綾梭夜夜織寒衣。"]'),
('e0eb3016-9288-4dc0-9257-3de36e5ad73c','錦瑟','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e03\u8a00\u5f8b\u8bd7", "\u6292\u60c5", "\u7231\u60c5"]','錦瑟無端五十絃，一絃一柱思華年。',64,'全唐诗/poet.tang.29000.json','["錦瑟無端五十絃，一絃一柱思華年。", "莊生曉夢迷蝴蝶，望帝春心託杜鵑。", "滄海月明珠有淚，藍田日暖玉生煙。", "此情可待成追憶，只是當時已惘然。"]'),
('d7d221a9-62ed-4b94-8713-c2d70e174526','重過聖女祠','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u4eba", "\u795e\u8bdd"]','白石巖扉碧蘚滋，上清淪謫得歸遲。',64,'全唐诗/poet.tang.29000.json','["白石巖扉碧蘚滋，上清淪謫得歸遲。", "一春夢雨常飄瓦，盡日靈風不滿旗。", "萼綠華來無定所，杜蘭香去未移時。", "玉郎會此通仙籍，憶向天階問紫芝。"]'),
('70779e79-e103-4985-9e37-0e408d149c71','寄羅劭興','李商隱','唐','唐诗','tang','','[]','棠棣黃花發，忘憂碧葉齊。',48,'全唐诗/poet.tang.29000.json','["棠棣黃花發，忘憂碧葉齊。", "人閑微病酒，燕重遠兼泥。", "混沌何由鑿，青冥有未梯。", "高陽舊徒侶，時復一相攜。"]'),
('c6683b74-ed00-456c-8c1d-9847d9546e11','令狐舍人說昨夜西掖翫月因戲贈','李商隱','唐','唐诗','tang','','[]','昨夜玉輪明，傳聞近太清。',48,'全唐诗/poet.tang.29000.json','["昨夜玉輪明，傳聞近太清。", "涼波衝碧瓦，曉暈落金莖。", "露索秦宮井，風絃漢殿箏。", "幾時緜竹頌，擬薦子虛名。"]'),
('714393ee-b874-436c-9c76-59964b530556','崔處士','李商隱','唐','唐诗','tang','','[]','真人塞其內，夫子入於機。',48,'全唐诗/poet.tang.29000.json','["真人塞其內，夫子入於機。", "未肯投竿起，惟歡負米歸。", "雪中東郭履，堂上老萊衣。", "讀遍先賢傳，如君事者稀。"]'),
('288e18ae-3c84-47db-b7ef-41f41605d397','自喜','李商隱','唐','唐诗','tang','','[]','自喜蝸牛舍，兼容燕子巢。',48,'全唐诗/poet.tang.29000.json','["自喜蝸牛舍，兼容燕子巢。", "綠筠遺粉籜，紅藥綻香苞。", "虎過遙知穽，魚來且佐庖。", "慢行成酩酊，鄰壁有松醪。"]'),
('6c99fc38-53b2-48be-b92d-ee089fc614be','題僧壁','李商隱','唐','唐诗','tang','','[]','捨生求道有前蹤，乞腦剜身結願重。',64,'全唐诗/poet.tang.29000.json','["捨生求道有前蹤，乞腦剜身結願重。", "大去便應欺粟顆，小來兼可隱針鋒。", "蚌胎未滿思新桂，琥珀初成憶舊松。", "若信貝多真實語，三生同聽一樓鐘。"]'),
('0f653e6b-c416-4d2e-9866-c6dbcfcf0b99','霜月','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u6708\u4eae", "\u79cb\u5929", "\u4e2d\u79cb"]','初聞征雁已無蟬，百尺樓高水接天。',32,'全唐诗/poet.tang.29000.json','["初聞征雁已無蟬，百尺樓高水接天。", "青女素娥俱耐冷，月中霜裏鬬嬋娟。"]'),
('36d0e69d-6290-44db-8e9f-3a9625079cef','異俗二首 一','李商隱','唐','唐诗','tang','','[]','鬼瘧朝朝避，春寒夜夜添。',48,'全唐诗/poet.tang.29000.json','["鬼瘧朝朝避，春寒夜夜添。", "未驚雷破柱，不報水齊簷。", "虎箭侵膚毒，魚鉤刺骨銛。", "鳥言成諜訴，多是恨彤幨。"]'),
('5e1c2074-1e65-4118-9c6e-f8e3aeac511e','異俗二首 二','李商隱','唐','唐诗','tang','','[]','戶盡懸秦網，家多事越巫。',48,'全唐诗/poet.tang.29000.json','["戶盡懸秦網，家多事越巫。", "未曾容獺祭，只是縱猪都。", "點對連鰲餌，搜求縛虎符。", "賈生兼事鬼，不信有洪爐。"]'),
('2ac175f6-6785-4fc9-bbdc-c788540c51fc','歸墅','李商隱','唐','唐诗','tang','','[]','行李踰南極，旬時到舊鄉。',48,'全唐诗/poet.tang.29000.json','["行李踰南極，旬時到舊鄉。", "楚芝應徧紫，鄧橘未全黃。", "渠濁村舂急，旗高社酒香。", "故山歸夢喜，先入讀書堂。"]'),
('7a702135-6667-47b5-8c68-5b908f1eee18','商於','李商隱','唐','唐诗','tang','','[]','商於朝雨霽，歸路有秋光。',72,'全唐诗/poet.tang.29000.json','["商於朝雨霽，歸路有秋光。", "背塢猿收果，投巖麝退香。", "建瓴真得勢，橫戟豈能當。", "割地張儀詐，謀身綺季長。", "清渠州外月，黃葉廟前霜。", "今日看雲意，依依入帝鄉。"]'),
('5e37fb83-959d-4b18-8229-d8f5506f9e1e','和孫朴韋蟾孔雀詠','李商隱','唐','唐诗','tang','','[]','此去三梁遠，今來萬里攜。',168,'全唐诗/poet.tang.29000.json','["此去三梁遠，今來萬里攜。", "西施因網得，秦客被花迷。", "可在青鸚鵡，非關碧野雞。", "約眉憐翠羽，刮目想金篦。", "瘴氣籠飛遠，蠻花向坐低。", "輕於趙皇后，貴極楚懸黎。", "都護矜羅幕，佳人炫繡袿。", "屏風臨燭釦，捍撥倚香臍。", "舊思牽雲葉，新愁待雪泥。", "愛堪通夢寐，畫得不端倪。", "地錦排蒼雁，簾釘鏤白犀。", "曙霞星斗外，涼月露盤西。", "妬好休誇舞，經寒且少啼。", "紅樓三十級，穩穩上丹梯。"]'),
('084f2451-8aed-4fc9-8e58-986c3d6e95b8','人欲','李商隱','唐','唐诗','tang','','[]','人欲天從竟不疑，莫言圓蓋便無私。',32,'全唐诗/poet.tang.29000.json','["人欲天從竟不疑，莫言圓蓋便無私。", "秦中已久烏頭白，却是君王未備知。"]'),
('dcbeff30-583c-4d6c-a4d7-3f0b790e7d7c','華山題王母祠','李商隱','唐','唐诗','tang','','[]','蓮華峰下鎖雕梁，此去瑤池地共長。',32,'全唐诗/poet.tang.29000.json','["蓮華峰下鎖雕梁，此去瑤池地共長。", "好爲麻姑到東海，勸栽黃竹莫栽桑。"]'),
('5624914b-f695-4597-ad74-a12319e4e181','華清宮','李商隱','唐','唐诗','tang','','[]','華清恩幸古無倫，猶恐蛾眉不勝人。',32,'全唐诗/poet.tang.29000.json','["華清恩幸古無倫，猶恐蛾眉不勝人。", "未免被他褒女笑，只教天子暫蒙塵。"]'),
('1fc515bd-7e51-4759-acff-3686100584c7','楚澤','李商隱','唐','唐诗','tang','','[]','夕陽歸路後，霜野物聲乾。',48,'全唐诗/poet.tang.29000.json','["夕陽歸路後，霜野物聲乾。", "集鳥翻漁艇，殘虹拂馬鞍。", "劉楨元抱病，虞寄數辭官。", "白袷經年卷，西來及早寒。"]'),
('b3de619f-cc8b-457d-942b-49f06651aba4','蟬','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u548f\u7269", "\u548f\u7269\u8bd7", "\u4e94\u8a00\u5f8b\u8bd7"]','本以高難飽，徒勞恨費聲。',48,'全唐诗/poet.tang.29000.json','["本以高難飽，徒勞恨費聲。", "五更疎欲斷，一樹碧無情。", "薄宦梗猶汎，故園蕪已平。", "煩君最相警，我亦舉家清。"]'),
('5c96efde-f36f-44ef-934a-874377c14e5f','江亭散席循柳路吟','李商隱','唐','唐诗','tang','','[]','春詠敢輕裁，銜辭入半杯。',48,'全唐诗/poet.tang.29000.json','["春詠敢輕裁，銜辭入半杯。", "已遭江映柳，更被雪藏梅。", "寡和真徒爾，殷憂動即來。", "從詩得何報，惟感二毛催。"]'),
('ac47b62e-5756-4ae0-a9f9-973354451549','潭州','李商隱','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u8bbd\u55bb", "\u5178\u6545"]','潭州官舍暮樓空，今古無端入望中。',64,'全唐诗/poet.tang.29000.json','["潭州官舍暮樓空，今古無端入望中。", "湘淚淺深滋竹色，楚歌重疊怨蘭叢。", "陶公戰艦空灘雨，賈傅承塵破廟風。", "目斷故園人不至，松醪一醉與誰同。"]'),
('57ee870e-5fea-4717-992d-73683ed0680e','贈劉司戶','李商隱','唐','唐诗','tang','','[]','江風吹浪動雲根，重碇危檣白日昏。',64,'全唐诗/poet.tang.29000.json','["江風吹浪動雲根，重碇危檣白日昏。", "已斷燕鴻初起勢，更驚騷客後歸魂。", "漢廷急詔誰先入，楚路高歌自欲翻。", "萬里相逢歡復泣，鳳巢西隔九重門。"]'),
('deef7ba3-321f-4369-89c6-c537c545e17a','哭劉司戶二首 一','李商隱','唐','唐诗','tang','','[]','離居星歲易，失望死生分。',48,'全唐诗/poet.tang.29000.json','["離居星歲易，失望死生分。", "酒甕凝餘桂，書籤冷舊芸。", "江風吹鴈急，山木帶蟬曛。", "一呌千迴首，天高不爲聞。"]'),
('f90656d1-0400-4f14-a2c7-6bd5d3b43ca1','哭劉司戶二首 二','李商隱','唐','唐诗','tang','','[]','有美扶皇運，無誰薦直言。',48,'全唐诗/poet.tang.29000.json','["有美扶皇運，無誰薦直言。", "已爲秦逐客，復作楚冤魂。", "湓浦應分派，荆江有會源。", "幷將添恨淚，一灑問乾坤。"]'),
('41464110-35a8-44f3-bf5c-76ecb6a4c324','悼傷後赴東蜀辟至散關遇雪','李商隱','唐','唐诗','tang','','["\u5199\u96ea", "\u96ea", "\u611f\u4f24"]','劍外從軍遠，無家與寄衣。',24,'全唐诗/poet.tang.29000.json','["劍外從軍遠，無家與寄衣。", "散關三尺雪，回夢舊鴛機。"]'),
('d7c6d072-6e84-482e-856a-5a4c21226a3c','樂遊原','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u60dc\u65f6", "\u54f2\u7406"]','向晚意不適，驅車登古原。',24,'全唐诗/poet.tang.29000.json','["向晚意不適，驅車登古原。", "夕陽無限好，只是近黃昏。"]'),
('bf2d420a-183e-4a15-9573-65405bd59c37','北齊二首 一','李商隱','唐','唐诗','tang','','[]','一笑相傾國便亡，何勞荆棘始堪傷。',32,'全唐诗/poet.tang.29000.json','["一笑相傾國便亡，何勞荆棘始堪傷。", "小憐玉體橫陳夜，已報周師入晉陽。"]'),
('f664ffbd-72d2-469a-8ea9-38f07e89da32','北齊二首 二','李商隱','唐','唐诗','tang','','[]','巧笑知堪敵萬幾，傾城最在著戎衣。',32,'全唐诗/poet.tang.29000.json','["巧笑知堪敵萬幾，傾城最在著戎衣。", "晉陽已陷休回顧，更請君王獵一圍。"]'),
('9aa6d4de-b69e-4014-8c48-61e78ba8eae8','街西池館','李商隱','唐','唐诗','tang','','[]','白閣他年別，朱門此夜過。',48,'全唐诗/poet.tang.29000.json','["白閣他年別，朱門此夜過。", "疎簾留月魄，珍簟接煙波。", "太守三刀夢，將軍一箭歌。", "國租容客旅，香熟玉山禾。"]'),
('7b5ddd79-3af3-4a8b-af40-6518271fd803','南朝','李商隱','唐','唐诗','tang','','[]','玄武湖中玉漏催，雞鳴埭口繡襦迴。',64,'全唐诗/poet.tang.29000.json','["玄武湖中玉漏催，雞鳴埭口繡襦迴。", "誰言瓊樹朝朝見，不及金蓮步步來。", "敵國軍營漂木柹，前朝神廟鎖煙煤。", "滿宮學士皆顏色，江令當年只費才。"]'),
('bd7468ad-47dc-4649-9d6c-ee54a20898e7','復京','李商隱','唐','唐诗','tang','','[]','虜騎胡兵一戰摧，萬靈回首賀軒臺。',32,'全唐诗/poet.tang.29000.json','["虜騎胡兵一戰摧，萬靈回首賀軒臺。", "天教李令心如日，可要昭陵石馬來。"]'),
('b84ef046-ac28-4874-90c8-f47d0a56145d','渾河中','李商隱','唐','唐诗','tang','','[]','九廟無塵八馬回，奉天城壘長春苔。',32,'全唐诗/poet.tang.29000.json','["九廟無塵八馬回，奉天城壘長春苔。", "咸陽原上英雄骨，半向君家養馬來。"]'),
('9c4de9fe-8f11-48c5-9e13-efa389cc9d9b','鄠杜馬上念漢書','李商隱','唐','唐诗','tang','','[]','世上蒼龍種，人間武帝孫。',48,'全唐诗/poet.tang.29000.json','["世上蒼龍種，人間武帝孫。", "小來惟射獵，興罷得乾坤。", "渭水天開苑，咸陽地獻原。", "英靈殊未已，丁傅漸華軒。"]'),
('77545bf3-4b59-4497-890b-63bdf574debd','柳','李商隱','唐','唐诗','tang','','[]','動春何限葉，撼曉幾多枝。',50,'全唐诗/poet.tang.29000.json','["動春何限葉，撼曉幾多枝。", "解有相思[否]，應無不舞時。", "絮飛藏皓蝶，帶弱露黃鸝。", "傾國宜通體，誰來獨賞眉。"]'),
('6c7f0d3e-9a2c-43f0-b16e-09f79d2ac6b9','巴江柳','李商隱','唐','唐诗','tang','','[]','巴江可惜柳，柳色綠侵江。',24,'全唐诗/poet.tang.29000.json','["巴江可惜柳，柳色綠侵江。", "好向金鑾殿，移陰入綺窗。"]'),
('c533fae8-97bd-4d1f-bf97-c17b826883b6','咸陽','李商隱','唐','唐诗','tang','','[]','咸陽宮闕鬱嵯峨，六國樓臺豔綺羅。',32,'全唐诗/poet.tang.29000.json','["咸陽宮闕鬱嵯峨，六國樓臺豔綺羅。", "自是當時天帝醉，不關秦地有山河。"]'),
('65831daa-4494-43b4-8405-e162cb81ec73','同崔八詣藥山訪融禪師','李商隱','唐','唐诗','tang','','[]','共受征南不次恩，報恩惟是有忘言。',32,'全唐诗/poet.tang.29000.json','["共受征南不次恩，報恩惟是有忘言。", "巖花澗草西林路，未見高僧只見猿。"]'),
('e1061247-281a-49d5-be00-fd15cb352bf5','聞著明凶問哭寄飛卿','李商隱','唐','唐诗','tang','','[]','昔歎讒銷骨，今傷淚滿膺。',48,'全唐诗/poet.tang.29000.json','["昔歎讒銷骨，今傷淚滿膺。", "空餘雙玉劍，無復一壺冰。", "江勢翻銀礫，天文露玉繩。", "何因攜庾信，同去哭徐陵。"]'),
('183987da-b8e6-4632-bc8d-8b50a1766ad4','聽鼓','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u8ffd\u5fc6", "\u5199\u666f", "\u6124\u61d1"]','城頭疊鼓聲，城下暮江清。',24,'全唐诗/poet.tang.29000.json','["城頭疊鼓聲，城下暮江清。", "欲問漁陽摻，時無禰正平。"]'),
('1c3c5b7a-80f1-42a5-9209-b73263839c10','送崔珏往西川','李商隱','唐','唐诗','tang','','[]','年少因何有旅愁，欲爲東下更西遊。',64,'全唐诗/poet.tang.29000.json','["年少因何有旅愁，欲爲東下更西遊。", "一條雪浪吼巫峽，千里火雲燒益州。", "卜肆至今多寂寞，酒壚從古擅風流。", "浣花牋紙桃花色，好好題詩詠玉鉤。"]'),
('ec00137e-f391-4173-91b9-725c0644ae64','代贈','李商隱','唐','唐诗','tang','','[]','楊柳路盡處，芙蓉湖上頭。',40,'全唐诗/poet.tang.29000.json','["楊柳路盡處，芙蓉湖上頭。", "雖同錦步障，獨映鈿箜篌。", "鴛鴦可羨頭俱白，飛去飛來煙雨秋。"]'),
('4b96fec6-886f-4e98-b144-0ae0e09f5935','桂林','李商隱','唐','唐诗','tang','','[]','城窄山將壓，江寬地共浮。',48,'全唐诗/poet.tang.29000.json','["城窄山將壓，江寬地共浮。", "東南通絕域，西北有高樓。", "神護青楓岸，龍移白石湫。", "殊鄉竟何禱，簫鼓不曾休。"]'),
('75db753d-e7da-48a1-a6c0-6ed9147e58db','夜雨寄北','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u5199\u96e8", "\u5199\u666f", "\u666f\u4e2d\u60c5", "\u521d\u4e2d\u53e4\u8bd7"]','君問歸期未有期，巴山夜雨漲秋池。',32,'全唐诗/poet.tang.29000.json','["君問歸期未有期，巴山夜雨漲秋池。", "何當共剪西窗燭，却話巴山夜雨時。"]'),
('b8371f9a-23c9-46f5-babc-19e230bb9ff5','陳後宮','李商隱','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5bab\u5ef7"]','茂苑城如畫，閶門瓦欲流。',48,'全唐诗/poet.tang.29000.json','["茂苑城如畫，閶門瓦欲流。", "還依水光殿，更起月華樓。", "侵夜鸞開鏡，迎冬雉獻裘。", "從臣皆半醉，天子正無愁。"]'),
('50ab4770-f08a-4fd7-917a-95087a5886e4','屬疾','李商隱','唐','唐诗','tang','','[]','許靖猶羈宦，安仁復悼亡。',48,'全唐诗/poet.tang.29000.json','["許靖猶羈宦，安仁復悼亡。", "茲辰聊屬疾，何日免殊方。", "秋蝶無端麗，寒花只暫香。", "多情真命薄，容易即迴腸。"]'),
('72aac7c5-766e-476f-b094-a780465c172b','石榴','李商隱','唐','唐诗','tang','','["\u7231\u60c5", "\u5973\u5b50"]','榴枝婀娜榴實繁，榴膜輕明榴子鮮。',32,'全唐诗/poet.tang.29000.json','["榴枝婀娜榴實繁，榴膜輕明榴子鮮。", "可羨瑤池碧桃樹，碧桃紅頰一千年。"]'),
('88f7fe7a-b54f-425c-a071-d3b3f7a3b2f8','明日','李商隱','唐','唐诗','tang','','[]','天上參旗過，人間燭燄銷。',48,'全唐诗/poet.tang.29000.json','["天上參旗過，人間燭燄銷。", "誰言整雙履，便是隔三橋。", "知處黃金鏁，曾來碧綺寮。", "憑欄明日意，池闊雨蕭蕭。"]'),
('a47cdd5d-29e7-4366-ad6a-852c52053894','飲席戲贈同舍','李商隱','唐','唐诗','tang','','[]','洞中屐響省分攜，不是花迷客自迷。',64,'全唐诗/poet.tang.29000.json','["洞中屐響省分攜，不是花迷客自迷。", "珠樹重行憐翡翠，玉樓雙舞羨鵾雞。", "蘭迴舊蘂緣屏綠，椒綴新香和壁泥。", "唱盡陽關無限疊，半杯松葉凍頗黎。"]'),
('7a05d50d-c871-46d7-be27-7e2c2cf9cc09','西溪','李商隱','唐','唐诗','tang','','[]','近郭西溪好，誰堪共酒壺。',48,'全唐诗/poet.tang.29000.json','["近郭西溪好，誰堪共酒壺。", "苦吟防柳惲，多淚怯楊朱。", "野鶴隨君子，寒松揖大夫。", "天涯常病意，岑寂勝歡娛。"]'),
('c5f86a2d-85f1-4c90-b963-adf541dc98a4','憶梅','李商隱','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u6885\u82b1", "\u548f\u7269\u8bd7"]','定定住天涯，依依向物華。',24,'全唐诗/poet.tang.29000.json','["定定住天涯，依依向物華。", "寒梅最堪恨，常作去年花。"]'),
('e3294466-f013-45b2-ac51-bfebf036fd0c','贈柳','李商隱','唐','唐诗','tang','','[]','章臺從掩映，郢路更參差。',48,'全唐诗/poet.tang.29000.json','["章臺從掩映，郢路更參差。", "見說風流極，來當婀娜時。", "橋迴行欲斷，隄遠意相隨。", "忍放花如雪，青樓撲酒旗。"]'),
('5a82a392-7715-49fb-8535-7c6293195bf5','謔柳','李商隱','唐','唐诗','tang','','[]','已帶黃金縷，仍飛白玉花。',48,'全唐诗/poet.tang.29000.json','["已帶黃金縷，仍飛白玉花。", "長時須拂馬，密處少藏鴉。", "眉細從他斂，腰輕莫自斜。", "玳梁誰道好，偏擬映盧家。"]'),
('ca9041ae-c4a9-4e2d-954f-3c54eac4d399','北禽','李商隱','唐','唐诗','tang','','[]','爲戀巴江好，無辭瘴霧蒸。',36,'全唐诗/poet.tang.29000.json','["爲戀巴江好，無辭瘴霧蒸。", "縱能朝杜宇，可得值蒼鷹。", "石小虛填海，蘆銛未破矰。"]'),
('39d4f078-6426-4c54-a98d-a982a3c7512d','初起','李商隱','唐','唐诗','tang','','[]','想像咸池日欲光，五更鐘後更迴腸。',32,'全唐诗/poet.tang.29000.json','["想像咸池日欲光，五更鐘後更迴腸。", "三年苦霧巴江水，不爲離人照屋梁。"]'),
('deb5d0c9-3679-4270-9984-c18a3e262827','楚宮','李商隱','唐','唐诗','tang','','[]','複壁交青瑣，重簾挂紫繩。',48,'全唐诗/poet.tang.29000.json','["複壁交青瑣，重簾挂紫繩。", "如何一柱觀，不礙九枝燈。", "扇薄常規月，釵斜只鏤冰。", "歌成猶未唱，秦火入夷陵。"]'),
('7fd23d94-707f-4553-afe4-84228157bbab','柳','李商隱','唐','唐诗','tang','','[]','柳映江潭底有情，望中頻遣客心驚。',32,'全唐诗/poet.tang.29000.json','["柳映江潭底有情，望中頻遣客心驚。", "巴雷隱隱千山外，更作章臺走馬聲。"]'),
('6028db2f-bac8-432c-a0c1-edf7fe69b567','石城','李商隱','唐','唐诗','tang','','[]','石城誇窈窕，花縣更風流。',48,'全唐诗/poet.tang.29000.json','["石城誇窈窕，花縣更風流。", "簟冰將飄枕，簾烘不隱鉤。", "玉童收夜鑰，金狄守更籌。", "共笑鴛鴦綺，鴛鴦兩白頭。"]'),
('0d2c5fba-d350-4c3f-b55e-72a491a84df6','韓碑','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53d9\u4e8b", "\u4e03\u8a00\u53e4\u8bd7", "\u548f\u53f2"]','元和天子神武姿，彼何人哉軒與羲。',384,'全唐诗/poet.tang.29000.json','["元和天子神武姿，彼何人哉軒與羲。", "誓將上雪列聖恥，坐法宮中朝四夷。", "淮西有賊五十載，封狼生貙貙生羆。", "不據山河據平地，長戈利矛日可麾。", "帝得聖相相曰度，賊斫不死神扶持。", "腰懸相印作都統，陰風慘澹天王旗。", "愬武古通作牙爪，儀曹外郎載筆隨。", "行軍司馬智且勇，十四萬衆猶虎貔。", "入蔡縛賊獻太廟，功無與讓恩不訾。", "帝曰汝度功第一，汝從事愈宜爲辭。", "愈拜稽首蹈且舞，金石刻畫臣能爲。", "古者世稱大手筆，此事不繫于職司。", "當仁自古有不讓，言訖屢頷天子頤。", "公退齋戒坐小閣，濡染大筆何淋漓。", "點竄堯典舜典字，塗改清廟生民詩。", "文成破體書在紙，清晨再拜鋪丹墀。", "表曰臣愈昧死上，詠神聖功書之碑。", "碑高三丈字如斗，負以靈鼇蟠以螭。", "句奇語重喻者少，讒之天子言其私。", "長繩百尺拽碑倒，麤砂大石相磨治。", "公之斯文若元氣，先時已入人肝脾。", "湯盤孔鼎有述作，今無其器存其辭。", "嗚呼聖皇及聖相，相與烜赫流淳熙。", "公之斯文不示後，曷與三五相攀追。"]'),
('4c16d46f-edbd-423e-a3b1-c6e361ac7b9d','令狐八拾遺見招送裴十四歸華州','李商隱','唐','唐诗','tang','','[]','二十中郎未足希，驪駒先自有光輝。',64,'全唐诗/poet.tang.29000.json','["二十中郎未足希，驪駒先自有光輝。", "蘭亭讌罷方回去，雪夜詩成道韞歸。", "漢苑風煙吹客夢，雲臺洞穴接郊扉。", "嗟予久抱臨邛渴，便欲因君問釣磯。"]'),
('f4c68770-d2b0-4281-b4e9-e9fbe7ff7a56','離思','李商隱','唐','唐诗','tang','','[]','氣盡前溪舞，心酸子夜歌。',48,'全唐诗/poet.tang.29000.json','["氣盡前溪舞，心酸子夜歌。", "峽雲尋不得，溝水欲如何。", "朔雁傳書絕，湘篁染淚多。", "無由見顏色，還自託微波。"]'),
('d538dace-1398-4b98-ba44-600d6168de07','宿駱氏亭寄懷崔雍衮','李商隱','唐','唐诗','tang','','["\u6000\u4eba", "\u5199\u96e8", "\u5199\u666f", "\u96e8"]','竹塢無塵水檻清，相思迢遞隔重城。',32,'全唐诗/poet.tang.29000.json','["竹塢無塵水檻清，相思迢遞隔重城。", "秋陰不散霜飛晚，留得枯荷聽雨聲。"]'),
('d32a2610-09d7-49ad-8cdf-dd9c649144c7','風雨','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u98ce\u96e8", "\u4e94\u8a00\u5f8b\u8bd7", "\u6000\u624d\u4e0d\u9047"]','淒涼寶劍篇，羈泊欲窮年。',48,'全唐诗/poet.tang.29000.json','["淒涼寶劍篇，羈泊欲窮年。", "黃葉仍風雨，青樓自管絃。", "新知遭薄俗，舊好隔良緣。", "心斷新豐酒，銷愁斗幾千。"]'),
('81bb84d2-9d4a-45d1-bd40-1858c9993f7d','夢澤','李商隱','唐','唐诗','tang','','[]','夢澤悲風動白茅，楚王葬盡滿城嬌。',32,'全唐诗/poet.tang.29000.json','["夢澤悲風動白茅，楚王葬盡滿城嬌。", "未知歌舞能多少，虛減宮廚爲細腰。"]'),
('166e4c58-3443-49c1-8201-2f0f3de2af8e','贈歌妓二首 一','李商隱','唐','唐诗','tang','','[]','水精如意玉連環，下蔡城危莫破顏。',32,'全唐诗/poet.tang.29000.json','["水精如意玉連環，下蔡城危莫破顏。", "紅綻櫻桃含白雪，斷腸聲裏唱陽關。"]'),
('d37e138e-e4e4-4e18-a3e8-25584c54c5aa','贈歌妓二首 二','李商隱','唐','唐诗','tang','','[]','白日相思可奈何，嚴城清夜斷經過。',32,'全唐诗/poet.tang.29000.json','["白日相思可奈何，嚴城清夜斷經過。", "只知解道春來瘦，不道春來獨自多。"]'),
('0fa747cb-4f5d-4181-ade8-2e89cc0a71d5','謝書','李商隱','唐','唐诗','tang','','[]','微意何曾有一毫，空攜筆硯奉龍韜。',32,'全唐诗/poet.tang.29000.json','["微意何曾有一毫，空攜筆硯奉龍韜。", "自蒙半夜傳衣後，不羨王祥得佩刀。"]'),
('90b38fe6-b5ab-4031-94e4-b73a877a61fc','寄令狐學士','李商隱','唐','唐诗','tang','','[]','秘殿崔嵬拂彩霓，曹司今在殿東西。',64,'全唐诗/poet.tang.29000.json','["秘殿崔嵬拂彩霓，曹司今在殿東西。", "賡歌太液翻黃鵠，從獵陳倉獲碧雞。", "曉飲豈知金掌迥，夜吟應訝玉繩低。", "鈞天雖許人間聽，閶闔門多夢自迷。"]'),
('fbb31c57-4c0d-4dc1-9e10-399ae6e9b74c','酬令狐郎中見寄','李商隱','唐','唐诗','tang','','[]','望郎臨古郡，佳句灑丹青。',120,'全唐诗/poet.tang.29000.json','["望郎臨古郡，佳句灑丹青。", "應自丘遲宅，仍過柳惲汀。", "封來江渺渺，信去雨冥冥。", "句曲聞仙訣，臨川得佛經。", "朝吟搘客枕，夜讀漱僧瓶。", "不見銜蘆雁，空流腐草螢。", "土宜悲坎井，天怒識雷霆。", "象卉分疆近，蛟涎浸岸腥。", "補羸貪紫桂，負氣託青萍。", "萬里懸離抱，危於訟閤鈴。"]'),
('8291b5d8-531d-4eed-9175-3da19e4e3093','七月二十八日夜與王鄭二秀才聽雨後夢作','李商隱','唐','唐诗','tang','','["\u534e\u5c71"]','初夢龍宮寶燄然，瑞霞明麗滿晴天。',128,'全唐诗/poet.tang.29000.json','["初夢龍宮寶燄然，瑞霞明麗滿晴天。", "旋成醉倚蓬萊樹，有箇仙人拍我肩。", "少頃遠聞吹細管，聞聲不見隔飛煙。", "逡巡又過瀟湘雨，雨打湘靈五十絃。", "瞥見馮夷殊悵望，鮫綃休賣海爲田。", "亦逢毛女無憀極，龍伯擎將華嶽蓮。", "恍惚無倪明又暗，低迷不已斷還連。", "覺來正是平階雨，獨背寒燈枕手眠。"]'),
('fb376b71-91c6-44ee-b2e4-40f5b3f71b8f','寄令狐郎中','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u5199\u666f", "\u4e03\u8a00\u7edd\u53e5", "\u53cb\u60c5"]','嵩雲秦樹久離居，雙鯉迢迢一紙書。',32,'全唐诗/poet.tang.29000.json','["嵩雲秦樹久離居，雙鯉迢迢一紙書。", "休問梁園舊賓客，茂陵秋雨病相如。"]'),
('4b4440f8-f452-4515-b766-be813d27871e','漫成三首 一','李商隱','唐','唐诗','tang','','[]','不妨何范盡詩家，未解當年重物華。',32,'全唐诗/poet.tang.29000.json','["不妨何范盡詩家，未解當年重物華。", "遠把龍山千里雪，將來擬並洛陽花。"]'),
('cfacd1bc-7db5-42df-ad78-b14662f81cff','漫成三首 二','李商隱','唐','唐诗','tang','','[]','沈約憐何遜，延年毀謝莊。',24,'全唐诗/poet.tang.29000.json','["沈約憐何遜，延年毀謝莊。", "清新俱有得，名譽底相傷。"]'),
('6084bd4e-86bd-4d2f-8e34-d6db2b74b8ef','漫成三首 三','李商隱','唐','唐诗','tang','','[]','霧夕詠芙蕖，何郎得意初。',24,'全唐诗/poet.tang.29000.json','["霧夕詠芙蕖，何郎得意初。", "此時誰最賞，沈范兩尚書。"]'),
('9a808938-d03b-48b2-a4b8-6015ad7b6bc1','無題','李商隱','唐','唐诗','tang','','[]','白道縈迴入暮霞，斑騅嘶斷七香車。',32,'全唐诗/poet.tang.29000.json','["白道縈迴入暮霞，斑騅嘶斷七香車。", "春風自共何人笑，枉破陽城十萬家。"]'),
('7dd62de1-8821-4c7f-9359-c572fd6f82e6','槿花二首 一','李商隱','唐','唐诗','tang','','[]','燕體傷風力，雞香積露文。',48,'全唐诗/poet.tang.29000.json','["燕體傷風力，雞香積露文。", "殷鮮一相雜，啼笑兩難分。", "月裏寧無姊，雲中亦有君。", "三清與仙島，何事亦離羣。"]'),
('9538622b-0e41-4daf-be20-403a90d37cc2','槿花二首 二','李商隱','唐','唐诗','tang','','[]','珠館薰燃久，玉房梳掃餘。',48,'全唐诗/poet.tang.29000.json','["珠館薰燃久，玉房梳掃餘。", "燒蘭才作燭，襞錦不成書。", "本以亭亭遠，翻嫌眽眽疎。", "迴頭問殘照，殘照更空虛。"]'),
('e1459406-b1e8-4e70-a81a-db84b302a560','哭劉蕡','李商隱','唐','唐诗','tang','','[]','上帝深宮閉九閽，巫咸不下問銜冤。',64,'全唐诗/poet.tang.29000.json','["上帝深宮閉九閽，巫咸不下問銜冤。", "廣陵別後春濤隔，湓浦書來秋雨翻。", "只有安仁能作誄，何曾宋玉解招魂。", "平生風義兼師友，不敢同君哭寢門。"]'),
('f2af162e-d81f-4e16-9ffb-41e2a1514aa3','杜司勳','李商隱','唐','唐诗','tang','','["\u611f\u6168", "\u5199\u4eba", "\u6292\u6000", "\u5199\u4eba\u8bd7"]','高樓風雨感斯文，短翼差池不及羣。',32,'全唐诗/poet.tang.29000.json','["高樓風雨感斯文，短翼差池不及羣。", "刻意傷春復傷別，人間惟有杜司勳。"]'),
('1ae5d09e-62e1-4183-9e12-002e80b027bf','荆門西下','李商隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一夕南風一葉危，荆雲迴望夏雲時。',64,'全唐诗/poet.tang.29000.json','["一夕南風一葉危，荆雲迴望夏雲時。", "人生豈得輕離別，天意何曾忌嶮巇。", "骨肉書題安絕徼，蕙蘭蹊徑失佳期。", "洞庭湖闊蛟龍惡，却羨楊朱泣路岐。"]'),
('358c2152-ac78-4747-b30c-18d21cd2d10c','碧瓦','李商隱','唐','唐诗','tang','','[]','碧瓦銜珠樹，紅輪結綺寮。',120,'全唐诗/poet.tang.29000.json','["碧瓦銜珠樹，紅輪結綺寮。", "無雙漢殿鬢，第一楚宮腰。", "霧唾香難盡，珠啼冷易銷。", "歌從雍門學，酒是蜀城燒。", "柳暗將翻巷，荷欹正抱橋。", "鈿轅開道入，金管隔隣調。", "夢到飛魂急，書成即席遙。", "河流衝柱轉，海沫近槎飄。", "吳市蠀蛦甲，巴賨翡翠翹。", "他時未知意，重疊贈嬌饒。"]'),
('14f75f94-3c45-4442-9c18-339af0b9ac97','蜨','李商隱','唐','唐诗','tang','','[]','葉葉復翻翻，斜橋對側門。',48,'全唐诗/poet.tang.29000.json','["葉葉復翻翻，斜橋對側門。", "蘆花惟有白，柳絮可能溫。", "西子尋遺殿，昭君覓故村。", "年年芳物盡，來別敗蘭蓀。"]'),
('e96cddef-b91e-4ed1-b460-b3c9073a6ae8','蠅蜨雞麝鷥鳳等成篇','李商隱','唐','唐诗','tang','','[]','韓蝶翻羅幕，曹蠅拂綺窗。',48,'全唐诗/poet.tang.29000.json','["韓蝶翻羅幕，曹蠅拂綺窗。", "鬬雞迴玉勒，融麝暖金釭。", "瑇瑁明書閣，琉璃冰酒缸。", "畫樓多有主，鸞鳳各雙雙。"]'),
('3ac3275e-34f6-4e38-a35f-67c350ecc677','韓翃舍人即事','李商隱','唐','唐诗','tang','','[]','萱草含丹粉，荷花抱綠房。',48,'全唐诗/poet.tang.29000.json','["萱草含丹粉，荷花抱綠房。", "鳥應悲蜀帝，蟬是怨齊王。", "通內藏珠府，應官解玉坊。", "橋南荀令過，十里送衣香。"]'),
('fb9addd7-7a3c-446f-9e2b-a3b3bf05c3b1','公子','李商隱','唐','唐诗','tang','','[]','一盞新羅酒，凌晨恐易消。',48,'全唐诗/poet.tang.29000.json','["一盞新羅酒，凌晨恐易消。", "歸應衝鼓半，去不待笙調。", "歌好惟愁和，香濃豈惜飄。", "春場鋪艾帳，下馬雉媒嬌。"]'),
('72b042b5-0353-4304-b8e0-09356bf98d93','子初全溪作','李商隱','唐','唐诗','tang','','[]','全溪不可到，況復盡餘醅。',48,'全唐诗/poet.tang.29000.json','["全溪不可到，況復盡餘醅。", "漢苑生春水，昆池換劫灰。", "戰蒲知雁唼，皺月覺魚來。", "清興恭聞命，言詩未敢迴。"]'),
('1b6adc4d-ba8f-43c4-867a-a256ebfdfe55','楊本勝說於長安見小男阿衮','李商隱','唐','唐诗','tang','','[]','聞君來日下，見我最嬌兒。',48,'全唐诗/poet.tang.29000.json','["聞君來日下，見我最嬌兒。", "漸大啼應數，長貧學恐遲。", "寄人龍種瘦，失母鳳雛癡。", "語罷休邊角，青燈兩鬢絲。"]'),
('35bca1b9-9185-4d49-ac39-58b2962b358e','西溪','李商隱','唐','唐诗','tang','','[]','悵望西溪水，潺湲奈爾何。',72,'全唐诗/poet.tang.29000.json','["悵望西溪水，潺湲奈爾何。", "不驚春物少，只覺夕陽多。", "色染妖韶柳，光含窈窕蘿。", "人間從到海，天上莫爲河。", "鳳女彈瑤瑟，龍孫撼玉珂。", "京華他夜夢，好好寄雲波。"]'),
('5f6c36a5-b2a0-4a77-9c2d-a59e95a8cdc5','柳下暗記','李商隱','唐','唐诗','tang','','[]','無奈巴南柳，千條傍吹臺。',24,'全唐诗/poet.tang.29000.json','["無奈巴南柳，千條傍吹臺。", "更將黃映白，擬作杏花媒。"]'),
('1db4154b-fe66-40d4-8934-0caded561716','妓席','李商隱','唐','唐诗','tang','','[]','樂府聞桃葉，人前道得無。',24,'全唐诗/poet.tang.29000.json','["樂府聞桃葉，人前道得無。", "勸君書小字，慎莫喚官奴。"]'),
('9df0a61d-7466-4b2e-92dc-221dc07aebf4','少年','李商隱','唐','唐诗','tang','','[]','外戚平羌第一功，生年二十有重封。',64,'全唐诗/poet.tang.29000.json','["外戚平羌第一功，生年二十有重封。", "直登宣室螭頭上，橫過干泉豹尾中。", "別館覺來雲雨夢，後門歸去蕙蘭叢。", "灞陵夜獵隨田竇，不識寒郊自轉蓬。"]'),
('ac26dd32-e1c4-4b9c-a040-a6e88db2cbe8','無題','李商隱','唐','唐诗','tang','','[]','近知名阿侯，住處小江流。',36,'全唐诗/poet.tang.29000.json','["近知名阿侯，住處小江流。", "腰細不勝舞，眉長惟是愁。", "黄金堪作屋，何不作重樓。"]'),
('b559d48f-5a6a-4359-85fd-f0eede83005f','玄微先生','李商隱','唐','唐诗','tang','','[]','仙翁無定數，時入一壺藏。',96,'全唐诗/poet.tang.29000.json','["仙翁無定數，時入一壺藏。", "夜夜桂露濕，村村桃水香。", "醉中拋浩劫，宿處起神光。", "藥裹丹山鳳，碁函白石郎。", "弄河移砥柱，吞日倚扶桑。", "龍竹裁輕策，鮫綃熨下裳。", "樹栽嗤漢帝，橋扳笑秦王。", "徑欲隨關令，龍沙萬里強。"]'),
('fb945404-b9b7-4c4b-ae91-d65b5e2eebaf','藥轉','李商隱','唐','唐诗','tang','','[]','鬱金堂北畫樓東，換骨神方上藥通。',64,'全唐诗/poet.tang.29000.json','["鬱金堂北畫樓東，換骨神方上藥通。", "露氣暗連青桂苑，風聲偏獵紫蘭叢。", "長籌未必輸孫皓，香棗何勞問石崇。", "憶事懷人兼得句，翠衾歸臥繡簾中。"]'),
('adbed253-25b4-4bea-9f8d-52da370d9218','岳陽樓','李商隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','欲爲平生一散愁，洞庭湖上岳陽樓。',32,'全唐诗/poet.tang.29000.json','["欲爲平生一散愁，洞庭湖上岳陽樓。", "可憐萬里堪乘興，枉是蛟龍解覆舟。"]'),
('398af96c-8c59-4614-b859-5a3205bbb40a','寄成都高苗二從事','李商隱','唐','唐诗','tang','','[]','家近紅蕖曲水濱，全家羅襪起秋塵。',32,'全唐诗/poet.tang.29000.json','["家近紅蕖曲水濱，全家羅襪起秋塵。", "莫將越客千絲網，網得西施別贈人。"]'),
('4a8163d9-7f52-40a9-ab0f-6bcc125e3d48','岳陽樓','李商隱','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','漢水方城帶百蠻，四隣誰道亂周班。',32,'全唐诗/poet.tang.29000.json','["漢水方城帶百蠻，四隣誰道亂周班。", "如何一夢高唐雨，自此無心入武關。"]'),
('b490e3c6-ee9e-4aa3-9575-a01e4bca22c1','越燕二首 一','李商隱','唐','唐诗','tang','','[]','上國社方見，此鄉秋不歸。',48,'全唐诗/poet.tang.29000.json','["上國社方見，此鄉秋不歸。", "爲矜皇后舞，猶著羽人衣。", "拂水斜紋亂，銜花片影微。", "盧家文杏好，試近莫愁飛。"]'),
('f3c25a75-6445-47e0-a5ae-265559f9f990','越燕二首 二','李商隱','唐','唐诗','tang','','[]','將泥紅蓼岸，得草綠楊村。',48,'全唐诗/poet.tang.29000.json','["將泥紅蓼岸，得草綠楊村。", "命侶添新意，安巢復舊痕。", "去應逢阿母，來莫害王孫。", "記取丹山鳳，今爲百鳥尊。"]'),
('3d82417b-95c8-48a8-a026-18fc4e2842f4','杜工部蜀中離席','李商隱','唐','唐诗','tang','','["\u79bb\u522b", "\u5fe7\u56fd\u5fe7\u6c11", "\u5bb4\u4f1a"]','人生何處不離羣，世路干戈惜暫分。',64,'全唐诗/poet.tang.29000.json','["人生何處不離羣，世路干戈惜暫分。", "雪嶺未歸天外使，松州猶駐殿前軍。", "座中醉客延醒客，江上晴雲雜雨雲。", "美酒成都堪送老，當壚仍是卓文君。"]');
